-- Poems batch 458
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-31','越井臺望','劉言史','唐','御定全唐诗','yuding','','[]','獨立陽臺望廣州，更添羈客異鄉愁。',32,'御定全唐詩/json/468.json','["獨立陽臺望廣州，更添羈客異鄉愁。", "晚潮未至早潮落，井邑暫依沙上頭。"]'),
('yuding-32','扶病春亭','劉言史','唐','御定全唐诗','yuding','','[]','強梳稀發著綸巾，舍杖空行試病身。',32,'御定全唐詩/json/468.json','["強梳稀發著綸巾，舍杖空行試病身。", "花間自欲裴回立，稚子牽衣不許人。"]'),
('yuding-33','贈童尼','劉言史','唐','御定全唐诗','yuding','','[]','舊時豔質如明玉，今日空心是冷灰。',32,'御定全唐詩/json/468.json','["舊時豔質如明玉，今日空心是冷灰。", "料得襄王惆悵極，更無雲雨到陽臺。"]'),
('yuding-34','讀故友于君集','劉言史','唐','御定全唐诗','yuding','','[]','大底從頭總是悲，就中偏愴築城詞。',32,'御定全唐詩/json/468.json','["大底從頭總是悲，就中偏愴築城詞。", "依然想得初成日，寄出秋山與我時。"]'),
('yuding-35','病僧二首','劉言史','唐','御定全唐诗','yuding','','[]','竺國鄉程算不回，病中衣錫遍浮埃。',64,'御定全唐詩/json/468.json','["竺國鄉程算不回，病中衣錫遍浮埃。", "如今漢地諸經本，自過流沙遠背來。", "空林衰病臥多時，白髮從成數寸絲。", "西行卻過流沙日，枕上寥寥心獨知。"]'),
('yuding-36','右軍墨池','劉言史','唐','御定全唐诗','yuding','','[]','永嘉人事盡歸空，逸少遺居蔓草中。',32,'御定全唐詩/json/468.json','["永嘉人事盡歸空，逸少遺居蔓草中。", "至今池水涵餘墨，猶共諸泉色不同。"]'),
('yuding-37','送僧歸山','劉言史','唐','御定全唐诗','yuding','','[]','楚俗翻花自送迎，密人來往豈知情。',32,'御定全唐詩/json/468.json','["楚俗翻花自送迎，密人來往豈知情。", "夜行獨自寒山寺，雪徑泠泠金錫聲。"]'),
('yuding-38','題源分竹亭','劉言史','唐','御定全唐诗','yuding','','[]','繞屋扶疏千萬竿，年年相誘獨行看。',32,'御定全唐詩/json/468.json','["繞屋扶疏千萬竿，年年相誘獨行看。", "日光不透煙常在，先校諸家一月寒。"]'),
('yuding-39','山寺看櫻桃花題僧壁','劉言史','唐','御定全唐诗','yuding','','[]','楚寺春風臘盡時，含桃先坼一千枝。',32,'御定全唐詩/json/468.json','["楚寺春風臘盡時，含桃先坼一千枝。", "老僧不語傍邊坐，花發人來總不知。"]'),
('yuding-40','傷清江上人','劉言史','唐','御定全唐诗','yuding','','[]','往年偏共仰師游，聞過流沙淚不休。',32,'御定全唐詩/json/468.json','["往年偏共仰師游，聞過流沙淚不休。", "此身豈得多時住，更著塵心起外愁。"]'),
('yuding-41','山寺看海榴花','劉言史','唐','御定全唐诗','yuding','','[]','琉璃地上紺宮前，發翠凝紅已十年。',32,'御定全唐詩/json/468.json','["琉璃地上紺宮前，發翠凝紅已十年。", "夜久月明人去盡，火光霞焰遞相燃。"]'),
('yuding-42','贈成煉師四首','劉言史','唐','御定全唐诗','yuding','','[]','花冠蕊帔色嬋娟，一曲清簫淩紫煙。',128,'御定全唐詩/json/468.json','["花冠蕊帔色嬋娟，一曲清簫淩紫煙。", "不知今日重來意，更住人間幾百年。", "黃昏騎得下天龍，巡遍茅山數十峰。", "采芝卻到蓬萊上，花裏猶殘碧玉鐘。", "等閒何處得靈方，丹臉雲鬟日月長。", "大羅過卻三千歲，更向人間魅阮郎。", "曾隨阿母漢宮齋，鳳駕龍輧列玉階。", "當時白燕無尋處，今日雲鬟見玉釵。"]'),
('yuding-43','上巳日陪襄陽李尚書宴光風亭','劉言史','唐','御定全唐诗','yuding','','[]','碧池萍嫩柳垂波，綺席絲鏞舞翠娥。',32,'御定全唐詩/json/468.json','["碧池萍嫩柳垂波，綺席絲鏞舞翠娥。", "為報會稽亭上客，永和應不勝元和。"]'),
('yuding-44','奉酬','劉言史','唐','御定全唐诗','yuding','','[]','閏餘春早景沉沉，禊飲風亭恣賞心。',32,'御定全唐詩/json/468.json','["閏餘春早景沉沉，禊飲風亭恣賞心。", "紅袖青娥留永夕，漢陰寧肯羨山陰。"]'),
('yuding-45','病中客散複言懷','劉言史','唐','御定全唐诗','yuding','','[]','華髮離披臥滿頭，暗蟲衰草入鄉愁。',32,'御定全唐詩/json/468.json','["華髮離披臥滿頭，暗蟲衰草入鄉愁。", "枕前人去空庭暮，又見芭蕉白露秋。"]'),
('yuding-46','處州月夜穆中丞席和主人','劉言史','唐','御定全唐诗','yuding','','[]','羌竹繁弦銀燭紅，月光初出柳城東。',32,'御定全唐詩/json/468.json','["羌竹繁弦銀燭紅，月光初出柳城東。", "忽見隱侯裁一詠，還須書向郡樓中。"]'),
('yuding-47','尋花','劉言史','唐','御定全唐诗','yuding','','[]','遊春未足春將度，訪紫尋紅少在家。',32,'御定全唐詩/json/468.json','["遊春未足春將度，訪紫尋紅少在家。", "借問流鶯與飛蝶，更知何處有幽花。"]'),
('yuding-48','贈陳長史妓','劉言史','唐','御定全唐诗','yuding','','[]','寶鈿雲和玉禁仙，深含媚靨嫋朱弦。',32,'御定全唐詩/json/468.json','["寶鈿雲和玉禁仙，深含媚靨嫋朱弦。", "春風不怕君王恨，引出幽花落外邊。"]'),
('yuding-49','題王況故居','劉言史','唐','御定全唐诗','yuding','','[]','入巷蕭條起悲緒，兒女猶居舊貧處。',32,'御定全唐詩/json/468.json','["入巷蕭條起悲緒，兒女猶居舊貧處。", "塵滿空床屋見天，獨作驢鳴一聲去。"]'),
('yuding-50','偶題','劉言史','唐','御定全唐诗','yuding','','[]','遲日新妝游冶娘，盈盈彩艇白蓮塘。',32,'御定全唐詩/json/468.json','["遲日新妝游冶娘，盈盈彩艇白蓮塘。", "掬水遠濕岸邊郎，紅綃縷中玉釧光。"]'),
('yuding-51','慟柳論','劉言史','唐','御定全唐诗','yuding','','[]','孀妻棲戶仍無嗣，欲訪孤墳誰引至。',32,'御定全唐詩/json/468.json','["孀妻棲戶仍無嗣，欲訪孤墳誰引至。", "裴回無處展哀情，惟有衣襟知下淚。"]'),
('yuding-52','夜入簡子古城','劉言史','唐','御定全唐诗','yuding','','[]','遠火熒熒聚寒鬼，綠焰欲銷還複起。',32,'御定全唐詩/json/468.json','["遠火熒熒聚寒鬼，綠焰欲銷還複起。", "夜深風雪古城空，行客衣襟汗如水。"]'),
('yuding-53','桂江中題香頂台','劉言史','唐','御定全唐诗','yuding','','[]','岧岧香積淩空翠，天上名花落幽地。',32,'御定全唐詩/json/468.json','["岧岧香積淩空翠，天上名花落幽地。", "老僧相對竟無言，山鳥卻呼諸佛字。"]'),
('yuding-54','僧簷前獨竹詠','劉言史','唐','御定全唐诗','yuding','','[]','亂石田中寄孤本，亭亭不住淩虛引。',32,'御定全唐詩/json/468.json','["亂石田中寄孤本，亭亭不住淩虛引。", "欲以袈裟拂著來，一邊碧玉無輕粉。"]'),
('yuding-55','送人隨姊夫任雲安令','劉言史','唐','御定全唐诗','yuding','','[]','閑逐維私向武城，北風青雀片時行。',32,'御定全唐詩/json/468.json','["閑逐維私向武城，北風青雀片時行。", "孤帆瞥過荊州岸，認得瞿塘急浪聲。"]'),
('yuding-56','山中喜崔補闕見尋','劉言史','唐','御定全唐诗','yuding','','[]','鹿袖青藜鼠耳巾，潛夫豈解拜朝臣。',32,'御定全唐詩/json/468.json','["鹿袖青藜鼠耳巾，潛夫豈解拜朝臣。", "白屋藜床還共入，山妻老大不羞人。"]'),
('yuding-57','偶題二首','劉言史','唐','御定全唐诗','yuding','','[]','金榜榮名俱失盡，病身為庶更投魑。',64,'御定全唐詩/json/468.json','["金榜榮名俱失盡，病身為庶更投魑。", "春娥慢笑無愁色，別向人家舞柘枝。", "得罪除名謫海頭，驚心無暇與身愁。", "中使不知何處住，家書莫寄向春州。"]'),
('yuding-58','嘉興社日','劉言史','唐','御定全唐诗','yuding','','[]','消渴天涯寄病身，臨邛知我是何人。',32,'御定全唐詩/json/468.json','["消渴天涯寄病身，臨邛知我是何人。", "今年社日分餘肉，不值陳平又不均。"]'),
('yuding-59','席上贈李尹','劉言史','唐','御定全唐诗','yuding','','[]','傴僂山夫發似絲，松間石上坐多時。',32,'御定全唐詩/json/468.json','["傴僂山夫發似絲，松間石上坐多時。", "瓢飲不曾看酒肆，世人空笑亦何為。"]'),
('yuding-60','弼公院問病','劉言史','唐','御定全唐诗','yuding','','[]','一頭細發兩分絲，臥見芭蕉白露滋。',32,'御定全唐詩/json/468.json','["一頭細發兩分絲，臥見芭蕉白露滋。", "欲令居士身無病，直待眾生苦盡時。"]'),
('yuding-61','惜花','劉言史','唐','御定全唐诗','yuding','','[]','年少共憐含露色，老人偏惜委塵紅。',32,'御定全唐詩/json/468.json','["年少共憐含露色，老人偏惜委塵紅。", "如何遂得心中事，每要花時不厭風。"]'),
('yuding-62','代胡僧留別','劉言史','唐','御定全唐诗','yuding','','[]','此地緣疏語未通，歸時老病去無窮。',32,'御定全唐詩/json/468.json','["此地緣疏語未通，歸時老病去無窮。", "定知不徹南天竺，死在條支陰磧中。"]'),
('yuding-63','桂江逢王使君旅櫬歸','劉言史','唐','御定全唐诗','yuding','','[]','故人丹旐出南威，少婦隨喪哭漸歸。',32,'御定全唐詩/json/468.json','["故人丹旐出南威，少婦隨喪哭漸歸。", "遙想北原新壟上，日寒光淺水松稀。"]'),
('yuding-64','玉京詞','劉言史','唐','御定全唐诗','yuding','','[]','絕景寥寥日更遲，人間甲子不同時。',32,'御定全唐詩/json/468.json','["絕景寥寥日更遲，人間甲子不同時。", "未知樵客終何得，歸後無家是看棋。"]'),
('yuding-65','葛巾歌','劉言史','唐','御定全唐诗','yuding','','[]','一片白葛巾，潛夫自能結。籬邊折枯蒿，聊用簪華髮。',88,'御定全唐詩/json/468.json','["一片白葛巾，潛夫自能結。籬邊折枯蒿，聊用簪華髮。", "有時醉倒長松側，酒醒不見心還憶。穀鳥銜將卻趁來，", "草堂窗底漉春醅，山寺門前逢暮雨。臨汝袁郎得相見，", "空留棁仗犢鼻褌，濛濛煙雨歸山村。"]'),
('yuding-66','北原情三首','劉言史','唐','御定全唐诗','yuding','','[]','錯莫天色愁，挽歌出重闉。誰家白網車，送客入幽塵。',228,'御定全唐詩/json/468.json','["錯莫天色愁，挽歌出重闉。誰家白網車，送客入幽塵。", "銘旌下官道，葬輿去轔轔。蕭條黃蒿中，奠酒花翠新。", "米雪晚霏微，墓成悄無人。烏鳶下空地，煙火殘荒榛。", "生人更多苦，入戶事盈身。營營日易深，卻到不得頻。", "寂寥孤隧頭，草綠棠梨春。", "洛陽城北山，古今葬冥客。聚骨朽成泥，此山土多白。", "近來送葬人，亦去聞歸聲。豈能車輪疾，漸是墓侵城。", "城中人不絕，哀挽相次行。莫非北邙後，重向洛城生。", "蔔地起孤墳，全家送葬去。歸來卻到時，不復重知處。", "疊疊葬相續，土乾草已綠。列紙瀉壺漿，空向春雲哭。"]'),
('yuding-67','林中獨醒','劉言史','唐','御定全唐诗','yuding','','[]','晚來林沼靜，獨坐間瓢尊。向己非前跡，齊心欲不言。',48,'御定全唐詩/json/468.json','["晚來林沼靜，獨坐間瓢尊。向己非前跡，齊心欲不言。", "微涼生亂筱，輕馥起孤萱。未得渾無事，瓜田草正繁。"]'),
('yuding-68','江陵客舍留別樊尚書','劉言史','唐','御定全唐诗','yuding','','[]','信陵門館下，多病有歸思。墜履忘情後，寒灰更濕時。',48,'御定全唐詩/json/468.json','["信陵門館下，多病有歸思。墜履忘情後，寒灰更濕時。", "委欄芳蕙晚，憑幾雪髫垂。明日秋關外，單車風雨隨。"]'),
('yuding-0','擬古詠河邊枯樹','長孫佐輔','唐','御定全唐诗','yuding','','[]','野火燒枝水洗根，數圍孤樹半心存。',32,'御定全唐詩/json/469.json','["野火燒枝水洗根，數圍孤樹半心存。", "應是無機承雨露，卻將春色寄苔痕。"]'),
('yuding-1','別友人','長孫佐輔','唐','御定全唐诗','yuding','','[]','愁多不忍醒時別，想極還尋靜處行。',32,'御定全唐詩/json/469.json','["愁多不忍醒時別，想極還尋靜處行。", "誰遣同衾又分手，不如行路本無情。"]'),
('yuding-2','傷故人歌妓','長孫佐輔','唐','御定全唐诗','yuding','','[]','愁臉無紅衣滿塵，萬家門戶不容身。',32,'御定全唐詩/json/469.json','["愁臉無紅衣滿塵，萬家門戶不容身。", "曾將一笑君前去，誤殺幾多回顧人。"]'),
('yuding-3','南中客舍對雨送故人歸北','長孫佐輔','唐','御定全唐诗','yuding','','[]','猿聲啾啾雁聲苦，捲簾相對愁不語。幾年客吳君在楚，',24,'御定全唐詩/json/469.json','["猿聲啾啾雁聲苦，捲簾相對愁不語。幾年客吳君在楚，"]'),
('yuding-4','杭州秋日別故友','長孫佐輔','唐','御定全唐诗','yuding','','[]','相見又相別，大江秋水深。悲歡一世事，去住兩鄉心。',48,'御定全唐詩/json/469.json','["相見又相別，大江秋水深。悲歡一世事，去住兩鄉心。", "淅瀝籬下葉，淒清階上琴。獨隨孤棹去，何處更同衾。"]'),
('yuding-5','代別後夢別','長孫佐輔','唐','御定全唐诗','yuding','','[]','別中還夢別，悲後更生悲。覺夢俱千里，追隨難再期。',48,'御定全唐詩/json/469.json','["別中還夢別，悲後更生悲。覺夢俱千里，追隨難再期。", "翻思夢裏苦，卻恨覺來遲。縱是非真事，何妨夢會時。"]'),
('yuding-6','答邊信','長孫佐輔','唐','御定全唐诗','yuding','','[]','征人去年戍遼水，夜得邊書字盈紙。揮刀就燭裁紅綺，',48,'御定全唐詩/json/469.json','["征人去年戍遼水，夜得邊書字盈紙。揮刀就燭裁紅綺，", "同心再解心不離，書字頻看字愁滅。結成一夜和淚封，"]'),
('yuding-7','對鏡吟','長孫佐輔','唐','御定全唐诗','yuding','','[]','憶昔逢君新納娉，青銅鑄出千年鏡。意憐光彩固無瑕，',72,'御定全唐詩/json/469.json','["憶昔逢君新納娉，青銅鑄出千年鏡。意憐光彩固無瑕，", "君非結心空結帶，結處尚新恩已背。開簾覽鏡悲難語，", "昔日照來人共許，今朝照罷自生疑。鏡上有塵猶可淬，"]'),
('yuding-8','山行書事','長孫佐輔','唐','御定全唐诗','yuding','','[]','日落風bk々，驅車行遠郊。中心有所悲，古墓穿黃茅。',145,'御定全唐詩/json/469.json','["日落風bk々，驅車行遠郊。中心有所悲，古墓穿黃茅。", "茅中狐兔窠，四面烏鳶巢。鬼火時獨出，人煙不相交。", "行行近破村，一徑欹還坳。迎霜聽蟋蟀，向月看蠨蛸。", "翁喜客來至，客業羞廚庖。濁醪誇潑蟻，時果仍新苞。", "相勸對寒燈，呼兒爇枯梢。性樸頗近古，其言無鬥筲。", "憂歡世上並，歲月途中拋。誰知問津客，空作揚雄嘲。"]'),
('yuding-9','古宮怨','長孫佐輔','唐','御定全唐诗','yuding','','[]','窗前好樹名玫瑰，去年花落今年開。無情春色尚識返，',120,'御定全唐詩/json/469.json','["窗前好樹名玫瑰，去年花落今年開。無情春色尚識返，", "拊心卻笑西子嚬，掩鼻誰憂鄭姬謗。草染文章衣下履，", "盛衰傾奪欲何如，嬌愛翻悲逐佞諛。重遠豈能慚沼鵠，", "始喜類蘿新托柏，終傷如薺卻甘荼。院深獨開還獨閉，", "痕多開鏡照還悲，綠髻青蛾尚未衰。莫道新縑長絕比，"]'),
('yuding-10','關山月','長孫佐輔','唐','御定全唐诗','yuding','','[]','淒淒還切切，戍客多離別。何處最傷心，關山見秋月。',144,'御定全唐詩/json/469.json','["淒淒還切切，戍客多離別。何處最傷心，關山見秋月。", "關月竟如何，由來遠近過。始經玄菟塞，終繞白狼河。", "忽憶秦樓婦，流光應共有。已得並蛾眉，還知攬纖手。", "去歲照同行，比翼複連形。今宵照獨立，顧影自煢煢。", "餘暉慚西落，夜夜看如昨。借問映旌旗，何如鑒帷幕。", "拂曉朔風悲，蓬驚雁不飛。幾時征戍罷，還向月中歸。"]'),
('yuding-11','隴西行','長孫佐輔','唐','御定全唐诗','yuding','','[]','陰雲凝朔氣，隴上正飛雪。四月草不生，北風勁如切。',96,'御定全唐詩/json/469.json','["陰雲凝朔氣，隴上正飛雪。四月草不生，北風勁如切。", "朝來羽書急，夜救長城窟。道隘行不前，相呼抱鞍歇。", "人寒指欲墮，馬凍蹄亦裂。射雁旋充饑，斧冰還止渴。", "寧辭解圍鬥，但恐乘疲沒。早晚邊候空，歸來養羸卒。"]'),
('yuding-12','《尋山家','長孫佐輔','唐','御定全唐诗','yuding','','[]','獨訪山家歇還涉，茅屋斜連隔松葉。',32,'御定全唐詩/json/469.json','["獨訪山家歇還涉，茅屋斜連隔松葉。", "主人聞語未開門，繞籬野菜飛黃蝶。"]'),
('yuding-13','山居','長孫佐輔','唐','御定全唐诗','yuding','','[]','看書愛幽寂，結宇青冥間。飛泉引風聽，古桂和雲攀。',84,'御定全唐詩/json/469.json','["看書愛幽寂，結宇青冥間。飛泉引風聽，古桂和雲攀。", "地深草木稠，境靜魚鳥閑。陰氣晚出穀，朝光先照山。", "有時獨杖藜，入夜猶啟關。星昏歸鳥過，火出樵童還。", "神體自和適，不是離人寰。"]'),
('yuding-14','楚州鹽壒古牆望海','長孫佐輔','唐','御定全唐诗','yuding','','[]','混沌本冥冥，泄為洪川流。雄哉大造化，萬古橫中州。',96,'御定全唐詩/json/469.json','["混沌本冥冥，泄為洪川流。雄哉大造化，萬古橫中州。", "我從西北來，登高望蓬丘。陰晴乍開合，天地相沉浮。", "長風卷繁雲，日出扶桑頭。水淨露鮫室，煙銷凝蜃樓。", "時來會雲翔，道蹇即津遊。明發促歸軫，滄波非宿謀。"]'),
('yuding-15','聞韋駙馬使君遷拜台州','長孫佐輔','唐','御定全唐诗','yuding','','[]','溟藩軫帝憂，見說初鳴騶。德勝禍先戢，情閑思自流。',144,'御定全唐詩/json/469.json','["溟藩軫帝憂，見說初鳴騶。德勝禍先戢，情閑思自流。", "蠶殷桑柘空，廩實雀鼠稠。諫虎昔賜駿，安人將問牛。", "曾陪後乘光，共逐平津遊。旌旆擁追賞，歌鐘催獻酬。", "音徽一寂寥，貴賤雙沉浮。北郭乏中崖，東方稱上頭。", "躋山望百城，目盡增遐愁。海逼日月近，天高星漢秋。", "無階異漸鴻，有志慚馴鷗。終期促孤棹，暫訪天臺幽。"]'),
('yuding-16','山行經村徑','長孫佐輔','唐','御定全唐诗','yuding','','[]','一徑有人跡，到來唯數家。依稀聽機杼，寂曆看桑麻。',48,'御定全唐詩/json/469.json','["一徑有人跡，到來唯數家。依稀聽機杼，寂曆看桑麻。", "雨濕渡頭草，風吹墳上花。卻驅羸馬去，數點歸林鴉。"]'),
('yuding-17','野田行','張碧','唐','御定全唐诗','yuding','','[]','風昏晝色飛斜雨，冤骨千堆髑髏語。八紘牢落人物悲，',49,'御定全唐詩/json/469.json','["風昏晝色飛斜雨，冤骨千堆髑髏語。八紘牢落人物悲，", "秦皇矻矻築長城，漢祖區區白蛇死。野田之骨兮又成塵，"]'),
('yuding-18','貧女','張碧','唐','御定全唐诗','yuding','','[]','豈是昧容華，豈不知機織。自是生寒門，良媒不相識。',24,'御定全唐詩/json/469.json','["豈是昧容華，豈不知機織。自是生寒門，良媒不相識。"]'),
('yuding-19','幽思','張碧','唐','御定全唐诗','yuding','','[]','金爐煙靄微，銀釭殘影滅。出戶獨裴回，落花滿明月。',24,'御定全唐詩/json/469.json','["金爐煙靄微，銀釭殘影滅。出戶獨裴回，落花滿明月。"]'),
('yuding-20','惜花三首','張碧','唐','御定全唐诗','yuding','','[]','千枝萬枝占春開，彤霞著地紅成堆。',96,'御定全唐詩/json/469.json','["千枝萬枝占春開，彤霞著地紅成堆。", "一窖閒愁驅不去，殷勤對爾酌金杯。", "老鴉拍翼盤空疾，准擬浮生如瞬息。", "阿母蟠桃香未齊，漢皇骨葬秋山碧。", "朝開暮落煎人老，無人為報東君道。", "留取穠紅伴醉吟，莫教少女來吹掃。"]'),
('yuding-21','遊春引三首','張碧','唐','御定全唐诗','yuding','','[]','句芒愛弄春風權，開萌發翠無黨偏。',96,'御定全唐詩/json/469.json','["句芒愛弄春風權，開萌發翠無黨偏。", "句芒小女精神巧，機羅杼綺滿平川。", "五陵年少輕薄客，蠻錦花多春袖窄。", "酌桂鳴金玩物華，星蹄繡轂填香陌。", "千條碧綠輕拖水，金毛泣怕春江死。", "萬匯俱含造化恩，見我春工無私理。"]'),
('yuding-22','農父','張碧','唐','御定全唐诗','yuding','','[]','運鋤耕劚侵星起，隴畝豐盈滿家喜。',32,'御定全唐詩/json/469.json','["運鋤耕劚侵星起，隴畝豐盈滿家喜。", "到頭禾黍屬他人，不知何處拋妻子。"]'),
('yuding-23','古意','張碧','唐','御定全唐诗','yuding','','[]','鑾輿不碾香塵滅，更殘三十六宮月。',32,'御定全唐詩/json/469.json','["鑾輿不碾香塵滅，更殘三十六宮月。", "手持紈扇獨含情，秋風吹落橫波血。"]'),
('yuding-24','秋日登岳陽樓晴望','張碧','唐','御定全唐诗','yuding','','[]','三秋倚練飛金盞，洞庭波定平如剗。天高雲卷綠羅低，',48,'御定全唐詩/json/469.json','["三秋倚練飛金盞，洞庭波定平如剗。天高雲卷綠羅低，", "西南東北競無際，直疑侵斷青天涯。屈原回日牽愁吟，"]'),
('yuding-25','鴻溝','張碧','唐','御定全唐诗','yuding','','[]','毒龍銜日天地昏，八紘靉靆生愁雲。秦園走鹿無藏處，',144,'御定全唐詩/json/469.json','["毒龍銜日天地昏，八紘靉靆生愁雲。秦園走鹿無藏處，", "魚蝦舞浪狂鰍鯤，龍蛇膽戰登鴻門。星旗羽鏃強者尊，", "項莊憤氣吐不得，亞父鬥聲天上聞。玉光墮地驚昆侖，", "蛇枯老媼啼淚痕，星曹定秤秤王孫。項籍骨輕迷精魂，", "吳娃捧酒橫秋波，霜天月照空城壘。力拔山兮忽到此，", "三尺霜鳴金匣裏，神光一掉八千里。漢皇驟馬意氣生，"]'),
('yuding-26','美人梳頭','張碧','唐','御定全唐诗','yuding','','[]','玉堂花院小枝紅，綠窗一片春光曉。玉容驚覺濃睡醒，',64,'御定全唐詩/json/469.json','["玉堂花院小枝紅，綠窗一片春光曉。玉容驚覺濃睡醒，", "皓指高低寸黛愁，水精梳滑參差墜。須臾攏掠蟬鬢生，", "鸚鵡偷來話心曲，屏風半倚遙山綠。"]'),
('yuding-27','題祖山人池上怪石','張碧','唐','御定全唐诗','yuding','','[]','寒姿數片奇突兀，曾作秋江秋水骨。先生應是厭風雲，',76,'御定全唐詩/json/469.json','["寒姿數片奇突兀，曾作秋江秋水骨。先生應是厭風雲，", "參差翠縷擺不落，筆頭驚怪黏秋雲。", "我聞吳中項容水墨有高價，邀得將來倚松下。", "鋪卻雙繒直道難，掉首空歸不成畫。"]'),
('yuding-28','山居雨霽即事','張碧','唐','御定全唐诗','yuding','','[]','結茅蒼嶺下，自與喧卑隔。況值雷雨晴，郊原轉岑寂。',144,'御定全唐詩/json/469.json','["結茅蒼嶺下，自與喧卑隔。況值雷雨晴，郊原轉岑寂。", "出門看反照，繞屋殘溜滴。古路絕人行，荒陂響螻蟈。", "籬崩瓜豆蔓，圃壞牛羊跡。斷續古祠鴉，高低遠村笛。", "喜聞東皋潤，欲往未通屐。杖策試危橋，攀蘿瞰苔壁。", "鄰翁夜相訪，緩酌聊跂石。新月出汙尊，浮雲在巾舄。", "常隳腐儒操，謬習經邦畫。有待時未知，非關慕沮溺。"]'),
('yuding-29','贈琴棋僧歌','張瀛','唐','御定全唐诗','yuding','','[]','我嘗聽師法一說，波上蓮花水中月。不垢不淨是色空，',72,'御定全唐詩/json/469.json','["我嘗聽師法一說，波上蓮花水中月。不垢不淨是色空，", "河沙世界盡空空，一寸寒灰冷燈畔。我又聽師琴一撫，", "我又聽師棋一著，山頂坐沈紅日腳。阿誰稱是國手人，"]'),
('yuding-0','妾換馬','盧殷','唐','御定全唐诗','yuding','','[]','伴鳳樓中妾，如龍櫪上宛。同年辭舊寵，異地受新恩。',48,'御定全唐詩/json/470.json','["伴鳳樓中妾，如龍櫪上宛。同年辭舊寵，異地受新恩。", "香閣更衣處，塵蒙噴草痕。連嘶將忍淚，俱戀主人門。"]'),
('yuding-1','七夕','盧殷','唐','御定全唐诗','yuding','','[]','河耿月涼時，牽牛織女期。歡娛方在此，漏刻竟由誰。',48,'御定全唐詩/json/470.json','["河耿月涼時，牽牛織女期。歡娛方在此，漏刻竟由誰。", "定不嫌秋駛，唯當乞夜遲。全勝客子婦，十載泣生離。"]'),
('yuding-2','月夜','盧殷','唐','御定全唐诗','yuding','','[]','露下涼生簟，無人月滿庭。難聞逆河浪，徒望白榆星。',48,'御定全唐詩/json/470.json','["露下涼生簟，無人月滿庭。難聞逆河浪，徒望白榆星。", "樹繞孤棲鵲，窗飛就暗螢。移時宿蘭影，思共習芳馨。"]'),
('yuding-3','仲夏寄江南','盧殷','唐','御定全唐诗','yuding','','[]','五月行將近，三年客未回。夢成千里去，酒醒百憂來。',48,'御定全唐詩/json/470.json','["五月行將近，三年客未回。夢成千里去，酒醒百憂來。", "晚暮時看槿，悲酸不食梅。空將白團扇，從寄複裴回。"]'),
('yuding-4','欲銷雲','盧殷','唐','御定全唐诗','yuding','','[]','欲隱從龍質，仍餘觸石文。霏微依碧落，仿佛誤非雲。',48,'御定全唐詩/json/470.json','["欲隱從龍質，仍餘觸石文。霏微依碧落，仿佛誤非雲。", "度月光無隔，傾河影不分。如逢作霖處，當為起氤氳。"]'),
('yuding-5','遇邊使','盧殷','唐','御定全唐诗','yuding','','[]','累年無的信，每夜夢邊城。袖掩千行淚，書封一尺情。',24,'御定全唐詩/json/470.json','["累年無的信，每夜夢邊城。袖掩千行淚，書封一尺情。"]'),
('yuding-6','移住別居','盧殷','唐','御定全唐诗','yuding','','[]','自到西川住，唯君別有情。常逢對門遠，又隔一重城。',24,'御定全唐詩/json/470.json','["自到西川住，唯君別有情。常逢對門遠，又隔一重城。"]'),
('yuding-7','堋口逢友人','盧殷','唐','御定全唐诗','yuding','','[]','艱難別離久，中外往還深。已改當時法，空餘舊日心。',24,'御定全唐詩/json/470.json','["艱難別離久，中外往還深。已改當時法，空餘舊日心。"]'),
('yuding-8','雨霽登北岸寄友人','盧殷','唐','御定全唐诗','yuding','','[]','稻黃撲撲黍油油，野樹連山澗自流。',32,'御定全唐詩/json/470.json','["稻黃撲撲黍油油，野樹連山澗自流。", "憶得年時馮翊部，謝郎相引上樓頭。"]'),
('yuding-9','長安親故','盧殷','唐','御定全唐诗','yuding','','[]','楚蘭不佩佩吳鉤，帶酒城頭別舊遊。',32,'御定全唐詩/json/470.json','["楚蘭不佩佩吳鉤，帶酒城頭別舊遊。", "年事已多筋力在，試將弓箭到並州。"]'),
('yuding-10','悲秋','盧殷','唐','御定全唐诗','yuding','','[]','秋空雁度青天遠，疏樹蟬嘶白露寒。',32,'御定全唐詩/json/470.json','["秋空雁度青天遠，疏樹蟬嘶白露寒。", "階下敗蘭猶有氣，手中團扇漸無端。"]'),
('yuding-11','晚蟬','盧殷','唐','御定全唐诗','yuding','','[]','深藏高柳背斜暉，能軫孤愁減昔圍。',32,'御定全唐詩/json/470.json','["深藏高柳背斜暉，能軫孤愁減昔圍。", "猶畏旅人頭不白，再三移樹帶聲飛。"]'),
('yuding-12','維揚郡西亭贈友人','盧殷','唐','御定全唐诗','yuding','','[]','萍颯風池香滿船，楊花漠漠暮春天。',32,'御定全唐詩/json/470.json','["萍颯風池香滿船，楊花漠漠暮春天。", "玉人此日心中事，何似乘羊入市年。"]'),
('yuding-13','終南精舍月中聞磬','獨孤申叔','唐','御定全唐诗','yuding','','[]','精廬殘夜景，天宇滅埃氛。幽磬此時擊，餘音幾處聞。',72,'御定全唐詩/json/470.json','["精廬殘夜景，天宇滅埃氛。幽磬此時擊，餘音幾處聞。", "隨風樹杪去，支策月中分。斷絕如殘漏，淒清不隔雲。", "羈人方罷夢，獨雁忽迷群。響盡河漢落，千山空糾紛。"]'),
('yuding-14','題漢州西湖','嚴公弼','唐','御定全唐诗','yuding','','[]','西湖創置自房公，心匠縱橫造化同。',32,'御定全唐詩/json/470.json','["西湖創置自房公，心匠縱橫造化同。", "見說鳳池推獨步，高名何事滯川中。"]'),
('yuding-15','題漢州西湖','嚴公貺','唐','御定全唐诗','yuding','','[]','鳳沼才難盡，餘思鑿西湖。珍木羅修岸，冰光映坐隅。',48,'御定全唐詩/json/470.json','["鳳沼才難盡，餘思鑿西湖。珍木羅修岸，冰光映坐隅。", "琴台今寂寞，竹島尚縈紆。猶蘊濟川志，芳名終不渝。"]'),
('yuding-16','湘弦曲','莊南傑','唐','御定全唐诗','yuding','','[]','楚雲錚錚戛秋露，巫雲峽雨飛朝暮。古磬高敲百尺樓，',48,'御定全唐詩/json/470.json','["楚雲錚錚戛秋露，巫雲峽雨飛朝暮。古磬高敲百尺樓，", "鶯啼寂寞花枝雨，鬼嘯荒郊松柏風。滿堂怨咽悲相續，"]'),
('yuding-17','黃雀行','莊南傑','唐','御定全唐诗','yuding','','[]','穿屋穿牆不知止，爭樹爭巢入營死。林間公子挾彈弓，',40,'御定全唐詩/json/470.json','["穿屋穿牆不知止，爭樹爭巢入營死。林間公子挾彈弓，", "虞人設網當要路，白日啾嘲禍萬機。"]'),
('yuding-18','雁門太守行','莊南傑','唐','御定全唐诗','yuding','','[]','旌旗閃閃搖天末，長笛橫吹虜塵闊。跨下嘶風白練獰，',40,'御定全唐詩/json/470.json','["旌旗閃閃搖天末，長笛橫吹虜塵闊。跨下嘶風白練獰，", "九泉寂寞葬秋蟲，濕雲荒草啼秋思。"]'),
('yuding-19','陽春曲','莊南傑','唐','御定全唐诗','yuding','','[]','紫錦紅囊香滿風，金鸞玉軾搖丁冬。沙鷗白羽翦晴碧，',40,'御定全唐詩/json/470.json','["紫錦紅囊香滿風，金鸞玉軾搖丁冬。沙鷗白羽翦晴碧，", "鳳葉龍吟白日長，落花聲底仙娥醉。"]'),
('yuding-20','傷歌行','莊南傑','唐','御定全唐诗','yuding','','[]','兔走烏飛不相見，人事依稀速如電。王母夭桃一度開，',48,'御定全唐詩/json/470.json','["兔走烏飛不相見，人事依稀速如電。王母夭桃一度開，", "秋雨無情不惜花，芙蓉一一驚香倒。勸君莫謾栽荊棘，"]'),
('yuding-21','無題','李溟','唐','御定全唐诗','yuding','','[]','喬木掛斗邑，水驛壞門開。向月片帆去，背雲行雁來。',48,'御定全唐詩/json/470.json','["喬木掛斗邑，水驛壞門開。向月片帆去，背雲行雁來。", "晚年名利跡，甯免路岐哀。前計不能息，若為玄鬢回。"]'),
('yuding-22','客舍喜友人相訪','賀蘭朋吉','唐','御定全唐诗','yuding','','[]','荒居無四鄰，誰肯訪來頻。古樹秋中葉，他鄉病裏身。',48,'御定全唐詩/json/470.json','["荒居無四鄰，誰肯訪來頻。古樹秋中葉，他鄉病裏身。", "雁聲風送急，螢影月流新。獨為成名晚，多慚見友人。"]'),
('yuding-23','詣李侍郎','王魯複','唐','御定全唐诗','yuding','','[]','文字元無底，功夫轉到難。苦心三百首，暫請侍郎看。',24,'御定全唐詩/json/470.json','["文字元無底，功夫轉到難。苦心三百首，暫請侍郎看。"]'),
('yuding-24','吊靈均','王魯複','唐','御定全唐诗','yuding','','[]','萬古汨羅深，騷人道不沉。明明唐日月，應見楚臣心。',24,'御定全唐詩/json/470.json','["萬古汨羅深，騷人道不沉。明明唐日月，應見楚臣心。"]'),
('yuding-25','吊韓侍郎','王魯複','唐','御定全唐诗','yuding','','[]','星落少微宮，高人入古風。幾年才子淚，並寫五言中。',24,'御定全唐詩/json/470.json','["星落少微宮，高人入古風。幾年才子淚，並寫五言中。"]'),
('yuding-26','故白岩禪師院','王魯複','唐','御定全唐诗','yuding','','[]','能師還世名還在，空閉禪堂滿院苔。',32,'御定全唐詩/json/470.json','["能師還世名還在，空閉禪堂滿院苔。", "花樹不隨人寂寞，數枝猶自出牆來。"]'),
('yuding-27','招玉川子詠新文','徐希仁','唐','御定全唐诗','yuding','','[]','清氣宿我心，結為清泠音。一夜吟不足，君來相和吟。',24,'御定全唐詩/json/470.json','["清氣宿我心，結為清泠音。一夜吟不足，君來相和吟。"]'),
('yuding-0','五雜組','雍裕之','唐','御定全唐诗','yuding','','[]','五雜組，刺繡窠。往復還，織錦梭。不得已，戍交河。',24,'御定全唐詩/json/471.json','["五雜組，刺繡窠。往復還，織錦梭。不得已，戍交河。"]'),
('yuding-1','剪綵花','雍裕之','唐','御定全唐诗','yuding','','[]','敢競桃李色，自呈刀尺功。蝶猶迷剪翠，人豈辨裁紅。',24,'御定全唐詩/json/471.json','["敢競桃李色，自呈刀尺功。蝶猶迷剪翠，人豈辨裁紅。"]'),
('yuding-2','春晦送客','雍裕之','唐','御定全唐诗','yuding','','[]','野酌亂無巡，送君兼送春。明年春色至，莫作未歸人。',24,'御定全唐詩/json/471.json','["野酌亂無巡，送君兼送春。明年春色至，莫作未歸人。"]'),
('yuding-3','自君之出矣','雍裕之','唐','御定全唐诗','yuding','','[]','自君之出矣，寶鏡為誰明。思君如隴水，長聞嗚咽聲。',24,'御定全唐詩/json/471.json','["自君之出矣，寶鏡為誰明。思君如隴水，長聞嗚咽聲。"]'),
('yuding-4','四氣','雍裕之','唐','御定全唐诗','yuding','','[]','春禽猶競囀，夏木忽交陰。稍覺秋山遠，俄驚冬霰深。',24,'御定全唐詩/json/471.json','["春禽猶競囀，夏木忽交陰。稍覺秋山遠，俄驚冬霰深。"]'),
('yuding-5','四色','雍裕之','唐','御定全唐诗','yuding','','[]','壺中冰始結，盤上露初圓。何意瑤池雪，欲奪鶴毛鮮。',96,'御定全唐詩/json/471.json','["壺中冰始結，盤上露初圓。何意瑤池雪，欲奪鶴毛鮮。", "道士牛已至，仙家鳥亦來。骨為神不朽，眼向故人開。", "勞魴蓮渚內，汗馬火旗間。平生血誠盡，不獨左輪殷。", "已見池盡墨，誰言突不黔。漆身恩未報，貂裘弊豈嫌。"]'),
('yuding-6','大言','雍裕之','唐','御定全唐诗','yuding','','[]','四溟杯淥醑，五嶽髻青螺。揮汗曾成雨，畫地亦成河。',24,'御定全唐詩/json/471.json','["四溟杯淥醑，五嶽髻青螺。揮汗曾成雨，畫地亦成河。"]'),
('yuding-7','細言','雍裕之','唐','御定全唐诗','yuding','','[]','蚊眉自可托，蝸角豈勞爭。欲效絲毫力，誰知螻蟻誠。',24,'御定全唐詩/json/471.json','["蚊眉自可托，蝸角豈勞爭。欲效絲毫力，誰知螻蟻誠。"]'),
('yuding-8','山中桂','雍裕之','唐','御定全唐诗','yuding','','[]','八樹拂丹霄，四時青不凋。秋風何處起，先嫋最長條。',24,'御定全唐詩/json/471.json','["八樹拂丹霄，四時青不凋。秋風何處起，先嫋最長條。"]'),
('yuding-9','蘆花','雍裕之','唐','御定全唐诗','yuding','','[]','夾岸複連沙，枝枝搖浪花。月明渾似雪，無處認漁家。',24,'御定全唐詩/json/471.json','["夾岸複連沙，枝枝搖浪花。月明渾似雪，無處認漁家。"]'),
('yuding-10','江邊柳','雍裕之','唐','御定全唐诗','yuding','','[]','嫋嫋古堤邊，青青一樹煙。若為絲不斷，留取系郎船。',24,'御定全唐詩/json/471.json','["嫋嫋古堤邊，青青一樹煙。若為絲不斷，留取系郎船。"]'),
('yuding-11','江上山','雍裕之','唐','御定全唐诗','yuding','','[]','綺霞明赤岸，錦纜繞丹枝。楚客正愁絕，西風且莫吹。',24,'御定全唐詩/json/471.json','["綺霞明赤岸，錦纜繞丹枝。楚客正愁絕，西風且莫吹。"]'),
('yuding-12','遊絲','雍裕之','唐','御定全唐诗','yuding','','[]','遊絲何所似，應最似春心。一向風前亂，千條不可尋。',24,'御定全唐詩/json/471.json','["遊絲何所似，應最似春心。一向風前亂，千條不可尋。"]'),
('yuding-13','柳絮','雍裕之','唐','御定全唐诗','yuding','','[]','無風才到地，有風還滿空。緣渠偏似雪，莫近鬢毛生。',24,'御定全唐詩/json/471.json','["無風才到地，有風還滿空。緣渠偏似雪，莫近鬢毛生。"]'),
('yuding-14','殘鶯','雍裕之','唐','御定全唐诗','yuding','','[]','花闌鶯亦懶，不語似含情。何言百囀舌，唯餘一兩聲。',24,'御定全唐詩/json/471.json','["花闌鶯亦懶，不語似含情。何言百囀舌，唯餘一兩聲。"]'),
('yuding-15','早蟬','雍裕之','唐','御定全唐诗','yuding','','[]','一聲清溽暑，幾處促流年。志士心偏苦，初聞獨泫然。',24,'御定全唐詩/json/471.json','["一聲清溽暑，幾處促流年。志士心偏苦，初聞獨泫然。"]'),
('yuding-16','秋蛩','雍裕之','唐','御定全唐诗','yuding','','[]','雨絕蒼苔地，月斜青草階。蛩鳴誰不怨，況是正離懷。',24,'御定全唐詩/json/471.json','["雨絕蒼苔地，月斜青草階。蛩鳴誰不怨，況是正離懷。"]'),
('yuding-17','江上聞猿','雍裕之','唐','御定全唐诗','yuding','','[]','楓岸月斜明，猿啼旅夢驚。愁多腸易斷，不待第三聲。',24,'御定全唐詩/json/471.json','["楓岸月斜明，猿啼旅夢驚。愁多腸易斷，不待第三聲。"]'),
('yuding-18','折柳贈行人','雍裕之','唐','御定全唐诗','yuding','','[]','那言柳亂垂，盡日任風吹。欲識千條恨，和煙折一枝。',24,'御定全唐詩/json/471.json','["那言柳亂垂，盡日任風吹。欲識千條恨，和煙折一枝。"]'),
('yuding-19','題蒲葵扇','雍裕之','唐','御定全唐诗','yuding','','[]','傾心曾向日，在手幸搖風。羨爾逢提握，知名自謝公。',24,'御定全唐詩/json/471.json','["傾心曾向日，在手幸搖風。羨爾逢提握，知名自謝公。"]'),
('yuding-20','贈苦行僧','雍裕之','唐','御定全唐诗','yuding','','[]','幽深紅葉寺，清淨白毫僧。古殿長鳴磬，低頭禮晝燈。',24,'御定全唐詩/json/471.json','["幽深紅葉寺，清淨白毫僧。古殿長鳴磬，低頭禮晝燈。"]'),
('yuding-21','兩頭纖纖','雍裕之','唐','御定全唐诗','yuding','','[]','兩頭纖纖八字眉，半白半黑燈影帷。',32,'御定全唐詩/json/471.json','["兩頭纖纖八字眉，半白半黑燈影帷。", "腷腷膊膊曉禽飛，磊磊落落秋果垂。"]'),
('yuding-22','了語','雍裕之','唐','御定全唐诗','yuding','','[]','掃卻煙塵寇初剿，深水高林放魚鳥。',32,'御定全唐詩/json/471.json','["掃卻煙塵寇初剿，深水高林放魚鳥。", "雞人唱絕殘漏曉，仙樂拍終天悄悄。"]'),
('yuding-23','不了語','雍裕之','唐','御定全唐诗','yuding','','[]','浮名世利知多少，朝市喧喧塵擾擾。',32,'御定全唐詩/json/471.json','["浮名世利知多少，朝市喧喧塵擾擾。", "車馬交馳往復來，鐘鼓相催天又曉。"]'),
('yuding-24','聽彈沈湘','雍裕之','唐','御定全唐诗','yuding','','[]','賈誼投文吊屈平，瑤琴能寫此時情。',32,'御定全唐詩/json/471.json','["賈誼投文吊屈平，瑤琴能寫此時情。", "秋風一奏沈湘曲，流水千年作恨聲。"]'),
('yuding-25','豪家夏冰詠','雍裕之','唐','御定全唐诗','yuding','','[]','金錯銀盤貯賜冰，清光如聳玉山棱。',32,'御定全唐詩/json/471.json','["金錯銀盤貯賜冰，清光如聳玉山棱。", "無論塵客閑停扇，直到消時不見蠅。"]'),
('yuding-26','宿棣華館聞雁','雍裕之','唐','御定全唐诗','yuding','','[]','不堪旅宿棣花館，況有離群鴻雁聲。',32,'御定全唐詩/json/471.json','["不堪旅宿棣花館，況有離群鴻雁聲。", "一點秋燈殘影下，不知寒夢幾回驚。"]'),
('yuding-27','農家望晴','雍裕之','唐','御定全唐诗','yuding','','[]','嘗聞秦地西風雨，為問西風早晚回。',32,'御定全唐詩/json/471.json','["嘗聞秦地西風雨，為問西風早晚回。", "白髮老農如鶴立，麥場高處望雲開。"]'),
('yuding-28','宮人斜','雍裕之','唐','御定全唐诗','yuding','','[]','幾多紅粉委黃泥，野鳥如歌又似啼。',32,'御定全唐詩/json/471.json','["幾多紅粉委黃泥，野鳥如歌又似啼。", "應有春魂化為燕，年來飛入未央棲。"]'),
('yuding-29','曲江池上','雍裕之','唐','御定全唐诗','yuding','','[]','殷勤春在曲江頭，全藉群仙占勝遊。',32,'御定全唐詩/json/471.json','["殷勤春在曲江頭，全藉群仙占勝遊。", "何必三山待鸞鶴，年年此地是瀛洲。"]'),
('yuding-0','奉陪呂使君樓上夜看花','段弘古','唐','御定全唐诗','yuding','','[]','城上芳園花滿枝，城頭太守夜看時。',32,'御定全唐詩/json/472.json','["城上芳園花滿枝，城頭太守夜看時。", "為報林中高舉燭，感人情思欲題詩。"]'),
('yuding-1','所居寺院涼夜書情，呈上呂和叔溫郎中','何元上','唐','御定全唐诗','yuding','','[]','庾公念病宜清暑，遣向僧家占上方。月光似水衣裳濕，',40,'御定全唐詩/json/472.json','["庾公念病宜清暑，遣向僧家占上方。月光似水衣裳濕，", "何由一示雲霄路，腸斷星星兩鬢霜。"]'),
('yuding-2','塞上聞笛','宋濟','唐','御定全唐诗','yuding','','[]','胡兒吹笛戍樓間，樓上蕭條海月閑。',32,'御定全唐詩/json/472.json','["胡兒吹笛戍樓間，樓上蕭條海月閑。", "借問梅花何處落，風吹一夜滿關山。"]'),
('yuding-3','東鄰美人歌','宋濟','唐','御定全唐诗','yuding','','[]','花暖江城斜日陰，鶯啼繡戶曉雲深。',32,'御定全唐詩/json/472.json','["花暖江城斜日陰，鶯啼繡戶曉雲深。", "春風不道珠簾隔，傳得歌聲與客心。"]'),
('yuding-4','題李八百洞','符載','唐','御定全唐诗','yuding','','[]','太極之年混沌坼，此山亦是神仙宅。',32,'御定全唐詩/json/472.json','["太極之年混沌坼，此山亦是神仙宅。", "後世何人來飛升，紫陽真人李八百。"]'),
('yuding-5','甘州歌','符載','唐','御定全唐诗','yuding','','[]','月裏嫦娥不畫眉，只將雲霧作羅衣。',32,'御定全唐詩/json/472.json','["月裏嫦娥不畫眉，只將雲霧作羅衣。", "不知夢逐青鸞去，猶把花枝蓋面歸。"]'),
('yuding-6','句','符載','唐','御定全唐诗','yuding','','[]','綠迸穿籬筍，紅飄隔戶花。',12,'御定全唐詩/json/472.json','["綠迸穿籬筍，紅飄隔戶花。"]'),
('yuding-7','貞元八年十二月謁先主廟絕句三首','張儼','唐','御定全唐诗','yuding','','[]','仗順繼皇業，併吞勢由己。天命屈雄圖，誰歌大風起。',72,'御定全唐詩/json/472.json','["仗順繼皇業，併吞勢由己。天命屈雄圖，誰歌大風起。", "得股肱賢明，能以奇用兵。何事傷客情，何人歸帝京。", "雄名垂竹帛，荒陵壓阡陌。終古更何聞，悲風入松柏。"]'),
('yuding-8','題安樂山','先汪','唐','御定全唐诗','yuding','','[]','碧峰橫倚白雲端，隋氏真人化跡殘。',32,'御定全唐詩/json/472.json','["碧峰橫倚白雲端，隋氏真人化跡殘。", "翠柏不凋龍骨瘦，石泉猶在鏡光寒。"]'),
('yuding-9','姑熟雜詠：姑熟溪','李赤','唐','御定全唐诗','yuding','','[]','愛此溪水閑，乘流興無極。擊楫怕鷗驚，垂竿待魚食。',48,'御定全唐詩/json/472.json','["愛此溪水閑，乘流興無極。擊楫怕鷗驚，垂竿待魚食。", "波翻曉霞影，岸疊春山色。何處浣紗人，紅顏未相識。"]'),
('yuding-10','姑熟雜詠：丹陽湖','李赤','唐','御定全唐诗','yuding','','[]','湖與元氣通，風波浩難止。天外賈客歸，雲間片帆起。',48,'御定全唐詩/json/472.json','["湖與元氣通，風波浩難止。天外賈客歸，雲間片帆起。", "龜游蓮葉上，鳥宿蘆花裏。少女棹舟歸，歌聲逐流水。"]'),
('yuding-11','姑熟雜詠：謝公宅','李赤','唐','御定全唐诗','yuding','','[]','青山日將暝，寂寞謝公宅。竹裏無人聲，池中虛月白。',48,'御定全唐詩/json/472.json','["青山日將暝，寂寞謝公宅。竹裏無人聲，池中虛月白。", "荒庭衰草遍，廢井蒼苔積。唯有清風聞，時時起泉石。"]'),
('yuding-12','姑熟雜詠：淩歊台','李赤','唐','御定全唐诗','yuding','','[]','曠望登古台，台高極人目。疊嶂列遠空，閑花雜平陸。',48,'御定全唐詩/json/472.json','["曠望登古台，台高極人目。疊嶂列遠空，閑花雜平陸。", "白雲入窗牖，野翠生松竹。欲覽碑上文，苔侵豈堪讀。"]'),
('yuding-13','姑熟雜詠：桓公井','李赤','唐','御定全唐诗','yuding','','[]','桓公名已古，廢井曾未竭。石甃冷蒼苔，寒泉湛孤月。',48,'御定全唐詩/json/472.json','["桓公名已古，廢井曾未竭。石甃冷蒼苔，寒泉湛孤月。", "秋來桐暫落，春至桃還發。路遠人罕窺，誰能見清澈。"]'),
('yuding-14','姑熟雜詠：慈姥竹','李赤','唐','御定全唐诗','yuding','','[]','野竹攢石生，含煙映江島。翠色落波深，虛聲帶寒早。',48,'御定全唐詩/json/472.json','["野竹攢石生，含煙映江島。翠色落波深，虛聲帶寒早。", "龍吟曾未聽，鳳曲吹應好。不學蒲柳凋，貞心常自保。"]'),
('yuding-15','姑熟雜詠：望夫山','李赤','唐','御定全唐诗','yuding','','[]','顒望臨碧空，怨情感離別。芳草不知愁，岩花但爭發。',48,'御定全唐詩/json/472.json','["顒望臨碧空，怨情感離別。芳草不知愁，岩花但爭發。", "雲山萬重隔，音信千里絕。春去秋複來，相思幾時歇。"]'),
('yuding-16','姑熟雜詠：牛渚磯','李赤','唐','御定全唐诗','yuding','','[]','絕壁臨巨川，連峰勢相向。亂石流洑間，回波自成浪。',48,'御定全唐詩/json/472.json','["絕壁臨巨川，連峰勢相向。亂石流洑間，回波自成浪。", "但驚群木秀，莫測精靈狀。更聽猿夜啼，憂心醉江上。"]'),
('yuding-17','姑熟雜詠：靈墟山','李赤','唐','御定全唐诗','yuding','','[]','丁令辭世人，拂衣向仙路。伏煉九丹成，方隨五雲去。',48,'御定全唐詩/json/472.json','["丁令辭世人，拂衣向仙路。伏煉九丹成，方隨五雲去。", "松蘿蔽幽洞，桃杏深隱處。不知曾化鶴，遼海歸幾度。"]'),
('yuding-18','姑熟雜詠：天門山','李赤','唐','御定全唐诗','yuding','','[]','迥出江水上，雙峰自相對。岸映松色寒，石分浪花碎。',48,'御定全唐詩/json/472.json','["迥出江水上，雙峰自相對。岸映松色寒，石分浪花碎。", "參差遠天際，縹緲晴霞外。落日舟去遙，回首沈青靄。"]'),
('yuding-19','敕贈康尚書美人','薛zm','唐','御定全唐诗','yuding','','[]','天門喜氣曉氛氳，聖主臨軒召冠軍。',32,'御定全唐詩/json/472.json','["天門喜氣曉氛氳，聖主臨軒召冠軍。", "欲令從此行霖雨，先賜巫山一片雲。"]'),
('yuding-20','將赴東都上李相國','孫叔向','唐','御定全唐诗','yuding','','[]','四海兵初偃，平津閣正開。誰知大爐火，還有不然灰。',24,'御定全唐詩/json/472.json','["四海兵初偃，平津閣正開。誰知大爐火，還有不然灰。"]'),
('yuding-21','題昭應溫泉','孫叔向','唐','御定全唐诗','yuding','','[]','一道溫泉繞禦樓，先皇曾向此中游。',32,'御定全唐詩/json/472.json','["一道溫泉繞禦樓，先皇曾向此中游。", "雖然水是無情物，也到宮前咽不流。"]'),
('yuding-22','送咸安公主','孫叔向','唐','御定全唐诗','yuding','','[]','鹵簿遲遲出國門，漢家公主嫁烏孫。',32,'御定全唐詩/json/472.json','["鹵簿遲遲出國門，漢家公主嫁烏孫。", "玉顏便向穹廬去，衛霍空承明主恩。"]'),
('yuding-23','邊城柳','劉皂','唐','御定全唐诗','yuding','','[]','一株新柳色，十裏斷孤城。為近東西路，長懸離別情。',24,'御定全唐詩/json/472.json','["一株新柳色，十裏斷孤城。為近東西路，長懸離別情。"]'),
('yuding-24','長門怨三首','劉皂','唐','御定全唐诗','yuding','','[]','雨滴長門秋夜長，愁心和雨到昭陽。',96,'御定全唐詩/json/472.json','["雨滴長門秋夜長，愁心和雨到昭陽。", "淚痕不學君恩斷，拭卻千行更萬行。", "宮殿沉沉月欲分，昭陽更漏不堪聞。", "珊瑚枕上千行淚，不是思君是恨君。", "蟬鬢慵梳倚帳門，蛾眉不掃慣承恩。", "旁人未必知心事，一面殘妝空淚痕。"]'),
('yuding-25','旅次朔方','劉皂','唐','御定全唐诗','yuding','','[]','客舍並州數十霜，歸心日夜憶咸陽。',32,'御定全唐詩/json/472.json','["客舍並州數十霜，歸心日夜憶咸陽。", "無端又渡桑幹水，卻望並州似故鄉。"]'),
('yuding-26','早起','楊厚','唐','御定全唐诗','yuding','','[]','星漢轉寒更，伊余索寞情。鐘催歸夢斷，雁引遠愁生。',48,'御定全唐詩/json/472.json','["星漢轉寒更，伊余索寞情。鐘催歸夢斷，雁引遠愁生。", "危壁蘭光暗，疏簾露氣清。閒庭聊一望，海日未分明。"]'),
('yuding-27','長門怨','裴交泰','唐','御定全唐诗','yuding','','[]','自閉長門經幾秋，羅衣濕盡淚還流。',32,'御定全唐詩/json/472.json','["自閉長門經幾秋，羅衣濕盡淚還流。", "一種蛾眉明月夜，南宮歌管北宮愁。"]'),
('yuding-28','禁中送任山人','李秘','唐','御定全唐诗','yuding','','[]','子去非長往，君恩取大還。補天留彩石，縮地入青山。',48,'御定全唐詩/json/472.json','["子去非長往，君恩取大還。補天留彩石，縮地入青山。", "獻壽千春外，來朝數月間。莫拋殘藥物，竊取駐童顏。"]'),
('yuding-29','府試中元觀道流步虛','殷堯恭','唐','御定全唐诗','yuding','','[]','玄都開秘籙，白石禮先生。上界秋光靜，中元夜景清。',72,'御定全唐詩/json/472.json','["玄都開秘籙，白石禮先生。上界秋光靜，中元夜景清。", "星辰朝帝處，鸞鶴步虛聲。玉洞花長髮，珠宮月最明。", "掃壇天地肅，投簡鬼神驚。倘賜刀圭藥，還成不死名。"]'),
('yuding-30','王仙壇','林傑','唐','御定全唐诗','yuding','','[]','羽客已登仙路去，丹爐草木盡凋殘。',32,'御定全唐詩/json/472.json','["羽客已登仙路去，丹爐草木盡凋殘。", "不知千載歸何日，空使時人掃舊壇。"]'),
('yuding-31','乞巧','林傑','唐','御定全唐诗','yuding','','[]','七夕今宵看碧霄，牽牛織女渡河橋。',32,'御定全唐詩/json/472.json','["七夕今宵看碧霄，牽牛織女渡河橋。", "家家乞巧望秋月，穿盡紅絲幾萬條。"]'),
('yuding-32','句','林傑','唐','御定全唐诗','yuding','','[]','金盤摘下掛朱顆，紅殼開時飲玉漿。',16,'御定全唐詩/json/472.json','["金盤摘下掛朱顆，紅殼開時飲玉漿。"]'),
('yuding-33','哭林傑','鄭立之','唐','御定全唐诗','yuding','','[]','才高未及賈生年，何事孤魂逐逝川。',32,'御定全唐詩/json/472.json','["才高未及賈生年，何事孤魂逐逝川。", "螢聚帳中人已去，鶴離臺上月空圓。"]'),
('yuding-34','詠和親','蘇郁','唐','御定全唐诗','yuding','','[]','關月夜懸青塚鏡，寒雲秋薄漢宮羅。',32,'御定全唐詩/json/472.json','["關月夜懸青塚鏡，寒雲秋薄漢宮羅。", "君王莫信和親策，生得胡雛虜更多。"]'),
('yuding-35','鸚鵡詞','蘇郁','唐','御定全唐诗','yuding','','[]','莫把金籠閉鸚鵡，個個分明解人語。',32,'御定全唐詩/json/472.json','["莫把金籠閉鸚鵡，個個分明解人語。", "忽然更向君前言，三十六宮愁幾許。"]'),
('yuding-36','步虛詞','蘇鬱','唐','御定全唐诗','yuding','','[]','十二樓藏玉堞中，鳳凰雙宿碧芙蓉。',32,'御定全唐詩/json/472.json','["十二樓藏玉堞中，鳳凰雙宿碧芙蓉。", "流霞淺酌誰同醉，今夜笙歌第幾重。"]'),
('yuding-37','句','蘇鬱','唐','御定全唐诗','yuding','','[]','吟倚雨殘樹，月收山下村。',12,'御定全唐詩/json/472.json','["吟倚雨殘樹，月收山下村。"]'),
('yuding-38','賦得琢玉成器','浩虛舟','唐','御定全唐诗','yuding','','[]','已沐識堅貞，應憐器未成。輝山方可重，散璞乍堪驚。',72,'御定全唐詩/json/472.json','["已沐識堅貞，應憐器未成。輝山方可重，散璞乍堪驚。", "玷滅隨心正，瑕消奪眼明。琢磨虹氣在，拂拭水容生。", "賞玩冰光冷，提攜月魄輕。佇當親捧握，瑚璉幸齊名。"]'),
('yuding-39','責商山四皓','蔡京','唐','御定全唐诗','yuding','','[]','秦末家家思逐鹿，商山四皓獨忘機。',32,'御定全唐詩/json/472.json','["秦末家家思逐鹿，商山四皓獨忘機。", "如何鬢髮霜相似，更出深山定是非。"]'),
('yuding-40','假節邕交道由吳溪','蔡京','唐','御定全唐诗','yuding','','[]','停橈橫水中，舉目孤煙外。借問吳溪人，誰家有山賣。',24,'御定全唐詩/json/472.json','["停橈橫水中，舉目孤煙外。借問吳溪人，誰家有山賣。"]'),
('yuding-41','詠子規','蔡京','唐','御定全唐诗','yuding','','[]','千年冤魄化為禽，永逐悲風叫遠林。愁血滴花春豔死，',40,'御定全唐詩/json/472.json','["千年冤魄化為禽，永逐悲風叫遠林。愁血滴花春豔死，", "腸斷楚詞歸不得，劍門迢遞蜀江深。"]'),
('yuding-42','獻蔡京','張頂','唐','御定全唐诗','yuding','','[]','拋卻長竿卷卻絲，手持蓑笠獻新詩。',32,'御定全唐詩/json/472.json','["拋卻長竿卷卻絲，手持蓑笠獻新詩。", "臨川太守清如鏡，不是漁人下釣時。"]'),
('yuding-0','享惠昭太子廟樂章','李逢吉','唐','御定全唐诗','yuding','','[]','既潔酒醴，聿陳熟腥。肅將震念，昭格儲靈。',40,'御定全唐詩/json/473.json','["既潔酒醴，聿陳熟腥。肅將震念，昭格儲靈。", "展矣禮典，熏然德馨。愔愔管磬，亦具是聽。"]'),
('yuding-1','望京樓上寄令狐華州','李逢吉','唐','御定全唐诗','yuding','','[]','祇役滯南服，頹思屬暮年。閑上望京台，萬山蔽其前。',84,'御定全唐詩/json/473.json','["祇役滯南服，頹思屬暮年。閑上望京台，萬山蔽其前。", "落日歸飛翼，連翩東北天。涪江適在下，為我久潺湲。", "中葉成文教，德威清遠邊。頒條信徒爾，華發生蒼然。", "寄懷三峰守，岐路隔雲煙。"]'),
('yuding-2','再赴襄陽，辱宣武相公貽詩，今用奉酬','李逢吉','唐','御定全唐诗','yuding','','[]','解韍辭丹禁，揚旌去赤墀。自驚非素望，何力及清時。',72,'御定全唐詩/json/473.json','["解韍辭丹禁，揚旌去赤墀。自驚非素望，何力及清時。", "又據三公席，多慚四老祠。峴山風已遠，棠樹事難追。", "江漢饒春色，荊蠻足夢思。唯憐吐鳳句，相示鑿龍期。"]'),
('yuding-3','奉送李相公重鎮襄陽','李逢吉','唐','御定全唐诗','yuding','','[]','海內埏埴遍，漢陰旌旆還。望留丹闕下，恩在紫霄間。',72,'御定全唐詩/json/473.json','["海內埏埴遍，漢陰旌旆還。望留丹闕下，恩在紫霄間。", "冰雪背秦嶺，風煙經武關。樹皆人尚愛，轅即吏曾攀。", "自惜兩心合，相看雙鬢斑。終期謝戎務，同隱鑿龍山。"]'),
('yuding-4','和嚴揆省中宿齋遇令狐員外當直之作','李逢吉','唐','御定全唐诗','yuding','','[]','致齋分直宿南宮，越石盧諶此夜同。位極班行猶念舊，',40,'御定全唐詩/json/473.json','["致齋分直宿南宮，越石盧諶此夜同。位極班行猶念舊，", "竟夕文昌知有月，可憐如在庾樓中。"]'),
('yuding-5','奉酬忠武李相公見寄','李逢吉','唐','御定全唐诗','yuding','','[]','直繼先朝衛與英，能移孝友作忠貞。劍門失險曾縛虎，',40,'御定全唐詩/json/473.json','["直繼先朝衛與英，能移孝友作忠貞。劍門失險曾縛虎，", "惠連忽贈池塘句，又遣羸師破膽驚。"]'),
('yuding-6','酬致政楊祭酒見寄','李逢吉','唐','御定全唐诗','yuding','','[]','初還相印罷戎旃，獲守皇居在紫煙。妄比酂侯功蔑爾，',40,'御定全唐詩/json/473.json','["初還相印罷戎旃，獲守皇居在紫煙。妄比酂侯功蔑爾，", "十載別離那可道，倍令驚喜見來篇。"]'),
('yuding-7','送令狐秀才赴舉','李逢吉','唐','御定全唐诗','yuding','','[]','子有雄文藻思繁，齠年射策向金門。前隨鸞鶴登霄漢，',40,'御定全唐詩/json/473.json','["子有雄文藻思繁，齠年射策向金門。前隨鸞鶴登霄漢，", "那堪兩地生離緒，蓬戶長扃行旅喧。"]'),
('yuding-8','郡齋臥疾贈晝上人','於頔','唐','御定全唐诗','yuding','','[]','夙陪翰墨徒，深論窮文格。麗則風騷後，公然我詞客。',240,'御定全唐詩/json/473.json','["夙陪翰墨徒，深論窮文格。麗則風騷後，公然我詞客。", "晚依方外友，極理探精賾。吻合南北宗，晝公我禪伯。", "尤明性不染，故我行貞白。隨順令得解，故我言芳澤。", "霅水漾清潯，吳山橫碧岑。含珠複蘊玉，價重雙南金。", "的皪曜奇彩，淒清流雅音。商聲發楚調，調切譜瑤琴。", "吳山為我高，霅水為我深。萬景徒有象，孤雲本無心。", "眾木豈無聲，椅桐有清響。眾耳豈不聆，鐘期有真賞。", "高潔古人操，素懷夙所仰。覿君冰雪姿，祛我淫滯想。", "常吟柳惲詩，苕浦久相思。逮此遠為郡，蘋洲芳草衰。", "逢師年臘長，值我病容羸。共話無生理，聊用契心期。"]'),
('yuding-9','和丘員外題湛長史舊居','於頔','唐','御定全唐诗','yuding','','[]','蕭條曆山下，水木無氛滓。王門結長裾，岩扃怡暮齒。',72,'御定全唐詩/json/473.json','["蕭條曆山下，水木無氛滓。王門結長裾，岩扃怡暮齒。", "昔賢枕高躅，今彥仰知止。依依矚煙霞，眷眷返墟裏。", "湛生久已沒，丘也亦同恥。立言咸不朽，何必在青史。"]'),
('yuding-10','寒夜聞霜鐘','盧景亮','唐','御定全唐诗','yuding','','[]','洪鐘發長夜，清響出層岑。暗入繁霜切，遙傳古寺深。',72,'御定全唐詩/json/473.json','["洪鐘發長夜，清響出層岑。暗入繁霜切，遙傳古寺深。", "何城亂遠漏，幾處雜疏砧。已警離人夢，仍沾旅客襟。", "待時當命侶，抱器本無心。倘若無知者，誰能設此音。"]'),
('yuding-11','南溪詩','李渤','唐','御定全唐诗','yuding','','[]','玄岩麗南溪，新泉發幽色。岩泉孕靈秀，雲煙紛崖壁。',120,'御定全唐詩/json/473.json','["玄岩麗南溪，新泉發幽色。岩泉孕靈秀，雲煙紛崖壁。", "斜峰信天插，奇洞固神辟。窈窕去未窮，環回勢難極。", "玉池似無水，玄井昏不測。仙戶掩複開，乳膏凝更滴。", "丹砂有遺址，石徑無留跡。南眺蒼梧雲，北望洞庭客。", "蕭條風煙外，爽朗形神寂。若值浮丘翁，從此謝塵役。"]'),
('yuding-12','喜弟淑再至為長歌','李渤','唐','御定全唐诗','yuding','','[]','前年別時秋九月，白露吹霜金吹烈。離鴻一別影初分，',240,'御定全唐詩/json/473.json','["前年別時秋九月，白露吹霜金吹烈。離鴻一別影初分，", "廬山峨峨倚天碧，捧排空崖千萬尺。社榜長題高士名，", "自負心機四十年，羞聞社客山中篇。憂時魂夢憶歸路，", "吾吟行路五十篇，盡說江南數千里。自憐兄弟今五人，", "長兄年少曾落托，拔劍沙場隨衛霍。口裏雖譚周孔文，", "非論疾惡志如霜，更覺臨泉心似鐵。第三之兄更奇異，", "卻愁清逸不幹時，高蹤大器無人知。倘逢感激許然諾，", "卷中筆落星漢搖，洞裏丹靈鬼神泣。嗟餘流浪心最狂，", "廣海青山殊未足，逢著高樓還醉宿。朝走安公櫪上駒，", "雲騰浪走勢未衰，鶴膝蜂腰豈能障。送爾為文殊不識，"]'),
('yuding-13','留別南溪二首','李渤','唐','御定全唐诗','yuding','','[]','常歎春泉去不回，我今此去更難來。',64,'御定全唐詩/json/473.json','["常歎春泉去不回，我今此去更難來。", "欲知別後留情處，手種岩花次第開。", "如雲不厭蒼梧遠，似雁逢春又北歸。", "惟有隱山溪上月，年年相望兩依依。"]'),
('yuding-14','桂林歎雁','李渤','唐','御定全唐诗','yuding','','[]','三朝四黜倦遐征，往復皆愁萬里程。',32,'御定全唐詩/json/473.json','["三朝四黜倦遐征，往復皆愁萬里程。", "爾解分飛卻回去，我方從此向南行。"]'),
('yuding-15','享惠昭太子廟樂章','孟簡','唐','御定全唐诗','yuding','','[]','喧喧金石容既缺，肅肅羽駕就行列。',32,'御定全唐詩/json/473.json','["喧喧金石容既缺，肅肅羽駕就行列。", "緱山遺響昔所聞，廟庭進旅今攸設。"]'),
('yuding-16','擬古','孟簡','唐','御定全唐诗','yuding','','[]','劍客不誇貌，主人知此心。但營纖毫義，肯計千萬金。',48,'御定全唐詩/json/473.json','["劍客不誇貌，主人知此心。但營纖毫義，肯計千萬金。", "勇發看鷙擊，憤來聽虎吟。平生貴酬德，刃敵無幽深。"]'),
('yuding-17','詠歐陽行周事','孟簡','唐','御定全唐诗','yuding','','[]','有客西北逐，驅馬次太原。太原有佳人，神豔照行雲。',360,'御定全唐詩/json/473.json','["有客西北逐，驅馬次太原。太原有佳人，神豔照行雲。", "座上轉橫波，流光注夫君。夫君意蕩漾，即日相交歡。", "定情非一詞，結念誓青山。生死不變易，中誠無間言。", "此為太學徒，彼屬北府官。中夜欲相從，嚴城限軍門。", "白日欲同居，君畏仁人聞。忽如隴頭水，坐作東西分。", "驚離腸千結，滴淚眼雙昏。本達京師回，賀期相追攀。", "宿約始乖阻，彼憂已纏綿。高髻若黃鸝，危鬢如玉蟬。", "纖手自整理，剪刀斷其根。柔情托侍兒，為我遺所歡。", "所歡使者來，侍兒因複前。抆淚取遺寄，深誠祈為傳。", "封來贈君子，願言慰窮泉。使者回復命，遲遲蓄悲酸。", "詹生喜言旋，倒履走迎門。長跪聽未畢，驚傷涕漣漣。", "不飲亦不食，哀心百千端。襟情一夕空，精爽旦日殘。", "哀哉浩然氣，潰散歸化元。短生雖別離，長夜無阻難。", "雙魂終會合，兩劍遂蜿蜒。丈夫早通脫，巧笑安能幹。", "防身本苦節，一去何由還。後生莫沈迷，沈迷喪其真。"]'),
('yuding-18','惜分陰','孟簡','唐','御定全唐诗','yuding','','[]','業廣因功苦，拳拳志士心。九流難酌挹，四海易消沈。',72,'御定全唐詩/json/473.json','["業廣因功苦，拳拳志士心。九流難酌挹，四海易消沈。", "對景嗟移晷，窺園詎改陰。三冬勞聚學，駟景重兼金。", "刺股情方勵，偷光思益深。再中如可冀，終嗣絕編音。"]'),
('yuding-19','嘉禾合穎','孟簡','唐','御定全唐诗','yuding','','[]','玉燭將成歲，封人亦自歌。八方沾聖澤，異畝發嘉禾。',72,'御定全唐詩/json/473.json','["玉燭將成歲，封人亦自歌。八方沾聖澤，異畝發嘉禾。", "共秀芳何遠，連莖瑞且多。穎低甘露滴，影亂惠風過。", "表稔由神化，為祥識氣和。因知興嗣歲，王道舊無頗。"]'),
('yuding-20','賦得亞父碎玉鬥','孟簡','唐','御定全唐诗','yuding','','[]','獻謀既我違，積憤從心痗。鴻門入已迫，赤帝時潛退。',72,'御定全唐詩/json/473.json','["獻謀既我違，積憤從心痗。鴻門入已迫，赤帝時潛退。", "寶位方苦競，玉鬥何情愛。猶看虹氣凝，詎惜冰姿碎。", "而嗟大事返，當起千里悔。誰為西楚王，坐見東城潰。"]'),
('yuding-21','酬施先輩','孟簡','唐','御定全唐诗','yuding','','[]','襄陽才子得聲多，四海皆傳古鏡歌。',32,'御定全唐詩/json/473.json','["襄陽才子得聲多，四海皆傳古鏡歌。", "樂府正聲三百首，梨園新入教青娥。"]'),
('yuding-22','寄李十員外','王仲舒','唐','御定全唐诗','yuding','','[]','百丈懸泉舊臥龍，欲將肝膽佐時雍。',32,'御定全唐詩/json/473.json','["百丈懸泉舊臥龍，欲將肝膽佐時雍。", "惟愁又入煙霞去，知在廬峰第幾重。"]'),
('yuding-23','訪羊尊師','孫革','唐','御定全唐诗','yuding','','[]','松下問童子，言師采藥去。只在此山中，雲深不知處。',24,'御定全唐詩/json/473.json','["松下問童子，言師采藥去。只在此山中，雲深不知處。"]'),
('yuding-24','晚眺','汪萬於','唐','御定全唐诗','yuding','','[]','杖策倚柴門，泉聲隔岸聞。夕陽諸嶺出，晴雪萬山分。',48,'御定全唐詩/json/473.json','["杖策倚柴門，泉聲隔岸聞。夕陽諸嶺出，晴雪萬山分。", "靜對豺狼窟，幽觀鹿豕群。今宵寒月近，東北掃浮雲。"]'),
('yuding-25','亞父碎玉鬥','何儒亮','唐','御定全唐诗','yuding','','[]','嬴女昔解網，楚王有遺躅。破關既定秦，碎首聞獻玉。',72,'御定全唐詩/json/473.json','["嬴女昔解網，楚王有遺躅。破關既定秦，碎首聞獻玉。", "貞姿應刃散，清響因風續。匪徇切泥功，將明懷璧辱。", "莫量漢祖德，空受項君勖。事去見前心，千秋渭水綠。"]'),
('yuding-26','贈毛仙翁','李宗閔','唐','御定全唐诗','yuding','','[]','不知仙客占青春，肌骨才教稱兩旬。俗眼暫驚相見日，',40,'御定全唐詩/json/473.json','["不知仙客占青春，肌骨才教稱兩旬。俗眼暫驚相見日，", "殘藥倘能沾朽質，願將霄漢永為鄰。"]'),
('yuding-27','池州夫子廟麟台','韋表微','唐','御定全唐诗','yuding','','[]','二儀既閉，三象乃乖。聖道埋郁，人心不開。',200,'御定全唐詩/json/473.json','["二儀既閉，三象乃乖。聖道埋郁，人心不開。", "上無文武，下有定哀。籲嗟麟兮，孰為來哉。", "周雖不綱，孔實嗣聖。詩書既刪，禮樂大定。", "勸善懲惡，奸邪乃正。籲嗟麟兮，克昭符命。", "聖與時合，代行位尊。苟或乖戾，身窮道存。", "于昭魯邑，棲遲孔門。籲嗟麟兮，孰知其仁。", "運極數殘，德至時否。楚國浸廣，秦封益侈。", "牆仞迫厄，崎嶇闕裏。籲嗟麟兮，靡有攸止。", "世治則麟，世亂則麇。出非其時，麋鹿同群。", "孔不自聖，麟不自祥。籲嗟麟兮，天何所亡。"]'),
('yuding-0','送馬向入蜀','徐凝','唐','御定全唐诗','yuding','','[]','遊子出咸京，巴山萬里程。白雲連鳥道，青壁遰猿聲。',48,'御定全唐詩/json/474.json','["遊子出咸京，巴山萬里程。白雲連鳥道，青壁遰猿聲。", "雨雪經泥阪，煙花望錦城。工文人共許，應紀蜀中行。"]'),
('yuding-1','送李補闕歸朝','徐凝','唐','御定全唐诗','yuding','','[]','駟馬歸咸秦，雙鳧出海門。還從清切禁，再沐聖明恩。',48,'御定全唐詩/json/474.json','["駟馬歸咸秦，雙鳧出海門。還從清切禁，再沐聖明恩。", "禮樂中朝貴，文章大雅存。江湖多放逸，獻替欲誰論。"]'),
('yuding-2','送日本使還','徐凝','唐','御定全唐诗','yuding','','[]','絕國將無外，扶桑更有東。來朝逢聖日，歸去及秋風。',72,'御定全唐詩/json/474.json','["絕國將無外，扶桑更有東。來朝逢聖日，歸去及秋風。", "夜泛潮回際，晨征蒼莽中。鯨波騰水府，蜃氣壯仙宮。", "天眷何期遠，王文久已同。相望杳不見，離恨托飛鴻。"]'),
('yuding-3','題開元寺牡丹','徐凝','唐','御定全唐诗','yuding','','[]','此花南地知難種，慚愧僧閑用意栽。海燕解憐頻睥睨，',40,'御定全唐詩/json/474.json','["此花南地知難種，慚愧僧閑用意栽。海燕解憐頻睥睨，", "惟有數苞紅萼在，含芳只待舍人來。"]'),
('yuding-4','香爐峰','徐凝','唐','御定全唐诗','yuding','','[]','香爐一峰絕，頂在寺門前。儘是玲瓏石，時生旦暮煙。',24,'御定全唐詩/json/474.json','["香爐一峰絕，頂在寺門前。儘是玲瓏石，時生旦暮煙。"]'),
('yuding-5','白銅鞮','徐凝','唐','御定全唐诗','yuding','','[]','騕褭錦障泥，樓頭日又西。留歡住不住，素齒白銅鞮。',24,'御定全唐詩/json/474.json','["騕褭錦障泥，樓頭日又西。留歡住不住，素齒白銅鞮。"]'),
('yuding-6','楊叛兒','徐凝','唐','御定全唐诗','yuding','','[]','哀怨楊叛兒，駘蕩郎知否。香死博山爐，煙生白門柳。',24,'御定全唐詩/json/474.json','["哀怨楊叛兒，駘蕩郎知否。香死博山爐，煙生白門柳。"]'),
('yuding-7','春寒','徐凝','唐','御定全唐诗','yuding','','[]','亂雪從教舞，回風任聽吹。春寒能作底，已被柳條欺。',24,'御定全唐詩/json/474.json','["亂雪從教舞，回風任聽吹。春寒能作底，已被柳條欺。"]'),
('yuding-8','廬山獨夜','徐凝','唐','御定全唐诗','yuding','','[]','寒空五老雪，斜月九江雲。鐘聲知何處，蒼蒼樹裏聞。',24,'御定全唐詩/json/474.json','["寒空五老雪，斜月九江雲。鐘聲知何處，蒼蒼樹裏聞。"]'),
('yuding-9','天臺獨夜','徐凝','唐','御定全唐诗','yuding','','[]','銀地秋月色，石樑夜溪聲。誰知屐齒盡，為破煙苔行。',24,'御定全唐詩/json/474.json','["銀地秋月色，石樑夜溪聲。誰知屐齒盡，為破煙苔行。"]'),
('yuding-10','送寒岩歸士','徐凝','唐','御定全唐诗','yuding','','[]','不掛絲纊衣，歸向寒岩棲。寒岩風雪夜，又過岩前溪。',24,'御定全唐詩/json/474.json','["不掛絲纊衣，歸向寒岩棲。寒岩風雪夜，又過岩前溪。"]'),
('yuding-11','送陳司馬','徐凝','唐','御定全唐诗','yuding','','[]','家寄茅洞中，身遊越城下。甯知許長史，不憶陳司馬。',24,'御定全唐詩/json/474.json','["家寄茅洞中，身遊越城下。甯知許長史，不憶陳司馬。"]'),
('yuding-12','武夷山仙城','徐凝','唐','御定全唐诗','yuding','','[]','武夷無上路，毛徑不通風。欲共麻姑住，仙城半在空。',24,'御定全唐詩/json/474.json','["武夷無上路，毛徑不通風。欲共麻姑住，仙城半在空。"]'),
('yuding-13','避暑二首','徐凝','唐','御定全唐诗','yuding','','[]','一株金染密，數畝碧鮮疏。避暑臨溪坐，何妨直釣魚。',48,'御定全唐詩/json/474.json','["一株金染密，數畝碧鮮疏。避暑臨溪坐，何妨直釣魚。", "斑多筒簟冷，發少角冠清。避暑長林下，寒蟬又有聲。"]'),
('yuding-14','浙西李尚書奏毀淫昏廟','徐凝','唐','御定全唐诗','yuding','','[]','傳聞廢淫祀，萬里靜山陂。欲慰靈均恨，先燒靳尚祠。',24,'御定全唐詩/json/474.json','["傳聞廢淫祀，萬里靜山陂。欲慰靈均恨，先燒靳尚祠。"]'),
('yuding-15','酬相公再游雲門寺','徐凝','唐','御定全唐诗','yuding','','[]','遠羨五雲路，逶迤千騎回。遺簪唯一去，貴賞不重來。',24,'御定全唐詩/json/474.json','["遠羨五雲路，逶迤千騎回。遺簪唯一去，貴賞不重來。"]'),
('yuding-16','杭州祝濤頭二首','徐凝','唐','御定全唐诗','yuding','','[]','不道沙堤盡，猶欺石棧頑。寄言飛白雪，休去打青山。',48,'御定全唐詩/json/474.json','["不道沙堤盡，猶欺石棧頑。寄言飛白雪，休去打青山。", "倒打錢塘郭，長驅白浪花。吞吳休得也，輸卻五千家。"]'),
('yuding-17','問漁叟','徐凝','唐','御定全唐诗','yuding','','[]','生事同漂梗，機心在野船。如何臨逝水，白髮未忘筌。',24,'御定全唐詩/json/474.json','["生事同漂梗，機心在野船。如何臨逝水，白髮未忘筌。"]'),
('yuding-18','雲封庵','徐凝','唐','御定全唐诗','yuding','','[]','登岩背山河，立石秋風裏。隱見浙江濤，一尺東溝水。',24,'御定全唐詩/json/474.json','["登岩背山河，立石秋風裏。隱見浙江濤，一尺東溝水。"]'),
('yuding-19','漢宮曲','徐凝','唐','御定全唐诗','yuding','','[]','水色簾前流玉霜，趙家飛燕侍昭陽。',32,'御定全唐詩/json/474.json','["水色簾前流玉霜，趙家飛燕侍昭陽。", "掌中舞罷簫聲絕，三十六宮秋夜長。"]'),
('yuding-20','和嵩陽客月夜憶上清人','徐凝','唐','御定全唐诗','yuding','','[]','獨夜嵩陽憶上仙，月明三十六峰前。',32,'御定全唐詩/json/474.json','["獨夜嵩陽憶上仙，月明三十六峰前。", "瑤池月勝嵩陽月，人在玉清眠不眠。"]'),
('yuding-21','八月望夕雨','徐凝','唐','御定全唐诗','yuding','','[]','今年八月十五夜，寒雨蕭蕭不可聞。',32,'御定全唐詩/json/474.json','["今年八月十五夜，寒雨蕭蕭不可聞。", "如練如霜在何處，吳山越水萬重雲。"]'),
('yuding-22','觀浙江濤','徐凝','唐','御定全唐诗','yuding','','[]','浙江悠悠海西綠，驚濤日夜兩翻覆。',32,'御定全唐詩/json/474.json','["浙江悠悠海西綠，驚濤日夜兩翻覆。", "錢塘郭裏看潮人，直至白頭看不足。"]'),
('yuding-23','廬山瀑布','徐凝','唐','御定全唐诗','yuding','','[]','虛空落泉千仞直，雷奔入江不暫息。',32,'御定全唐詩/json/474.json','["虛空落泉千仞直，雷奔入江不暫息。", "今古長如白練飛，一條界破青山色。"]'),
('yuding-24','嘉興寒食','徐凝','唐','御定全唐诗','yuding','','[]','嘉興郭裏逢寒食，落日家家拜掃回。',32,'御定全唐詩/json/474.json','["嘉興郭裏逢寒食，落日家家拜掃回。", "唯有縣前蘇小小，無人送與紙錢來。"]'),
('yuding-25','憶揚州','徐凝','唐','御定全唐诗','yuding','','[]','蕭娘臉下難勝淚，桃葉眉頭易得愁。',32,'御定全唐詩/json/474.json','["蕭娘臉下難勝淚，桃葉眉頭易得愁。", "天下三分明月夜，二分無賴是揚州。"]'),
('yuding-26','八月燈夕寄游越施秀才','徐凝','唐','御定全唐诗','yuding','','[]','四天淨色寒如水，八月清輝冷似霜。',32,'御定全唐詩/json/474.json','["四天淨色寒如水，八月清輝冷似霜。", "想得越人今夜見，孟家珠在鏡中央。"]'),
('yuding-27','八月十五夜','徐凝','唐','御定全唐诗','yuding','','[]','皎皎秋空八月圓，常娥端正桂枝鮮。',32,'御定全唐詩/json/474.json','["皎皎秋空八月圓，常娥端正桂枝鮮。", "一年無似如今夜，十二峰前看不眠。"]'),
('yuding-28','題伍員廟','徐凝','唐','御定全唐诗','yuding','','[]','千載空祠雲海頭，夫差亡國已千秋。',32,'御定全唐詩/json/474.json','["千載空祠雲海頭，夫差亡國已千秋。", "浙波只有靈濤在，拜奠青山人不休。"]'),
('yuding-29','員嶠先生','徐凝','唐','御定全唐诗','yuding','','[]','員嶠先生無白髮，海煙深處采青芝。',32,'御定全唐詩/json/474.json','["員嶠先生無白髮，海煙深處采青芝。", "逢人借問陶唐主，欲進冰蠶五色絲。"]'),
('yuding-30','莫愁曲','徐凝','唐','御定全唐诗','yuding','','[]','玳瑁床頭刺戰袍，碧紗窗外葉騷騷。',32,'御定全唐詩/json/474.json','["玳瑁床頭刺戰袍，碧紗窗外葉騷騷。", "若為教作遼西夢，月冷如丁風似刀。"]'),
('yuding-31','寄白司馬','徐凝','唐','御定全唐诗','yuding','','[]','三條九陌花時節，萬戶千車看牡丹。',32,'御定全唐詩/json/474.json','["三條九陌花時節，萬戶千車看牡丹。", "爭遣江州白司馬，五年風景憶長安。"]'),
('yuding-32','相思林','徐凝','唐','御定全唐诗','yuding','','[]','遊客遠遊新過嶺，每逢芳樹問芳名。',32,'御定全唐詩/json/474.json','["遊客遠遊新過嶺，每逢芳樹問芳名。", "長林遍是相思樹，爭遣愁人獨自行。"]'),
('yuding-33','寄海嶠丈人','徐凝','唐','御定全唐诗','yuding','','[]','萬丈只愁滄海淺，一身誰測歲華遙。',32,'御定全唐詩/json/474.json','["萬丈只愁滄海淺，一身誰測歲華遙。", "自言來此雲邊住，曾看秦王樹石橋。"]'),
('yuding-34','寄潘先生','徐凝','唐','御定全唐诗','yuding','','[]','至人知姓不知名，聞道黃金骨節輕。',32,'御定全唐詩/json/474.json','["至人知姓不知名，聞道黃金骨節輕。", "世上仙方無覓處，欲來西嶽事先生。"]'),
('yuding-35','宮中曲二首','徐凝','唐','御定全唐诗','yuding','','[]','披香侍宴插山花，厭著龍綃著越紗。',64,'御定全唐詩/json/474.json','["披香侍宴插山花，厭著龍綃著越紗。", "恃賴傾城人不及，檀妝唯約數條霞。", "身輕入寵盡恩私，腰細偏能舞柘枝。", "一日新妝拋舊樣，六宮爭畫黑煙眉。"]'),
('yuding-36','七夕','徐凝','唐','御定全唐诗','yuding','','[]','一道鵲橋橫渺渺，千聲玉佩過玲玲。',32,'御定全唐詩/json/474.json','["一道鵲橋橫渺渺，千聲玉佩過玲玲。", "別離還有經年客，悵望不如河鼓星。"]'),
('yuding-37','八月九月望夕雨','徐凝','唐','御定全唐诗','yuding','','[]','八月繁雲連九月，兩回三五晦漫漫。',32,'御定全唐詩/json/474.json','["八月繁雲連九月，兩回三五晦漫漫。", "一年悵望秋將盡，不得常娥正面看。"]'),
('yuding-38','喜雪','徐凝','唐','御定全唐诗','yuding','','[]','長愛謝家能詠雪，今朝見雪亦狂歌。',32,'御定全唐詩/json/474.json','["長愛謝家能詠雪，今朝見雪亦狂歌。", "楊花道即偷人句，不那楊花似雪何。"]'),
('yuding-39','春飲','徐凝','唐','御定全唐诗','yuding','','[]','烏家若下蟻還浮，白玉尊前倒即休。',32,'御定全唐詩/json/474.json','["烏家若下蟻還浮，白玉尊前倒即休。", "不是春來偏愛酒，應須得酒遣春愁。"]'),
('yuding-40','二月望日','徐凝','唐','御定全唐诗','yuding','','[]','長短一年相似夜，中秋未必勝中春。',32,'御定全唐詩/json/474.json','["長短一年相似夜，中秋未必勝中春。", "不寒不暖看明月，況是從來少睡人。"]'),
('yuding-41','讀遠書','徐凝','唐','御定全唐诗','yuding','','[]','兩轉三回讀遠書，畫簷愁見燕歸初。',32,'御定全唐詩/json/474.json','["兩轉三回讀遠書，畫簷愁見燕歸初。", "百花時節教人懶，雲髻朝來不欲梳。"]'),
('yuding-42','古樹','徐凝','唐','御定全唐诗','yuding','','[]','古樹欹斜臨古道，枝不生花腹生草。',32,'御定全唐詩/json/474.json','["古樹欹斜臨古道，枝不生花腹生草。", "行人不見樹少時，樹見行人幾番老。"]'),
('yuding-43','獨住僧','徐凝','唐','御定全唐诗','yuding','','[]','百補袈裟一比丘，數莖長睫覆青眸。',32,'御定全唐詩/json/474.json','["百補袈裟一比丘，數莖長睫覆青眸。", "多應獨住山林慣，唯照寒泉自剃頭。"]'),
('yuding-44','傷畫松道芬上人','徐凝','唐','御定全唐诗','yuding','','[]','百法驅馳百年壽，五勞消瘦五株松。',32,'御定全唐詩/json/474.json','["百法驅馳百年壽，五勞消瘦五株松。", "昨來聞道嚴陵死，畫到青山第幾重。"]'),
('yuding-45','觀釣台畫圖','徐凝','唐','御定全唐诗','yuding','','[]','一水寂寥青靄合，兩崖崔崒白雲殘。',32,'御定全唐詩/json/474.json','["一水寂寥青靄合，兩崖崔崒白雲殘。", "畫人心到啼猿破，欲作三聲出樹難。"]'),
('yuding-46','荊巫夢思','徐凝','唐','御定全唐诗','yuding','','[]','楚水白波風嫋嫋，荊門暮色雨蕭蕭。',32,'御定全唐詩/json/474.json','["楚水白波風嫋嫋，荊門暮色雨蕭蕭。", "相思合眼夢何處，十二峰高巴字遙。"]'),
('yuding-47','浙東故孟尚書種柳','徐凝','唐','御定全唐诗','yuding','','[]','孟家種柳東城去，臨水逶迤思故人。',32,'御定全唐詩/json/474.json','["孟家種柳東城去，臨水逶迤思故人。", "不似當時大司馬，重來得見漢南春。"]'),
('yuding-48','長洲覽古','徐凝','唐','御定全唐诗','yuding','','[]','吳王上國長洲奢，翠黛寒江一道斜。',32,'御定全唐詩/json/474.json','["吳王上國長洲奢，翠黛寒江一道斜。", "傷見摧殘舊宮樹，美人曾插九枝花。"]'),
('yuding-49','卻歸舊山望月有寄','徐凝','唐','御定全唐诗','yuding','','[]','年年明月總相似，大抵人情自不同。',32,'御定全唐詩/json/474.json','["年年明月總相似，大抵人情自不同。", "今夜故山依舊見，班家扇樣碧峰東。"]'),
('yuding-50','再歸松溪舊居宿西林','徐凝','唐','御定全唐诗','yuding','','[]','五粒松深溪水清，眾山搖落月偏明。',32,'御定全唐詩/json/474.json','["五粒松深溪水清，眾山搖落月偏明。", "西林靜夜重來宿，暗記人家犬吠聲。"]'),
('yuding-51','玩花五首','徐凝','唐','御定全唐诗','yuding','','[]','一樹梨花春向暮，雪枝殘處怨風來。',160,'御定全唐詩/json/474.json','["一樹梨花春向暮，雪枝殘處怨風來。", "明朝漸校無多去，看到黃昏不欲回。", "麹塵溪上素紅枝，影在溪流半落時。", "時人自惜花腸斷，春風卻是等閒吹。", "朱霞焰焰山枝動，綠野聲聲杜宇來。", "誰為蜀王身作鳥，自啼還自有花開。", "誰家躑躅青林裏，半見殷花焰焰枝。", "憶得倡樓人送客，深紅衫子影門時。", "花到薔薇明豔絕，燕支顆破麥風秋。", "一番弄色一番退，小婦輕妝大婦愁。"]'),
('yuding-52','長慶春','徐凝','唐','御定全唐诗','yuding','','[]','山頭水色薄籠煙，久客新愁長慶年。',32,'御定全唐詩/json/474.json','["山頭水色薄籠煙，久客新愁長慶年。", "身上五勞仍病酒，夭桃窗下背花眠。"]'),
('yuding-53','山鷓鴣詞','徐凝','唐','御定全唐诗','yuding','','[]','南越嶺頭山鷓鴣，傳是當時守貞女。',32,'御定全唐詩/json/474.json','["南越嶺頭山鷓鴣，傳是當時守貞女。", "化為飛鳥怨何人，猶有啼聲帶蠻語。"]'),
('yuding-54','鄭女出參丈人詞','徐凝','唐','御定全唐诗','yuding','','[]','鳳釵翠翹雙宛轉，出見丈人梳洗晚。',32,'御定全唐詩/json/474.json','["鳳釵翠翹雙宛轉，出見丈人梳洗晚。", "掣曳羅綃跪拜時，柳條無力花枝軟。"]'),
('yuding-55','春雨','徐凝','唐','御定全唐诗','yuding','','[]','花時悶見聯綿雨，雲入人家水毀堤。',32,'御定全唐詩/json/474.json','["花時悶見聯綿雨，雲入人家水毀堤。", "昨日春風源上路，可憐紅錦枉拋泥。"]'),
('yuding-56','和白使君木蘭花','徐凝','唐','御定全唐诗','yuding','','[]','枝枝轉勢雕弓動，片片搖光玉劍斜。',32,'御定全唐詩/json/474.json','["枝枝轉勢雕弓動，片片搖光玉劍斜。", "見說木蘭征戍女，不知那作酒邊花。"]'),
