('yuding-86','見少室','徐凝','唐','御定全唐诗','yuding','','[]','適我一簞孤客性，問人三十六峰名。',32,'御定全唐詩/json/474.json','["適我一簞孤客性，問人三十六峰名。", "青雲無忘白雲在，便可嵩陽老此生。"]'),
('yuding-87','語兒見新月','徐凝','唐','御定全唐诗','yuding','','[]','幾處天邊見新月，經過草市憶西施。',32,'御定全唐詩/json/474.json','["幾處天邊見新月，經過草市憶西施。", "娟娟水宿初三夜，曾伴愁蛾到語兒。"]'),
('yuding-88','回施先輩見寄新詩二首','徐凝','唐','御定全唐诗','yuding','','[]','九幽仙子西山卷，讀了絛繩系又開。',64,'御定全唐詩/json/474.json','["九幽仙子西山卷，讀了絛繩系又開。", "此卷玉清宮裏少，曾尋真誥讀詩來。", "紫河車裏丹成也，皂莢枝頭早晚飛。", "料得仙宮列仙籍，如君進士出身稀。"]'),
('yuding-89','送沈亞之赴郢掾','徐凝','唐','御定全唐诗','yuding','','[]','千萬乘驄沈司戶，不須惆悵郢中游。',32,'御定全唐詩/json/474.json','["千萬乘驄沈司戶，不須惆悵郢中游。", "幾年白雪無人唱，今日唯君上雪樓。"]'),
('yuding-90','答白公','徐凝','唐','御定全唐诗','yuding','','[]','高景爭來草木頭，一生心事酒前休。',32,'御定全唐詩/json/474.json','["高景爭來草木頭，一生心事酒前休。", "山公自是仙人侶，攜手醉登城上樓。"]'),
('yuding-91','句','徐凝','唐','御定全唐诗','yuding','','[]','青山舊路在，白首醉還鄉。',60,'御定全唐詩/json/474.json','["青山舊路在，白首醉還鄉。", "試到第三橋，便入千頃花。", "亂後見淮水，歸心忽迢遙。", "乍疑鯨噴浪，忽似鷁淩風。呀呷汀洲動，喧闐裏巷空。"]'),
('yuding-0','奉和聖制南郊禮畢詩','李德裕','唐','御定全唐诗','yuding','','[]','磬筦歌大呂，冕裘旅天神。燒蕭辟閶闔，祈穀為蒸人。',72,'御定全唐詩/json/475.json','["磬筦歌大呂，冕裘旅天神。燒蕭辟閶闔，祈穀為蒸人。", "羽旗灑輕雪，麥隴含陽春。昌運歲今會，王猷從此新。", "三臣皆就日，萬國望如雲。仁壽信非遠，群生方在鈞。"]'),
('yuding-1','郊壇回輿中書二相公蒙聖慈召至御馬前仰感恩遇輒書是詩兼呈二相公','李德裕','唐','御定全唐诗','yuding','','[]','七萃和鑾動，三條葆吹回。相星環日道，蒼馬近龍媒。',48,'御定全唐詩/json/475.json','["七萃和鑾動，三條葆吹回。相星環日道，蒼馬近龍媒。", "咫尺天顏接，光華喜氣來。自慚衰且病，無以效涓埃。"]'),
('yuding-2','寒食日三殿侍宴，奉進詩一首','李德裕','唐','御定全唐诗','yuding','','[]','宛轉龍歌節，參差燕羽高。風光搖禁柳，霽色暖宮桃。',240,'御定全唐詩/json/475.json','["宛轉龍歌節，參差燕羽高。風光搖禁柳，霽色暖宮桃。", "春露明仙掌，晨霞照禦袍。雪凝陳組練，林植聳幹旄。", "廣樂初蹌鳳，神山欲抃鼇。鳴笳朱鷺起，疊鼓紫騂豪。", "象舞嚴金鎧，豐歌耀寶刀。不勞孫子法，自得太公韜。", "分席羅玄冕，行觴舉綠醪。彀中時落羽，橦末乍升猱。", "瑞景開陰翳，熏風散郁陶。天顏歡益醉，臣節勁尤高。", "楛矢方來貢，雕弓已載櫜。英威揚絕漠，神算盡臨洮。", "赤縣陽和布，蒼生雨露膏。野平惟有麥，田辟久無蒿。", "祿秩榮三事，功勳乏一毫。寢謀慚汲黯，秉羽貴孫敖。", "煥若游玄圃，歡如享太牢。輕生何以報，只自比鴻毛。"]'),
('yuding-3','雨中自祕書省訪王三侍御知早入朝便入集賢侍御任集賢校書及升柏臺又與祕閣相對同院張學士亦余特厚故以詩贈之','李德裕','唐','御定全唐诗','yuding','','[]','共憐獨鶴青霞姿，瀛洲故山歸已遲。仁者焉能效鷙鶚，',72,'御定全唐詩/json/475.json','["共憐獨鶴青霞姿，瀛洲故山歸已遲。仁者焉能效鷙鶚，", "鴻雁沖飆去不盡，寒聲晚下天泉池。顧我蓬萊靜無事，", "金門待詔何逍遙，名儒早問張子僑。王褒軼材晚始入，"]'),
('yuding-4','奉和太原張尚書山亭書懷','李德裕','唐','御定全唐诗','yuding','','[]','岩石在朱戶，風泉當翠樓。始知峴亭賞，難與清暉留。',48,'御定全唐詩/json/475.json','["岩石在朱戶，風泉當翠樓。始知峴亭賞，難與清暉留。", "餘景淡將夕，凝嵐輕欲收。東山有歸志，方接赤松遊。"]'),
('yuding-5','奉和韋侍禦陪相公游開義五言六韻','李德裕','唐','御定全唐诗','yuding','','[]','羊公追勝概，茲地暫逍遙。風景同南峴，丹青見北朝。',72,'御定全唐詩/json/475.json','["羊公追勝概，茲地暫逍遙。風景同南峴，丹青見北朝。", "石渠清夏氣，高樹激鮮飆。念法珍禽集，聞經醉象調。", "偶分甘露味，偏覺眾香饒。為問毗城內，餘熏幾日銷。"]'),
('yuding-6','贈圓明上人','李德裕','唐','御定全唐诗','yuding','','[]','遠公說易長松下，龍樹雙經海藏中。',32,'御定全唐詩/json/475.json','["遠公說易長松下，龍樹雙經海藏中。", "今日導師聞佛慧，始知前路化成空。"]'),
('yuding-7','贈奉律上人','李德裕','唐','御定全唐诗','yuding','','[]','知君學地厭多聞，廣渡群生出世氛。',32,'御定全唐詩/json/475.json','["知君學地厭多聞，廣渡群生出世氛。", "飯色不應殊寶器，樹香皆遣入禪熏。"]'),
('yuding-8','戲贈慎微寺主道安上座三僧正','李德裕','唐','御定全唐诗','yuding','','[]','甘露灑空惟一味，旃檀移植自成熏。',32,'御定全唐詩/json/475.json','["甘露灑空惟一味，旃檀移植自成熏。", "遙知暢獻分南北，應用調柔致六群。"]'),
('yuding-9','長安秋夜','李德裕','唐','御定全唐诗','yuding','','[]','內宮傳詔問戎機，載筆金鑾夜始歸。',32,'御定全唐詩/json/475.json','["內宮傳詔問戎機，載筆金鑾夜始歸。", "萬戶千門皆寂寂，月中清露點朝衣。"]'),
('yuding-10','清冷池懷古','李德裕','唐','御定全唐诗','yuding','','[]','區囿三百里，常聞駟馬來。旌旗朝甬道，簫鼓燕平臺。',96,'御定全唐詩/json/475.json','["區囿三百里，常聞駟馬來。旌旗朝甬道，簫鼓燕平臺。", "追昔賦文雅，從容遊上才。竹園秋水淨，風苑雪煙開。", "牛禍釁將發，羊孫謀始回。袁絲徒伏劍，長孺欲成灰。", "興廢由所感，湮淪斯可哀。空留故池雁，刷羽尚徘徊。"]'),
('yuding-11','述夢詩四十韻','李德裕','唐','御定全唐诗','yuding','','[]','賦命誠非薄，良時幸已遭。君當堯舜日，官接鳳凰曹。',480,'御定全唐詩/json/475.json','["賦命誠非薄，良時幸已遭。君當堯舜日，官接鳳凰曹。", "目睇煙霄闊，心驚羽翼高。椅梧連鶴禁，壀堄接龍韜。", "我後憐詞客，吾僚並雋髦。著書同陸賈，待詔比王褒。", "重價連懸璧，英詞淬寶刀。泉流初落澗，露滴更濡毫。", "赤豹欣來獻，彤弓喜暫櫜。非煙含瑞氣，馴雉潔霜毛。", "靜室便幽獨，虛樓散郁陶。花光晨豔豔，松韻晚騷騷。", "畫壁看飛鶴，仙圖見巨鼇。倚簷陰藥樹，落格蔓蒲桃。", "荷靜蓬池鱠，冰寒郢水醪。荔枝來自遠，盧橘賜仍叨。", "麝氣隨蘭澤，霜華入杏膏。恩光惟覺重，攜挈未為勞。", "夕閱梨園騎，宵聞禁仗獒。扇回交彩翟，雕起颺銀絛。", "轡待袁絲攬，書期蜀客操。盡規常謇謇，退食尚忉忉。", "龜顧垂金鈕，鸞飛曳錦袍。禦溝楊柳弱，天廄驌驦豪。", "屢換青春直，閑隨上苑遨。煙低行殿竹，風拆繞牆桃。", "聚散俄成昔，悲愁益自熬。每懷仙駕遠，更望茂陵號。", "地接三茅嶺，川迎伍子濤。花迷瓜步暗，石固蒜山牢。", "蘭野凝香管，梅洲動翠篙。泉魚驚彩妓，溪鳥避幹旄。", "感舊心猶絕，思歸首更搔。無聊燃蜜炬，誰複勸金舠。", "嵐氣朝生棟，城陰夜入濠。望煙歸海嶠，送雁渡江皋。", "宛馬嘶寒櫪，吳鉤在錦弢。未能追狡兔，空覺長黃蒿。", "水國逾千里，風帆過萬艘。閱川終古恨，惟見暮滔滔。"]'),
('yuding-12','招隱山觀玉蕊樹戲書即事奉寄江西沈大夫閣老','李德裕','唐','御定全唐诗','yuding','','[]','玉蕊天中樹，金閨昔共窺。落英閑舞雪，蜜葉乍低帷。',48,'御定全唐詩/json/475.json','["玉蕊天中樹，金閨昔共窺。落英閑舞雪，蜜葉乍低帷。", "舊賞煙霄遠，前歡歲月移。今來想顏色，還似憶瓊枝。"]'),
('yuding-13','寄題惠林李侍郎舊館','李德裕','唐','御定全唐诗','yuding','','[]','棟宇非吾室，煙山是我鄰。百齡惟待盡，一世樂長貧。',48,'御定全唐詩/json/475.json','["棟宇非吾室，煙山是我鄰。百齡惟待盡，一世樂長貧。", "半壁懸秋日，空林滿夕塵。只應雙鶴吊，松路更無人。"]'),
('yuding-14','寄茅山孫煉師','李德裕','唐','御定全唐诗','yuding','','[]','何地最翛然，華陽第八天。松風清有露，蘿月淨無煙。',112,'御定全唐詩/json/475.json','["何地最翛然，華陽第八天。松風清有露，蘿月淨無煙。", "乍警瑤壇鶴，時嘶玉樹蟬。欲馳千里戀，惟有鳳門泉。", "石上溪蓀發紫茸，碧山幽藹水溶溶。", "菖花定是無人見，春日惟應羽客逢。", "獨尋蘭渚玩遲暉，閑倚松窗望翠微。", "遙想春山明月曙，玉壇清磬步虛歸。"]'),
('yuding-15','題奇石','李德裕','唐','御定全唐诗','yuding','','[]','蘊玉抱清輝，閒庭日瀟灑。塊然天地間，自是孤生者。',24,'御定全唐詩/json/475.json','["蘊玉抱清輝，閒庭日瀟灑。塊然天地間，自是孤生者。"]'),
('yuding-16','送張中丞入台從事','李德裕','唐','御定全唐诗','yuding','','[]','驛騎朝天去，江城眷闕深。夜珠先去握，芳桂乍辭陰。',48,'御定全唐詩/json/475.json','["驛騎朝天去，江城眷闕深。夜珠先去握，芳桂乍辭陰。", "澤國三千里，羈孤萬感心。自嗟文廢久，此曲為盧諶。"]'),
('yuding-17','懷京國','李德裕','唐','御定全唐诗','yuding','','[]','海上東風犯雪來，臘前先折鏡湖梅。',32,'御定全唐詩/json/475.json','["海上東風犯雪來，臘前先折鏡湖梅。", "遙思禁苑青春夜，坐待宮人畫詔回。"]'),
('yuding-18','追和太師顏公同清遠道士游虎丘寺','李德裕','唐','御定全唐诗','yuding','','[]','茂苑有靈峰，嗟余未遊觀。藏山半平陸，壞谷為高岸。',168,'御定全唐詩/json/475.json','["茂苑有靈峰，嗟余未遊觀。藏山半平陸，壞谷為高岸。", "岡繞數仞牆，岩潛千丈幹。乃知造化意，回斡資奇玩。", "鏐騰昔虎踞，劍沒嘗龍煥。潭黛入海底，崟岑聳霄半。", "層巒未升日，哀狖寧知旦。綠筱夏凝陰，碧林秋不換。", "冥搜既窈窕，回望何蕭散。川晴嵐氣收，江春雜英亂。", "逸人綴清藻，前哲留篇翰。共扣哀玉音，皆舒文繡段。", "難追彥回賞，徒起興公歎。一夕如再升，含毫星斗爛。"]'),
('yuding-19','東郡懷古二首：王京兆','李德裕','唐','御定全唐诗','yuding','','[]','河水昔將決，沖波溢川潯。崢嶸金堤下，噴薄風雷音。',120,'御定全唐詩/json/475.json','["河水昔將決，沖波溢川潯。崢嶸金堤下，噴薄風雷音。", "投馬災未弭，為魚歎方深。惟公執珪璧，誓與身俱沉。", "誠信不虛發，神明宜爾臨。湍流自此回，咫尺焉能侵。", "逮我守東郡，淒然懷所欽。雖非識君面，自謂知君心。", "意氣苟相合，神明無古今。登城見遺廟，日夕空悲吟。"]'),
('yuding-20','東郡懷古二首：陽給事','李德裕','唐','御定全唐诗','yuding','','[]','宋氏遠家左，豺狼滿中州。陽君守滑台，終古垂英猷。',120,'御定全唐詩/json/475.json','["宋氏遠家左，豺狼滿中州。陽君守滑台，終古垂英猷。", "數仞城既毀，萬夫心莫留。跳身入飛鏃，免胄臨霜矛。", "畢命在旗下，僵屍橫道周。義風激河汴，壯氣淪山丘。", "嗟爾抱忠烈，古來誰與儔。就烹感漢使，握節悲陽秋。", "顏子綴清藻，鏗然如素璆。徘徊望故壘，尚想精魂遊。"]'),
('yuding-21','秋日登郡樓望贊皇山感而成詠','李德裕','唐','御定全唐诗','yuding','','[]','昔人懷井邑，為有掛冠期。顧我飄蓬者，長隨泛梗移。',48,'御定全唐詩/json/475.json','["昔人懷井邑，為有掛冠期。顧我飄蓬者，長隨泛梗移。", "越吟因病感，潘鬢入秋悲。北指邯鄲道，應無歸去期。"]'),
('yuding-22','雨後淨望河西連山愴然成詠','李德裕','唐','御定全唐诗','yuding','','[]','宿雨初收晚吹繁，秋光極目自銷魂。煙山北下歸遼海，',40,'御定全唐詩/json/475.json','["宿雨初收晚吹繁，秋光極目自銷魂。煙山北下歸遼海，", "唯懷藥餌蠲衰病，為惜餘年報主恩。"]'),
('yuding-23','秋日美晴，郡樓閑眺，寄荊南張書記','李德裕','唐','御定全唐诗','yuding','','[]','高檻涼風起，清川旭景開。秋聲向野去，爽氣自山來。',48,'御定全唐詩/json/475.json','["高檻涼風起，清川旭景開。秋聲向野去，爽氣自山來。", "霄外鴻初返，簷間燕已歸。不因煙雨夕，何處夢陽臺。"]'),
('yuding-24','故人寄茶','李德裕','唐','御定全唐诗','yuding','','[]','劍外九華英，緘題下玉京。開時微月上，碾處亂泉聲。',72,'御定全唐詩/json/475.json','["劍外九華英，緘題下玉京。開時微月上，碾處亂泉聲。", "半夜邀僧至，孤吟對竹烹。碧流霞腳碎，香泛乳花輕。", "六腑睡神去，數朝詩思清。其餘不敢費，留伴讀書行。"]'),
('yuding-25','奉送相公十八丈鎮揚州','李德裕','唐','御定全唐诗','yuding','','[]','千騎風生大旆舒，春江重到武侯廬。共懸龜印銜新綬，',40,'御定全唐詩/json/475.json','["千騎風生大旆舒，春江重到武侯廬。共懸龜印銜新綬，", "今來卻笑臨邛客，入蜀空馳使者車。"]'),
('yuding-26','題劍門','李德裕','唐','御定全唐诗','yuding','','[]','奇峰百仞懸，清眺出嵐煙。迥若戈回日，高疑劍倚天。',48,'御定全唐詩/json/475.json','["奇峰百仞懸，清眺出嵐煙。迥若戈回日，高疑劍倚天。", "參差霞壁聳，合遝翠屏連。想是三刀夢，森然在目前。"]'),
('yuding-27','漢州月夕游房太尉西湖','李德裕','唐','御定全唐诗','yuding','','[]','丞相鳴琴地，何年閉玉徽。偶因明月夕，重敞故樓扉。',48,'御定全唐詩/json/475.json','["丞相鳴琴地，何年閉玉徽。偶因明月夕，重敞故樓扉。", "桃柳溪空在，芙蓉客暫依。誰憐濟川楫，長與夜舟歸。"]'),
('yuding-28','重題','李德裕','唐','御定全唐诗','yuding','','[]','晚日臨寒渚，微風發棹謳。鳳池波自闊，魚水運難留。',48,'御定全唐詩/json/475.json','["晚日臨寒渚，微風發棹謳。鳳池波自闊，魚水運難留。", "亭古思宏棟，川長憶夜舟。想公高世志，只似冶城遊。"]'),
('yuding-29','房公舊竹亭聞琴緬慕風流神期如在因重題此作','李德裕','唐','御定全唐诗','yuding','','[]','流水音長在，青霞意不傳。獨悲形解後，誰聽廣陵弦。',24,'御定全唐詩/json/475.json','["流水音長在，青霞意不傳。獨悲形解後，誰聽廣陵弦。"]'),
('yuding-30','憶金門舊遊奉寄江西沈大夫','李德裕','唐','御定全唐诗','yuding','','[]','東望滄溟路幾重，無因白首更相逢。已悲泉下雙琪樹，',40,'御定全唐詩/json/475.json','["東望滄溟路幾重，無因白首更相逢。已悲泉下雙琪樹，", "思君遠寄西山藥，歲暮相期向赤松。"]'),
('yuding-31','早入中書行公主冊禮事畢，登集賢閣成詠','李德裕','唐','御定全唐诗','yuding','','[]','明星入東陌，燦燦光層宙。皎月映高梧，輕風發涼候。',96,'御定全唐詩/json/475.json','["明星入東陌，燦燦光層宙。皎月映高梧，輕風發涼候。", "金門列葆吹，鐘室傳清漏。簡冊自中來，貂黃忝宣授。", "更登天祿閣，極眺終南岫。遙羨商山翁，閑歌紫芝秀。", "晨興念始辱，夕惕思致寇。傾奪非我心，淒然感田竇。"]'),
('yuding-32','題羅浮石','李德裕','唐','御定全唐诗','yuding','','[]','清景持芳菊，涼天倚茂松。名山何必去，此地有群峰。',24,'御定全唐詩/json/475.json','["清景持芳菊，涼天倚茂松。名山何必去，此地有群峰。"]'),
('yuding-33','重過列子廟，追感頃年自淮服與居守王，僕射同題名於廓壁僕射已為御史，余尚布衣，自後俱列紫垣，繼遊內署，兩為夏官之代，復聯左揆之榮，荷寵多同，感涕何極，因書四韻奉寄','李德裕','唐','御定全唐诗','yuding','','[]','白首過遺廟，朱輪入故城。已慚聯左揆，猶喜抗前旌。',48,'御定全唐詩/json/475.json','["白首過遺廟，朱輪入故城。已慚聯左揆，猶喜抗前旌。", "曳履忘年舊，彈冠久要情。重看題壁處，豈羨棄繻生。"]'),
('yuding-34','遙傷茅山縣孫尊師三首','李德裕','唐','御定全唐诗','yuding','','[]','蟬蛻遺虛白，蜺飛入上清。同人悲劍解，舊友覺衣輕。',144,'御定全唐詩/json/475.json','["蟬蛻遺虛白，蜺飛入上清。同人悲劍解，舊友覺衣輕。", "黃鵠遙將舉，斑麟儼未行。惟應鮑靚室，中夜識琴聲。", "金格期初至，飆輪去不停。山摧武擔石，天隕少微星。", "弟子悲徐甲，門人泣蔡經。空聞留玉舄，猶在阜鄉亭。", "空宇留丹灶，層霞被羽衣。舊山聞鹿化，遺舄尚鳧飛。", "數日奇香在，何年白鶴歸。想君旋下淚，方款裏閭扉。"]'),
('yuding-35','尊師是桃源黃先生傳法弟子常見尊師稱先靈跡今重賦此詩兼寄題黃先生舊館','李德裕','唐','御定全唐诗','yuding','','[]','後學方成市，吾師又上賓。洞天應不夜，源樹只如春。',48,'御定全唐詩/json/475.json','["後學方成市，吾師又上賓。洞天應不夜，源樹只如春。", "棋客留童子，山精避直神。無因握石髓，及與養生人。"]'),
('yuding-36','僕射相公偶話於故集賢張學士廳寫得德裕與僕射舊唱和詩，其時和者五人，惟僕射與德裕皆列高位，淒然懷舊，輒獻此詩','李德裕','唐','御定全唐诗','yuding','','[]','賦感鄰人笛，詩留夫子牆。延年如有作，應不用山王。',24,'御定全唐詩/json/475.json','["賦感鄰人笛，詩留夫子牆。延年如有作，應不用山王。"]'),
('yuding-37','惠泉','李德裕','唐','御定全唐诗','yuding','','[]','茲泉由太潔，終不畜纖鱗。到底清何益，含虛勢自貧。',48,'御定全唐詩/json/475.json','["茲泉由太潔，終不畜纖鱗。到底清何益，含虛勢自貧。", "明璣難秘彩，美玉詎潛珍。未及黃陂量，滔滔豈有津。"]'),
('yuding-38','無題','李德裕','唐','御定全唐诗','yuding','','[]','松倚蒼崖老，蘭臨碧洞衰。不勞鄰舍笛，吹起舊時悲。',24,'御定全唐詩/json/475.json','["松倚蒼崖老，蘭臨碧洞衰。不勞鄰舍笛，吹起舊時悲。"]'),
('yuding-39','題冠蓋裏','李德裕','唐','御定全唐诗','yuding','','[]','偶來冠蓋裏，愧是舊三公。自喜無兵術，輕裘上閟宮。',24,'御定全唐詩/json/475.json','["偶來冠蓋裏，愧是舊三公。自喜無兵術，輕裘上閟宮。"]'),
('yuding-40','離平泉馬上作','李德裕','唐','御定全唐诗','yuding','','[]','十年紫殿掌洪鈞，出入三朝一品身。文帝寵深陪雉尾，',40,'御定全唐詩/json/475.json','["十年紫殿掌洪鈞，出入三朝一品身。文帝寵深陪雉尾，", "自是功高臨盡處，禍來名滅不由人。"]'),
('yuding-41','謫嶺南道中作','李德裕','唐','御定全唐诗','yuding','','[]','嶺水爭分路轉迷，桄榔椰葉暗蠻溪。愁沖毒霧逢蛇草，',40,'御定全唐詩/json/475.json','["嶺水爭分路轉迷，桄榔椰葉暗蠻溪。愁沖毒霧逢蛇草，", "不堪腸斷思鄉處，紅槿花中越鳥啼。"]'),
('yuding-42','到惡溪夜泊蘆島','李德裕','唐','御定全唐诗','yuding','','[]','甘露花香不再持，遠公應怪負前期。青蠅豈獨悲虞氏，',40,'御定全唐詩/json/475.json','["甘露花香不再持，遠公應怪負前期。青蠅豈獨悲虞氏，", "嶺頭無限相思淚，泣向寒梅近北枝。"]'),
('yuding-43','登崖州城作','李德裕','唐','御定全唐诗','yuding','','[]','獨上高樓望帝京，鳥飛猶是半年程。',32,'御定全唐詩/json/475.json','["獨上高樓望帝京，鳥飛猶是半年程。", "青山似欲留人住，百匝千遭繞郡城。"]'),
('yuding-44','鴛鴦篇','李德裕','唐','御定全唐诗','yuding','','[]','君不見昔時同心人，化作鴛鴦鳥。和鳴一夕不暫離，',139,'御定全唐詩/json/475.json','["君不見昔時同心人，化作鴛鴦鳥。和鳴一夕不暫離，", "南有瀟湘洲，且為千里遊。洞庭無苦寒，沅江多碧流。", "昔為薄命妾，無日不含愁。今為水中鳥，頡頏自相求。", "洛陽女兒在青閣，二月羅衣輕更薄。金泥文彩未足珍，", "夜夜學織連枝錦，織作鴛鴦人共憐。悠悠湘水濱，", "唯憐獨鶴依琴曲，更念孤鸞隱鏡塵。願作鴛鴦被，"]'),
('yuding-45','南梁行','李德裕','唐','御定全唐诗','yuding','','[]','江南鬱鬱春草長，悠悠漢水浮清光。雜英飛盡空和景，',144,'御定全唐詩/json/475.json','["江南鬱鬱春草長，悠悠漢水浮清光。雜英飛盡空和景，", "青天詔下寵光至，頒籍金閨征石渠。重歸山路煙嵐隔，", "杜鵑啼咽花亦殷，聲悲絕豔連空山。斜陽瞥映淺深樹，", "喬木幽谷上下同，雄雌不異飛棲處。望秦峰迥過商顏，", "元和列侍明光殿，諫草初焚市朝變。北闕趨臣半隙塵，", "故園歲深開斷簡，秋堂月曉掩遺袿。嗚嗚曉角霞輝粲，"]'),
('yuding-46','近於伊川卜山居將命者畫圖而至欣然有感聊賦此詩兼寄上浙東元相公大夫使求青田胎化鶴','李德裕','唐','御定全唐诗','yuding','','[]','弱歲弄詞翰，遂叨明主恩。懷章過越邸，建旆守吳門。',144,'御定全唐詩/json/475.json','["弱歲弄詞翰，遂叨明主恩。懷章過越邸，建旆守吳門。", "西圯陰難駐，東皋意尚存。慚逾六百石，愧負五千言。", "寄世知嬰繳，辭榮類觸藩。欲追綿上隱，況近子平村。", "邑有桐鄉愛，山餘黍穀暄。既非逃相地，乃是故侯園。", "野竹多微徑，嚴泉豈一源。映池方樹密，傍澗古藤繁。", "邛杖堪扶老，黃牛已服轅。只應將唳鶴，幽谷共翩翻。"]'),
('yuding-47','憶平泉山居，贈沈吏部一首','李德裕','唐','御定全唐诗','yuding','','[]','昔聞羊叔子，茅屋在東渠。豈不念歸路，徘徊畏簡書。',144,'御定全唐詩/json/475.json','["昔聞羊叔子，茅屋在東渠。豈不念歸路，徘徊畏簡書。", "乃知軒冕客，自與田園疏。歿世有遺恨，精誠何所如。", "嗟予寡時用，夙志在林閭。雖抱山水癖，敢希仁智居。", "清泉繞捨下，修竹蔭庭除。幽徑松蓋密，小池蓮葉初。", "從來有好鳥，近複躍鰷魚。少室映川陸，鳴皋對蓬廬。", "張何舊寮寀，相勉在懸輿。常恐似伯玉，瞻前慚魏舒。"]'),
('yuding-48','夏晚有懷平泉林居','李德裕','唐','御定全唐诗','yuding','','[]','孟夏守畏途，舍舟在徂暑。愀然何所念，念我龍門塢。',144,'御定全唐詩/json/475.json','["孟夏守畏途，舍舟在徂暑。愀然何所念，念我龍門塢。", "密竹無蹊徑，高松有四五。飛泉鳴樹間，颯颯如度雨。", "菌桂秀層嶺，芳蓀媚幽渚。稚子候我歸，衡門獨延佇。", "誰言聖與哲，曾是不懷土。公旦既思周，宣尼亦念魯。", "矧餘竄炎裔，日夕誰晤語。眷闕悲子牟，班荊感椒舉。", "淒淒視環玦，惻惻步庭廡。豈待莊舄吟，方知倦羈旅。"]'),
('yuding-49','早秋龍興寺江亭閑眺憶龍門山居寄崔張舊從事','李德裕','唐','御定全唐诗','yuding','','[]','江亭感秋至，蘭徑悲露泫。粳稻秀晚川，杉松鬱晴巘。',120,'御定全唐詩/json/475.json','["江亭感秋至，蘭徑悲露泫。粳稻秀晚川，杉松鬱晴巘。", "嗟予有林壑，茲夕念原衍。綠筱連嶺多，青莎近溪淺。", "淵明菊猶在，仲蔚蒿莫翦。喬木粲淩苕，陰崖積幽蘚。", "遙思伊川水，北渡龍門峴。蒼翠雙闕間，逶迤清灘轉。", "故人在鄉國，歲晏路悠緬。惆悵此生涯，無由共登踐。"]'),
('yuding-50','比聞龍門敬善寺有紅桂樹獨秀伊川，嘗於江南諸山訪之莫致，陳侍御知予所好，因訪剡溪樵客，偶得數株，移植郊園，眾芳色沮，乃知敬善所有是蜀道菵草，徒得嘉名，因賦是詩，兼贈陳侍御','李德裕','唐','御定全唐诗','yuding','','[]','昔聞紅桂枝，獨秀龍門側。越叟遺數株，周人未嘗識。',120,'御定全唐詩/json/475.json','["昔聞紅桂枝，獨秀龍門側。越叟遺數株，周人未嘗識。", "平生愛此樹，攀玩無由得。君子知我心，因之為羽翼。", "豈煩嘉客譽，且就清陰息。來自天姥岑，長疑翠嵐色。", "芬芳世所絕，偃蹇枝漸直。瓊葉潤不凋，珠英粲如織。", "猶疑翡翠宿，想待鵷雛食。寧止暫淹留，終當更封植。"]'),
('yuding-51','懷山居邀松陽子同作','李德裕','唐','御定全唐诗','yuding','','[]','我有愛山心，如饑複如渴。出谷一年餘，常疑十年別。',192,'御定全唐詩/json/475.json','["我有愛山心，如饑複如渴。出谷一年餘，常疑十年別。", "春思岩花爛，夏憶寒泉冽。秋憶泛蘭卮，冬思玩松雪。", "晨思小山桂，暝憶深潭月。醉憶剖紅梨，飯思食紫蕨。", "坐思藤蘿密，步憶莓苔滑。晝夜百刻中，愁腸幾回絕。", "每念羊叔子，言之豈常輟。人生不如意，十乃居七八。", "我未及懸輿，今猶佩朝紱。焉能逐糜鹿，便得游林樾。", "範恣滄波舟，張懷赤松列。惟應詎身恤，豈敢忘臣節。", "器滿自當欹，物盈終有缺。從茲返樵徑，庶可希前哲。"]'),
('yuding-52','思歸赤松村呈松陽子','李德裕','唐','御定全唐诗','yuding','','[]','昔人思避世，惟恐不深幽。禽慶潛名嶽，鴟夷漾釣舟。',48,'御定全唐詩/json/475.json','["昔人思避世，惟恐不深幽。禽慶潛名嶽，鴟夷漾釣舟。", "顧餘知止足，所樂在歸休。不似尋山者，忘家恣遠遊。"]'),
('yuding-53','近臘對雪有懷林居','李德裕','唐','御定全唐诗','yuding','','[]','蓬門常晝掩，竹徑寂無人。鳥起飄松霰，麇行動穀榛。',48,'御定全唐詩/json/475.json','["蓬門常晝掩，竹徑寂無人。鳥起飄松霰，麇行動穀榛。", "應知禽魚侶，合與薜蘿親。遙憶平皋望，溪煙已發春。"]'),
('yuding-54','思山居一十首：清明後憶山中','李德裕','唐','御定全唐诗','yuding','','[]','遙思寒食後，野老林下醉。月照一山明，風吹百花氣。',48,'御定全唐詩/json/475.json','["遙思寒食後，野老林下醉。月照一山明，風吹百花氣。", "飛泉與萬籟，仿佛疑簫吹。不待曙華分，已應喧鳥至。"]'),
('yuding-55','思山居一十首：題寄商山石','李德裕','唐','御定全唐诗','yuding','','[]','綺皓岩中石，嘗經伴隱淪。紫芝呈幾曲，紅蘚閟千春。',48,'御定全唐詩/json/475.json','["綺皓岩中石，嘗經伴隱淪。紫芝呈幾曲，紅蘚閟千春。", "聊用支琴尾，寧惟倚病身。自知來處所，何暇問嚴遵。"]'),
('yuding-56','思山居一十首：憶種苽時','李德裕','唐','御定全唐诗','yuding','','[]','尚平方畢娶，疏廣念歸期。澗底松成蓋，簷前桂長枝。',48,'御定全唐詩/json/475.json','["尚平方畢娶，疏廣念歸期。澗底松成蓋，簷前桂長枝。", "徑閑芳草合，山靜落花遲。雖有苽園在，無因及種時。"]'),
('yuding-57','思山居一十首：春日獨坐思歸','李德裕','唐','御定全唐诗','yuding','','[]','壯齡心已盡，孤賞意猶存。豈望圖麟閣，惟思臥鹿門。',48,'御定全唐詩/json/475.json','["壯齡心已盡，孤賞意猶存。豈望圖麟閣，惟思臥鹿門。", "無謀堪適野，何力可拘原。只有容身去，幽山自灌園。"]'),
('yuding-58','思山居一十首：思登家山林嶺','李德裕','唐','御定全唐诗','yuding','','[]','自知無世用，只是愛山遊。舊有嵇康懶，今慚趙武偷。',48,'御定全唐詩/json/475.json','["自知無世用，只是愛山遊。舊有嵇康懶，今慚趙武偷。", "登巒未覺疾，泛水便忘憂。最惜殘筋力，捫蘿遍一丘。"]'),
('yuding-59','思山居一十首：思鄉園老人','李德裕','唐','御定全唐诗','yuding','','[]','常羨蓽門翁，所思惟歲稔。遙知松月曙，尚在山窗寢。',48,'御定全唐詩/json/475.json','["常羨蓽門翁，所思惟歲稔。遙知松月曙，尚在山窗寢。", "蘭氣入幽簾，禽言傍孤枕。晨興步岩徑，更酌寒泉飲。"]'),
('yuding-60','思山居一十首：寄龍門僧','李德裕','唐','御定全唐诗','yuding','','[]','龍門有開士，愛我春潭碧。清景出東山，閑來玩松石。',48,'御定全唐詩/json/475.json','["龍門有開士，愛我春潭碧。清景出東山，閑來玩松石。", "應憐林壑主，遠作滄溟客。為我謝此僧，終當理歸策。"]'),
('yuding-61','思山居一十首：憶藥苗','李德裕','唐','御定全唐诗','yuding','','[]','溪上藥苗齊，豐茸正堪掇。皆能扶我壽，豈止堅肌骨。',48,'御定全唐詩/json/475.json','["溪上藥苗齊，豐茸正堪掇。皆能扶我壽，豈止堅肌骨。", "味掩商山芝，英逾首陽蕨。豈如甘穀士，只得香泉啜。"]'),
('yuding-62','思山居一十首：憶村中老人春酒','李德裕','唐','御定全唐诗','yuding','','[]','二叟茅茨下，清晨飲濁醪。雨殘紅芍藥，風落紫櫻桃。',48,'御定全唐詩/json/475.json','["二叟茅茨下，清晨飲濁醪。雨殘紅芍藥，風落紫櫻桃。", "巢燕銜泥疾，簷蟲掛網高。閑思春穀事，轉覺宦途勞。"]'),
('yuding-63','思山居一十首：憶葛勝木禪床','李德裕','唐','御定全唐诗','yuding','','[]','憶我齋中榻，寒宵幾獨眠。管甯穿亦坐，徐孺去常懸。',48,'御定全唐詩/json/475.json','["憶我齋中榻，寒宵幾獨眠。管甯穿亦坐，徐孺去常懸。", "蟲網垂應遍，苔痕染更鮮。何人及身在，歸對老僧禪。"]'),
('yuding-64','思山居一十首：初夏有懷山居','李德裕','唐','御定全唐诗','yuding','','[]','山中有所憶，夏景始清幽。野竹陰無日，岩泉冷似秋。',48,'御定全唐詩/json/475.json','["山中有所憶，夏景始清幽。野竹陰無日，岩泉冷似秋。", "翠岑當累榭，皓月入輕舟。只有思歸夕，空簾且夢遊。"]'),
('yuding-65','張公超谷中石','李德裕','唐','御定全唐诗','yuding','','[]','鼓篋依綠槐，橫經起秋霧。有時連岳客，尚辦弦歌處。',48,'御定全唐詩/json/475.json','["鼓篋依綠槐，橫經起秋霧。有時連岳客，尚辦弦歌處。", "自予去幽谷，誰人襲芳杜。空留古苔石，對我岩中樹。"]'),
('yuding-66','初歸平泉，過龍門南嶺，遙望山居即事','李德裕','唐','御定全唐诗','yuding','','[]','初歸故鄉陌，極望且徐輪。近野樵蒸至，平泉煙火新。',48,'御定全唐詩/json/475.json','["初歸故鄉陌，極望且徐輪。近野樵蒸至，平泉煙火新。", "農夫饋雞黍，漁子薦霜鱗。惆悵懷楊僕，慚為關外人。"]'),
('yuding-67','伊川晚眺','李德裕','唐','御定全唐诗','yuding','','[]','桑葉初黃梨葉紅，伊川落日盡無風。',32,'御定全唐詩/json/475.json','["桑葉初黃梨葉紅，伊川落日盡無風。", "漢儲何假終南客，甪裏先生在谷中。"]'),
('yuding-68','潭上喜見新月','李德裕','唐','御定全唐诗','yuding','','[]','簪組十年夢，園廬今夕情。誰憐故鄉月，複映碧潭生。',48,'御定全唐詩/json/475.json','["簪組十年夢，園廬今夕情。誰憐故鄉月，複映碧潭生。", "皓彩松上見，寒光波際輕。還將孤賞意，暫寄玉琴聲。"]'),
('yuding-69','郊外即事寄侍郎大尹','李德裕','唐','御定全唐诗','yuding','','[]','高秋慚非隱，閑林喜退居。老農爭席坐，稚子帶經鋤。',48,'御定全唐詩/json/475.json','["高秋慚非隱，閑林喜退居。老農爭席坐，稚子帶經鋤。", "竹徑難回騎，仙舟但跂予。豈知陶靖節，只自愛吾廬。"]'),
('yuding-70','山居遇雪喜道者相訪','李德裕','唐','御定全唐诗','yuding','','[]','幽居近谷西，喬木與山齊。野竹連池合，岩松映雪低。',48,'御定全唐詩/json/475.json','["幽居近谷西，喬木與山齊。野竹連池合，岩松映雪低。", "喜君來白社，值我在青溪。應笑於陵子，遺榮自灌畦。"]'),
('yuding-71','雪霽晨起','李德裕','唐','御定全唐诗','yuding','','[]','雪覆寒溪竹，風卷野田蓬。四望無行跡，誰憐孤老翁。',24,'御定全唐詩/json/475.json','["雪覆寒溪竹，風卷野田蓬。四望無行跡，誰憐孤老翁。"]'),
('yuding-72','洛中士君子多以平泉見呼愧獲方外之名因以此詩為報奉寄劉賓客','李德裕','唐','御定全唐诗','yuding','','[]','非高柳下逸，自愛竹林閑。才異居東裏，愚因在北山。',48,'御定全唐詩/json/475.json','["非高柳下逸，自愛竹林閑。才異居東裏，愚因在北山。", "徑荒寒未掃，門設晝長關。不及鴟夷子，悠悠煙水間。"]'),
('yuding-73','早春至言禪公法堂憶平泉別業','李德裕','唐','御定全唐诗','yuding','','[]','昔我伊原上，孤遊竹樹間。人依紅桂靜，鳥傍碧潭閑。',48,'御定全唐詩/json/475.json','["昔我伊原上，孤遊竹樹間。人依紅桂靜，鳥傍碧潭閑。", "松蓋低春雪，藤輪倚暮山。永懷桑梓邑，衰老若為還。"]'),
('yuding-74','峽山亭月夜獨宿對櫻桃花有懷伊川別墅金陵作','李德裕','唐','御定全唐诗','yuding','','[]','皎月照芳樹，鮮葩含素輝。愁人惜春夜，達曙想岩扉。',48,'御定全唐詩/json/475.json','["皎月照芳樹，鮮葩含素輝。愁人惜春夜，達曙想岩扉。", "風靜陰滿砌，露濃香入衣。恨無金穀妓，為我奏思歸。"]'),
('yuding-75','春暮思平泉雜詠二十首：望伊川','李德裕','唐','御定全唐诗','yuding','','[]','遠村寒食後，細雨度川來。芳草連溪合，梨花映墅開。',48,'御定全唐詩/json/475.json','["遠村寒食後，細雨度川來。芳草連溪合，梨花映墅開。", "槿籬懸落照，松徑長新苔。向夕亭皋望，游禽幾處回。"]'),
('yuding-76','春暮思平泉雜詠二十首：潭上紫藤','李德裕','唐','御定全唐诗','yuding','','[]','故鄉春欲盡，一歲芳難再。岩樹已青蔥，吾廬日堪愛。',48,'御定全唐詩/json/475.json','["故鄉春欲盡，一歲芳難再。岩樹已青蔥，吾廬日堪愛。", "幽溪人未去，芳草行應礙。遙憶紫藤垂，繁英照潭黛。"]'),
('yuding-77','春暮思平泉雜詠二十首：書樓晴望','李德裕','唐','御定全唐诗','yuding','','[]','幽居人世外，久厭市朝喧。蒼翠連雙闕，微茫認九原。',48,'御定全唐詩/json/475.json','["幽居人世外，久厭市朝喧。蒼翠連雙闕，微茫認九原。", "殘紅映鞏樹，斜日照轘轅。薄暮柴扉掩，誰知仲蔚園。"]'),
('yuding-78','春暮思平泉雜詠二十首：西嶺望鳴皋山','李德裕','唐','御定全唐诗','yuding','','[]','高秋對涼野，四望何蕭瑟。遠見鳴皋山，青峰原上出。',48,'御定全唐詩/json/475.json','["高秋對涼野，四望何蕭瑟。遠見鳴皋山，青峰原上出。", "晨興采薇蕨，向暮歸蓬蓽。詎假數揮金，餐和養餘日。"]'),
('yuding-79','春暮思平泉雜詠二十首：瀑泉亭','李德裕','唐','御定全唐诗','yuding','','[]','向老多悲恨，淒然念一丘。岩泉終古在，風月幾年遊。',48,'御定全唐詩/json/475.json','["向老多悲恨，淒然念一丘。岩泉終古在，風月幾年遊。", "菌閣饒佳樹，菱潭有釣舟。不如羊叔子，名與峴山留。"]'),
('yuding-80','春暮思平泉雜詠二十首：紅桂樹','李德裕','唐','御定全唐诗','yuding','','[]','欲求塵外物，此樹是瑤林。後素合餘絢，如丹見本心。',48,'御定全唐詩/json/475.json','["欲求塵外物，此樹是瑤林。後素合餘絢，如丹見本心。", "妍姿無點辱，芳意托幽深。願以鮮葩色，淩霜照碧潯。"]'),
('yuding-81','春暮思平泉雜詠二十首：金松','李德裕','唐','御定全唐诗','yuding','','[]','台嶺生奇樹，佳名世未知。纖纖疑大菊，落落是松枝。',48,'御定全唐詩/json/475.json','["台嶺生奇樹，佳名世未知。纖纖疑大菊，落落是松枝。", "照日含金晰，籠煙淡翠滋。勿言人去晚，猶有歲寒期。"]'),
('yuding-82','春暮思平泉雜詠二十首：月桂','李德裕','唐','御定全唐诗','yuding','','[]','何年霜夜月，桂子落寒山。翠幹生岩下，金英在世間。',48,'御定全唐詩/json/475.json','["何年霜夜月，桂子落寒山。翠幹生岩下，金英在世間。", "幽崖空自老，清漢未知還。惟有涼秋夜，嫦娥來暫攀。"]'),
('yuding-83','春暮思平泉雜詠二十首：山桂','李德裕','唐','御定全唐诗','yuding','','[]','吾愛山中樹，繁英滿目鮮。臨風飄碎錦，映日亂非煙。',48,'御定全唐詩/json/475.json','["吾愛山中樹，繁英滿目鮮。臨風飄碎錦，映日亂非煙。", "影入春潭底，香凝月榭前。豈知幽獨客，賴此當朱弦。"]'),
('yuding-84','春暮思平泉雜詠二十首：柏','李德裕','唐','御定全唐诗','yuding','','[]','聞有三株樹，惟應秘閬風。珊瑚不生葉，朱草又無叢。',48,'御定全唐詩/json/475.json','["聞有三株樹，惟應秘閬風。珊瑚不生葉，朱草又無叢。", "未若淩雲柏，常能終歲紅。晨霞與落日，相照在岩中。"]'),
('yuding-85','春暮思平泉雜詠二十首：芳蓀','李德裕','唐','御定全唐诗','yuding','','[]','楚客重蘭蓀，遺芳今未歇。葉抽清淺水，花照暄妍節。',48,'御定全唐詩/json/475.json','["楚客重蘭蓀，遺芳今未歇。葉抽清淺水，花照暄妍節。", "紫豔映渠鮮，輕香含露潔。離居若有贈，暫與幽人折。"]'),
('yuding-86','春暮思平泉雜詠二十首：流杯亭','李德裕','唐','御定全唐诗','yuding','','[]','激水自山椒，析波分淺瀨。回環疑古篆，詰曲如縈帶。',48,'御定全唐詩/json/475.json','["激水自山椒，析波分淺瀨。回環疑古篆，詰曲如縈帶。", "甯愬羽觴遲，惟歡親友會。欲知中聖處，皓月臨松蓋。"]'),
('yuding-87','春暮思平泉雜詠二十首：東溪','李德裕','唐','御定全唐诗','yuding','','[]','近蓄東溪水，悠悠起淥波。彩鴛留不去，芳草日應多。',48,'御定全唐詩/json/475.json','["近蓄東溪水，悠悠起淥波。彩鴛留不去，芳草日應多。", "夾岸生奇筱，緣岩覆女蘿。蘭橈思無限，為感濯纓歌。"]'),
('yuding-88','春暮思平泉雜詠二十首：鸂鶒','李德裕','唐','御定全唐诗','yuding','','[]','清沚雙鸂鶒，前年海上雛。今來戀洲嶼，思若在江湖。',48,'御定全唐詩/json/475.json','["清沚雙鸂鶒，前年海上雛。今來戀洲嶼，思若在江湖。", "欲起搖荷蓋，閑飛濺水珠。不能常泛泛，惟作逐波鳧。"]'),
('yuding-89','春暮思平泉雜詠二十首：西園','李德裕','唐','御定全唐诗','yuding','','[]','西園最多趣，永日自忘歸。石瀨流清淺，風岑澹翠微。',48,'御定全唐詩/json/475.json','["西園最多趣，永日自忘歸。石瀨流清淺，風岑澹翠微。", "曉翻紅藥豔，晴嫋碧潭輝。獨望娟娟月，宵分半掩扉。"]'),
('yuding-90','春暮思平泉雜詠二十首：海石楠','李德裕','唐','御定全唐诗','yuding','','[]','昔見曆陽山，雞籠已孤秀。今看海嶠樹，翠蓋何幽茂。',48,'御定全唐詩/json/475.json','["昔見曆陽山，雞籠已孤秀。今看海嶠樹，翠蓋何幽茂。", "霰雪詎能侵，煙嵐自相揉。攀條獨臨憩，況值清陰晝。"]'),
('yuding-91','春暮思平泉雜詠二十首：雙碧潭','李德裕','唐','御定全唐诗','yuding','','[]','清剡與嚴湍，潺湲皆可憶。適來玩山水，無此秋潭色。',48,'御定全唐詩/json/475.json','["清剡與嚴湍，潺湲皆可憶。適來玩山水，無此秋潭色。", "莫辨幽蘭叢，難分翠禽翼。遲遲洲渚步，臨眺忘餐食。"]'),
('yuding-92','春暮思平泉雜詠二十首：竹徑','李德裕','唐','御定全唐诗','yuding','','[]','野竹自成徑，繞溪三裏餘。檀欒被層阜，蕭瑟蔭清渠。',48,'御定全唐詩/json/475.json','["野竹自成徑，繞溪三裏餘。檀欒被層阜，蕭瑟蔭清渠。", "日落見林靜，風行知穀虛。田家故人少，誰肯共焚魚。"]'),
('yuding-93','春暮思平泉雜詠二十首：花藥欄','李德裕','唐','御定全唐诗','yuding','','[]','蕙草春已碧，蘭花秋更紅。四時發英豔，三徑滿芳叢。',48,'御定全唐詩/json/475.json','["蕙草春已碧，蘭花秋更紅。四時發英豔，三徑滿芳叢。", "秀色濯清露，鮮輝搖惠風。王孫未知返，幽賞竟誰同。"]'),
('yuding-94','春暮思平泉雜詠二十首：自敘','李德裕','唐','御定全唐诗','yuding','','[]','五嶽徑雖深，遍遊心已蕩。苟能知止足，所遇皆清曠。',48,'御定全唐詩/json/475.json','["五嶽徑雖深，遍遊心已蕩。苟能知止足，所遇皆清曠。", "七十難可期，一丘乃微尚。遙懷少室山，常恐非吾望。"]'),
('yuding-95','首夏清景想望山居','李德裕','唐','御定全唐诗','yuding','','[]','嘉樹陰初合，山中賞更新。禽言未知夏，蘭徑尚餘春。',72,'御定全唐詩/json/475.json','["嘉樹陰初合，山中賞更新。禽言未知夏，蘭徑尚餘春。", "散滿蘿垂帶，扶疏桂長輪。丹青寫不盡，宵夢歎非真。", "累榭空留月，虛舟若待人。何時倚蘭棹，相與掇汀蘋。"]'),
('yuding-96','思平泉樹石雜詠一十首：釣台','李德裕','唐','御定全唐诗','yuding','','[]','我有嚴湍思，懷人訪故台。客星依釣隱，仙石逐槎回。',48,'御定全唐詩/json/475.json','["我有嚴湍思，懷人訪故台。客星依釣隱，仙石逐槎回。", "倒影含清沚，凝陰長碧苔。飛泉信可挹，幽客未歸來。"]'),
('yuding-97','思平泉樹石雜詠一十首：似鹿石','李德裕','唐','御定全唐诗','yuding','','[]','林中有奇石，仿佛獸潛行。乍似依岩桂，還疑食野蘋。',48,'御定全唐詩/json/475.json','["林中有奇石，仿佛獸潛行。乍似依岩桂，還疑食野蘋。", "茸長綠蘚映，斑細紫苔生。不是見羈者，何勞如頓纓。"]'),
('yuding-98','思平泉樹石雜詠一十首：海上石筍','李德裕','唐','御定全唐诗','yuding','','[]','常愛仙都山，奇峰千仞懸。迢迢一何迥，不與眾山連。',48,'御定全唐詩/json/475.json','["常愛仙都山，奇峰千仞懸。迢迢一何迥，不與眾山連。", "忽逢海嶠石，稍慰平生憶。何以慰我心，亭亭孤且直。"]'),
('yuding-99','思平泉樹石雜詠一十首：疊石','李德裕','唐','御定全唐诗','yuding','','[]','潺湲桂水湍，漱石多奇狀。鱗次冠煙霞，蟬聯疊波浪。',48,'御定全唐詩/json/475.json','["潺湲桂水湍，漱石多奇狀。鱗次冠煙霞，蟬聯疊波浪。", "今來碧梧下，迥出秋潭上。歲晚苔蘚滋，懷賢益惆悵。"]'),
('yuding-100','思平泉樹石雜詠一十首：重台芙蓉','李德裕','唐','御定全唐诗','yuding','','[]','芙蓉含露時，秀色波中溢。玉女襲朱裳，重重映皓質。',48,'御定全唐詩/json/475.json','["芙蓉含露時，秀色波中溢。玉女襲朱裳，重重映皓質。", "晨霞耀丹景，片片明秋日。蘭澤多眾芳，妍姿不相匹。"]'),
('yuding-101','思平泉樹石雜詠一十首：白鷺鶿','李德裕','唐','御定全唐诗','yuding','','[]','餘心憐白鷺，潭上日相依。拂石疑星落，淩風似雪飛。',48,'御定全唐詩/json/475.json','["餘心憐白鷺，潭上日相依。拂石疑星落，淩風似雪飛。", "碧沙常獨立，清景自忘歸。所樂惟煙水，徘徊戀釣磯。"]'),
('yuding-102','思平泉樹石雜詠一十首：海魚骨','李德裕','唐','御定全唐诗','yuding','','[]','昔日任公子，期年釣此魚。無由見成嶽，聊喜識專車。',48,'御定全唐詩/json/475.json','["昔日任公子，期年釣此魚。無由見成嶽，聊喜識專車。", "皎皎連霜月，高高映碧渠。陶潛雖好事，觀海只披圖。"]'),
('yuding-103','思平泉樹石雜詠一十首：泛池舟','李德裕','唐','御定全唐诗','yuding','','[]','桂舟蘭作枻，芬芳皆絕世。只可弄潺湲，焉能濟大川。',48,'御定全唐詩/json/475.json','["桂舟蘭作枻，芬芳皆絕世。只可弄潺湲，焉能濟大川。", "樹懸涼夜月，風散碧潭煙。未得同魚子，菱歌共扣舷。"]'),
('yuding-104','思平泉樹石雜詠一十首：舴艋舟','李德裕','唐','御定全唐诗','yuding','','[]','無輕舴艋舟，始自鴟夷子。雙闕掛朝衣，五湖極煙水。',48,'御定全唐詩/json/475.json','["無輕舴艋舟，始自鴟夷子。雙闕掛朝衣，五湖極煙水。", "時遊杏壇下，乍入湘川裏。永日歌濯纓，超然謝塵滓。"]'),
('yuding-105','思平泉樹石雜詠一十首：二猿','李德裕','唐','御定全唐诗','yuding','','[]','釣瀨水漣漪，富春山合遝。松上夜猿鳴，穀中清響合。',48,'御定全唐詩/json/475.json','["釣瀨水漣漪，富春山合遝。松上夜猿鳴，穀中清響合。", "沖網忽見羈，故山從此辭。無由碧潭飲，爭接綠蘿枝。"]'),
('yuding-106','思在山居日偶成此詠邀松陽子同作','李德裕','唐','御定全唐诗','yuding','','[]','閑思昔歲事，忽忽念伊川。乘月步秋阪，滿山聞石泉。',72,'御定全唐詩/json/475.json','["閑思昔歲事，忽忽念伊川。乘月步秋阪，滿山聞石泉。", "回塘碧潭映，高樹綠蘿懸。露下叫田鶴，風來嘶晚蟬。", "懷茲長在夢，歸去且無緣。幽谷人未至，蘭苕應更鮮。"]'),
('yuding-107','重憶山居六首：平泉源','李德裕','唐','御定全唐诗','yuding','','[]','山谷才浮芥，中園已濫觴。逶迤過竹塢，浩淼走蘭塘。',48,'御定全唐詩/json/475.json','["山谷才浮芥，中園已濫觴。逶迤過竹塢，浩淼走蘭塘。", "夜靜聞魚躍，風微見雁翔。從茲東向海，可泛濟川航。"]'),
('yuding-108','重憶山居六首：泰山石','李德裕','唐','御定全唐诗','yuding','','[]','雞鳴日觀望，遠與扶桑對。滄海似熔金，眾山如點黛。',48,'御定全唐詩/json/475.json','["雞鳴日觀望，遠與扶桑對。滄海似熔金，眾山如點黛。", "遙知碧峰首，獨立煙嵐內。此石依五松，蒼蒼幾千載。"]'),
('yuding-109','重憶山居六首：巫山石','李德裕','唐','御定全唐诗','yuding','','[]','十二峰前月，三聲猿夜愁。此中多怪石，日夕漱寒流。',48,'御定全唐詩/json/475.json','["十二峰前月，三聲猿夜愁。此中多怪石，日夕漱寒流。", "必是歸星渚，先求曆鬥牛。還疑煙雨霽，仿佛是嵩丘。"]'),
('yuding-110','重憶山居六首：羅浮山','李德裕','唐','御定全唐诗','yuding','','[]','龍伯釣鼇時，蓬萊一峰坼。飛來碧海畔，遂與三山隔。',48,'御定全唐詩/json/475.json','["龍伯釣鼇時，蓬萊一峰坼。飛來碧海畔，遂與三山隔。", "其下多長溪，潺湲淙亂石。知君分如此，贈逾荊山璧。"]'),
('yuding-111','重憶山居六首：漏潭石','李德裕','唐','御定全唐诗','yuding','','[]','常疑六合外，未信漆園書。及此聞溪漏，方欣驗尾閭。',48,'御定全唐詩/json/475.json','["常疑六合外，未信漆園書。及此聞溪漏，方欣驗尾閭。", "大哉天地氣，呼吸有盈虛。美石勞相贈，瓊瑰自不如。"]'),
('yuding-112','重憶山居六首：釣石','李德裕','唐','御定全唐诗','yuding','','[]','嚴光隱富春，山色溪又碧。所釣不在魚，揮綸以自適。',48,'御定全唐詩/json/475.json','["嚴光隱富春，山色溪又碧。所釣不在魚，揮綸以自適。", "余懷慕君子，且欲坐潭石。持此返伊川，悠然慰衰疾。"]'),
('yuding-113','懷伊川郊居','李德裕','唐','御定全唐诗','yuding','','[]','衰疾常懷土，郊園欲掩扉。雖知明目地，不及有身歸。',48,'御定全唐詩/json/475.json','["衰疾常懷土，郊園欲掩扉。雖知明目地，不及有身歸。", "鞏樹秋陰遍，伊原霽色微。此生看白首，良願已應違。"]'),
('yuding-114','晨起見雪憶山居','李德裕','唐','御定全唐诗','yuding','','[]','忽憶岩中雪，誰人拂薜蘿。竹梢低未舉，松蓋偃應多。',48,'御定全唐詩/json/475.json','["忽憶岩中雪，誰人拂薜蘿。竹梢低未舉，松蓋偃應多。", "山溜隨冰落，林麇帶霰過。不勞聞鶴語，方奏苦寒歌。"]'),
('yuding-115','憶平泉雜詠：憶初暖','李德裕','唐','御定全唐诗','yuding','','[]','今日初春暖，山中事若何。雪開喧鳥至，澌散躍魚多。',48,'御定全唐詩/json/475.json','["今日初春暖，山中事若何。雪開喧鳥至，澌散躍魚多。", "幽翠生松栝，輕煙起薜蘿。柴扉常晝掩，惟有野人過。"]'),
('yuding-116','憶平泉雜詠：憶辛夷','李德裕','唐','御定全唐诗','yuding','','[]','昔年將出穀，幾日對辛夷。倚樹憐芳意，攀條惜歲滋。',48,'御定全唐詩/json/475.json','["昔年將出穀，幾日對辛夷。倚樹憐芳意，攀條惜歲滋。", "清陰須暫憩，秀色正堪思。只待揮金日，殷勤泛羽卮。"]'),
('yuding-117','憶平泉雜詠：憶寒梅','李德裕','唐','御定全唐诗','yuding','','[]','寒塘數樹梅，常近臘前開。雪映緣岩竹，香侵泛水苔。',48,'御定全唐詩/json/475.json','["寒塘數樹梅，常近臘前開。雪映緣岩竹，香侵泛水苔。", "遙思清景暮，還有野禽來。誰是攀枝客，茲辰醉始回。"]'),
('yuding-118','憶平泉雜詠：憶藥欄','李德裕','唐','御定全唐诗','yuding','','[]','野人清旦起，掃雪見蘭芽。始畎春泉入，惟愁暮景斜。',48,'御定全唐詩/json/475.json','["野人清旦起，掃雪見蘭芽。始畎春泉入，惟愁暮景斜。", "未抽萱草葉，才發款冬花。誰念江潭老，中宵旅夢賒。"]'),
('yuding-119','憶平泉雜詠：憶茗芽','李德裕','唐','御定全唐诗','yuding','','[]','穀中春日暖，漸憶掇茶英。欲及清明火，能銷醉客酲。',48,'御定全唐詩/json/475.json','["穀中春日暖，漸憶掇茶英。欲及清明火，能銷醉客酲。", "松花飄鼎泛，蘭氣入甌輕。飲罷閑無事，捫蘿溪上行。"]'),
('yuding-120','憶平泉雜詠：憶野花','李德裕','唐','御定全唐诗','yuding','','[]','雖遊洛陽道，未識故園花。曉憶東溪雪，晴思冠嶺霞。',48,'御定全唐詩/json/475.json','["雖遊洛陽道，未識故園花。曉憶東溪雪，晴思冠嶺霞。", "穀深蘭色秀，村迥柳陰斜。悵望龍門晚，誰知小隱家。"]'),
('yuding-121','憶平泉雜詠：憶春雨','李德裕','唐','御定全唐诗','yuding','','[]','春鳩鳴野樹，細雨入池塘。潭上花微落，溪邊草更長。',48,'御定全唐詩/json/475.json','["春鳩鳴野樹，細雨入池塘。潭上花微落，溪邊草更長。", "梳風白鷺起，拂水彩鴛翔。最羨歸飛燕，年年在故鄉。"]'),
('yuding-122','憶平泉雜詠：憶晚眺','李德裕','唐','御定全唐诗','yuding','','[]','伊川新雨霽，原上見春山。緱嶺晴虹斷，龍門宿鳥還。',48,'御定全唐詩/json/475.json','["伊川新雨霽，原上見春山。緱嶺晴虹斷，龍門宿鳥還。", "牛羊平野外，桑柘夕煙間。不及鄉園叟，悠悠盡日閑。"]'),
('yuding-123','憶平泉雜詠：憶新藤','李德裕','唐','御定全唐诗','yuding','','[]','遙聞碧潭上，春晚紫藤開。水似晨霞照，林疑彩鳳來。',48,'御定全唐詩/json/475.json','["遙聞碧潭上，春晚紫藤開。水似晨霞照，林疑彩鳳來。", "清香凝島嶼，繁豔映莓苔。金谷如相並，應將錦帳回。"]'),
('yuding-124','憶平泉雜詠：憶春耕','李德裕','唐','御定全唐诗','yuding','','[]','郊外杏花坼，林間布穀鳴。原田春雨後，溪水夕流平。',48,'御定全唐詩/json/475.json','["郊外杏花坼，林間布穀鳴。原田春雨後，溪水夕流平。", "野老荷蓑至，和風吹草輕。無因共沮溺，相與事岩耕。"]'),
('yuding-125','余所居平泉村舍近蒙韋常侍大尹特改嘉名因寄詩以謝','李德裕','唐','御定全唐诗','yuding','','[]','未謝留侯疾，常懷仲蔚園。閑謠紫芝曲，歸夢赤松村。',48,'御定全唐詩/json/475.json','["未謝留侯疾，常懷仲蔚園。閑謠紫芝曲，歸夢赤松村。", "忽改蓬蒿色，俄吹黍穀暄。多慚孔北海，傳教及衡門。"]'),
('yuding-126','山信至說平泉別墅草木滋長地轉幽深悵然思歸複此作','李德裕','唐','御定全唐诗','yuding','','[]','忽聞樵客語，暫慰野人心。幽徑芳蘭密，閒庭秀木深。',48,'御定全唐詩/json/475.json','["忽聞樵客語，暫慰野人心。幽徑芳蘭密，閒庭秀木深。", "麇麚來澗底，鳧鵠遍川潯。誰念滄溟上，歸歟起歎音。"]'),
('yuding-127','臨海太守惠予赤城石，報以是詩','李德裕','唐','御定全唐诗','yuding','','[]','聞君采奇石，剪斷赤城霞。潭上倒虹影，波中搖日華。',48,'御定全唐詩/json/475.json','["聞君采奇石，剪斷赤城霞。潭上倒虹影，波中搖日華。", "仙岩接絳氣，溪路雜桃花。若值客星去，便應隨海槎。"]'),
('yuding-128','上巳憶江南禊事','李德裕','唐','御定全唐诗','yuding','','[]','黃河西繞郡城流，上巳應無祓禊遊。',32,'御定全唐詩/json/475.json','["黃河西繞郡城流，上巳應無祓禊遊。", "為憶淥江春水色，更無宵夢向吳州。"]'),
('yuding-129','北固懷古','李德裕','唐','御定全唐诗','yuding','','[]','自有此山川，於今幾太守。近世二千石，畢公宣化厚。',48,'御定全唐詩/json/475.json','["自有此山川，於今幾太守。近世二千石，畢公宣化厚。", "丞相量納川，平陽氣沖鬥。三賢若時雨，所至躋仁壽。"]'),
('yuding-130','汨羅','李德裕','唐','御定全唐诗','yuding','','[]','遠謫南荒一病身，停舟暫吊汨羅人。都緣靳尚圖專國，',40,'御定全唐詩/json/475.json','["遠謫南荒一病身，停舟暫吊汨羅人。都緣靳尚圖專國，", "不勞漁父重相問，自有招魂拭淚巾。"]'),
('yuding-131','嶺外守歲','李德裕','唐','御定全唐诗','yuding','','[]','冬逐更籌盡，春隨斗柄回。寒暄一夜隔，客鬢兩年催。',24,'御定全唐詩/json/475.json','["冬逐更籌盡，春隨斗柄回。寒暄一夜隔，客鬢兩年催。"]'),
('yuding-132','訪韋楚老不遇','李德裕','唐','御定全唐诗','yuding','','[]','昔日征黃綺，餘慚在鳳池。今來招隱士，恨不見瓊枝。',24,'御定全唐詩/json/475.json','["昔日征黃綺，餘慚在鳳池。今來招隱士，恨不見瓊枝。"]'),
('yuding-133','題柳郎中故居','李德裕','唐','御定全唐诗','yuding','','[]','下馬荒階日欲曛，潺潺石溜靜中聞。',32,'御定全唐詩/json/475.json','["下馬荒階日欲曛，潺潺石溜靜中聞。", "鳥啼花發人聲絕，寂寞山窗掩白雲。"]'),
('yuding-134','盤陀嶺驛樓','李德裕','唐','御定全唐诗','yuding','','[]','嵩少心期杳莫攀，好山聊複一開顏。',32,'御定全唐詩/json/475.json','["嵩少心期杳莫攀，好山聊複一開顏。", "明朝便是南荒路，更上層樓望故關。"]'),
('yuding-135','句','李德裕','唐','御定全唐诗','yuding','','[]','檢經求綠字，憑酒借紅顏。',262,'御定全唐詩/json/475.json','["檢經求綠字，憑酒借紅顏。", "君不見秋山寂曆風飆歇，半夜青崖吐明月。", "寒光乍出松筱間，萬籟蕭蕭從此發。忽聞歌管吟朔風，", "銀花懸院榜，神撼引鈴絛。", "葳蕤輕風裏，若銜若垂何可擬。", "自從一夢高唐後，可是無人勝楚王。（《賦巫山神女》，", "牛羊具特俎。", "心悟覺身勞，雲中棄寶刀。久閑生髀肉，多壽長眉毫。", "書空蹺足睡，路險側身行。（德裕嘗吟此句雲是先達詩。", "附記見《桂苑叢談》）", "誰家幼女敲箸歌，何處丁妻點燈織。", "魚蝦集橘市。", "休咎占人甲，挨持見天丁。", "洛下推年少，山東許地高。", "世上文章士，誰為第一人。老生誇隱拙，時輩毀尖新。", "dc濴寒泉深百尺。", "奇觚率爾操，諷諫欣然納。"]'),
('yuding-0','至日荷李常侍過郊居','熊孺登','唐','御定全唐诗','yuding','','[]','賤子守柴荊，誰人記姓名。風雲千騎降，草木一陽生。',72,'御定全唐詩/json/476.json','["賤子守柴荊，誰人記姓名。風雲千騎降，草木一陽生。", "禮異江河動，歡殊裏巷驚。稱觴容侍坐，看竹許同行。", "遇覺滄溟淺，恩疑太嶽輕。盡搜天地物，無諭此時情。"]'),
('yuding-1','日暮天無雲','熊孺登','唐','御定全唐诗','yuding','','[]','杳杳複蒼然，無雲日暮天。象分青氣外，景盡赤霄前。',72,'御定全唐詩/json/476.json','["杳杳複蒼然，無雲日暮天。象分青氣外，景盡赤霄前。", "漸吐星河色，遙生水木煙。從容難附麗，顧步欲澄鮮。", "但見收三素，何能測上玄。應非暫呈瑞，不許出山川。"]'),
('yuding-2','新成小亭月夜','熊孺登','唐','御定全唐诗','yuding','','[]','已被月知處，斬新風到來。無人伴幽境，多取木蘭栽。',24,'御定全唐詩/json/476.json','["已被月知處，斬新風到來。無人伴幽境，多取木蘭栽。"]'),
('yuding-3','和竇中丞歲酒喜見小男兩歲','熊孺登','唐','御定全唐诗','yuding','','[]','更添十歲應為相，歲酒從今把未休。',32,'御定全唐詩/json/476.json','["更添十歲應為相，歲酒從今把未休。", "聞得一毛添五色，眼看相逐鳳池頭。"]'),
('yuding-4','寒食','熊孺登','唐','御定全唐诗','yuding','','[]','東風潑火雨新休，舁盡春泥掃雪溝。',32,'御定全唐詩/json/476.json','["東風潑火雨新休，舁盡春泥掃雪溝。", "走馬犢車當禦路，漢陽公主謝雞球。"]'),
('yuding-5','送僧游山','熊孺登','唐','御定全唐诗','yuding','','[]','雲身自在山山去，何處靈山不是歸。',32,'御定全唐詩/json/476.json','["雲身自在山山去，何處靈山不是歸。", "日暮寒林投古寺，雪花飛滿水田衣。"]'),
('yuding-6','雪中答僧書','熊孺登','唐','御定全唐诗','yuding','','[]','八行銀字非常草，六出天花儘是梅。',32,'御定全唐詩/json/476.json','["八行銀字非常草，六出天花儘是梅。", "無所與陳童子別，雪中辛苦遠山來。"]'),
('yuding-7','題逍遙樓傷故韋大夫','熊孺登','唐','御定全唐诗','yuding','','[]','利及生人無更為，落花流水舊城池。',32,'御定全唐詩/json/476.json','["利及生人無更為，落花流水舊城池。", "逍遙樓上雕龍字，便是羊公墮淚碑。"]'),
('yuding-8','戲贈費冠卿','熊孺登','唐','御定全唐诗','yuding','','[]','但恐紅塵虛白首，寧論蹇逸分先後。',32,'御定全唐詩/json/476.json','["但恐紅塵虛白首，寧論蹇逸分先後。", "莫占鶯花笑寂寥，長安春色年年有。"]'),
('yuding-9','與左興宗湓城別','熊孺登','唐','御定全唐诗','yuding','','[]','江逢九派人將別，猿到三聲月為秋。',32,'御定全唐詩/json/476.json','["江逢九派人將別，猿到三聲月為秋。", "不知相見更何日，此夜少年堪白頭。"]'),
('yuding-10','八月十五夜臥疾','熊孺登','唐','御定全唐诗','yuding','','[]','一年只有今宵月，盡上江樓獨病眠。',32,'御定全唐詩/json/476.json','["一年只有今宵月，盡上江樓獨病眠。", "寂寞竹窗閑不閉，夜深斜影到床前。"]'),
('yuding-11','正月十五日','熊孺登','唐','御定全唐诗','yuding','','[]','漢家遺事今宵見，楚郭明燈幾處張。',32,'御定全唐詩/json/476.json','["漢家遺事今宵見，楚郭明燈幾處張。", "深夜行歌聲絕後，紫姑神下月蒼蒼。"]'),
('yuding-12','曲池陪宴即事上竇中丞','熊孺登','唐','御定全唐诗','yuding','','[]','水自山阿繞坐來，珊瑚臺上木綿開。',32,'御定全唐詩/json/476.json','["水自山阿繞坐來，珊瑚臺上木綿開。", "欲知舉目無情罰，一片花流酒一杯。"]'),
('yuding-13','董監廟','熊孺登','唐','御定全唐诗','yuding','','[]','仁傑淫祠廢欲無，枯楓老櫟兩三株。',32,'御定全唐詩/json/476.json','["仁傑淫祠廢欲無，枯楓老櫟兩三株。", "神烏慣得商人食，飛趁征帆過蠡湖。"]'),
('yuding-14','贈侯山人','熊孺登','唐','御定全唐诗','yuding','','[]','一見清容愜素聞，有人傳是紫陽君。',32,'御定全唐詩/json/476.json','["一見清容愜素聞，有人傳是紫陽君。", "來時玉女裁春服，剪破湘山幾片雲。"]'),
('yuding-15','送馬判官赴安南','熊孺登','唐','御定全唐诗','yuding','','[]','故人交趾去從軍，應笑狂生揮陣雲。',32,'御定全唐詩/json/476.json','["故人交趾去從軍，應笑狂生揮陣雲。", "省得蔡州今日事，舊曾都護帳前聞。"]'),
('yuding-16','送准上人歸石經院','熊孺登','唐','御定全唐诗','yuding','','[]','旃檀刻像今猶少，白石鐫經古未曾。',32,'御定全唐詩/json/476.json','["旃檀刻像今猶少，白石鐫經古未曾。", "歸去更尋翻譯寺，前山應遇雁門僧。"]'),
('yuding-17','寒食野望','熊孺登','唐','御定全唐诗','yuding','','[]','拜掃無過骨肉親，一年唯此兩三辰。',32,'御定全唐詩/json/476.json','["拜掃無過骨肉親，一年唯此兩三辰。", "塚頭莫種有花樹，春色不關泉下人。"]'),
('yuding-18','祗役遇風謝湘中春色','熊孺登','唐','御定全唐诗','yuding','','[]','水生風熟布帆新，只見公程不見春。',32,'御定全唐詩/json/476.json','["水生風熟布帆新，只見公程不見春。", "應被百花撩亂笑，比來天地一閒人。"]'),
('yuding-19','湘江夜泛','熊孺登','唐','御定全唐诗','yuding','','[]','江流如箭月如弓，行盡三湘數夜中。',32,'御定全唐詩/json/476.json','["江流如箭月如弓，行盡三湘數夜中。", "無那子規知向蜀，一聲聲似怨春風。"]'),
('yuding-20','蜀江水','熊孺登','唐','御定全唐诗','yuding','','[]','日夜朝宗來萬里，共憐江水引蕃心。',32,'御定全唐詩/json/476.json','["日夜朝宗來萬里，共憐江水引蕃心。", "若論巴峽愁人處，猿比灘聲是好音。"]'),
('yuding-21','寄安南馬中丞','熊孺登','唐','御定全唐诗','yuding','','[]','龍韜能致虎符分，萬里霜台壓瘴雲。',32,'御定全唐詩/json/476.json','["龍韜能致虎符分，萬里霜台壓瘴雲。", "蕃客不須愁海路，波神今伏馬將軍。"]'),
('yuding-22','甘子堂陪宴上韋大夫','熊孺登','唐','御定全唐诗','yuding','','[]','武陵樓上春長早，甘子堂前花落遲。',32,'御定全唐詩/json/476.json','["武陵樓上春長早，甘子堂前花落遲。", "楚樂怪來聲競起，新歌儘是大夫詞。"]'),
('yuding-23','青溪村居二首','熊孺登','唐','御定全唐诗','yuding','','[]','家占溪南千個竹，地臨湖上一群山。',64,'御定全唐詩/json/476.json','["家占溪南千個竹，地臨湖上一群山。", "漁船多在馬長放，出處自由閑不閑。", "深樹黃鸝曉一聲，林西江上月猶明。", "野人早起無他事，貪繞沙泉看筍生。"]'),
('yuding-24','奉和興元鄭相公早春送楊侍郎','熊孺登','唐','御定全唐诗','yuding','','[]','征鞍欲上醉還留，南浦春生百草頭。',32,'御定全唐詩/json/476.json','["征鞍欲上醉還留，南浦春生百草頭。", "丞相新裁別離曲，聲聲飛出舊梁州。"]'),
('yuding-25','送舍弟孺複往廬山','熊孺登','唐','御定全唐诗','yuding','','[]','能騎竹馬辨西東，未省煙花暫不同。',32,'御定全唐詩/json/476.json','["能騎竹馬辨西東，未省煙花暫不同。", "第一早歸春欲盡，廬山好看過湖風。"]'),
('yuding-26','野別留少微上人','熊孺登','唐','御定全唐诗','yuding','','[]','若為相見還分散，翻覺浮雲亦不閑。',32,'御定全唐詩/json/476.json','["若為相見還分散，翻覺浮雲亦不閑。", "何處留師暫且住，家貧唯有坐中山。"]'),
('yuding-27','經古墓','熊孺登','唐','御定全唐诗','yuding','','[]','碑折松枯山火燒，夜台從閉不曾朝。',32,'御定全唐詩/json/476.json','["碑折松枯山火燒，夜台從閉不曾朝。", "那將逝者比流水，流水東流逢上潮。"]'),
('yuding-28','贈靈徹上人','熊孺登','唐','御定全唐诗','yuding','','[]','詩句能生世界春，僧家更有姓湯人。',32,'御定全唐詩/json/476.json','["詩句能生世界春，僧家更有姓湯人。", "況聞暗憶前朝事，知是修行第幾身。"]'),
('yuding-29','春郊醉中贈章八元','熊孺登','唐','御定全唐诗','yuding','','[]','三月踏青能幾日，百回添酒莫辭頻。',32,'御定全唐詩/json/476.json','["三月踏青能幾日，百回添酒莫辭頻。", "看君倒臥楊花裏，始覺春光為醉人。"]'),
('yuding-0','懷古','李涉','唐','御定全唐诗','yuding','','[]','尼父未適魯，屢屢倦迷津。徒懷教化心，紆鬱不能伸。',48,'御定全唐詩/json/477.json','["尼父未適魯，屢屢倦迷津。徒懷教化心，紆鬱不能伸。", "一遇知己言，萬方始喧喧。至今百王則，孰不挹其源。"]'),
('yuding-1','詠古','李涉','唐','御定全唐诗','yuding','','[]','大智思濟物，道行心始休。垂綸自消息，歲月任春秋。',96,'御定全唐詩/json/477.json','["大智思濟物，道行心始休。垂綸自消息，歲月任春秋。", "紂虐武既賢，風雲固可求。順天行殺機，所向協良謀。", "況以丈人師，將濟安川流。何勞問枯骨，再取陰陽籌。", "霸國不務仁，兵戈恣相酬。空令渭水跡，千古獨悠悠。"]'),
('yuding-2','題清溪鬼谷先生舊居','李涉','唐','御定全唐诗','yuding','','[]','翠壁開天池，青崖列雲樹。水容不可狀，杳若清河霧。',120,'御定全唐詩/json/477.json','["翠壁開天池，青崖列雲樹。水容不可狀，杳若清河霧。", "常聞先生教，指示秦儀路。二子才不同，逞詞過尺度。", "偶因從吏役，遠到冥棲處。松月想舊山，煙霞了如故。", "未遑煉金鼎，日覺容光暮。萬慮隨境生，何由返真素。", "寂寞天籟息，清迥鳥聲曙。回首望重重，無期挹風馭。"]'),
('yuding-3','感興','李涉','唐','御定全唐诗','yuding','','[]','隋氏造宮闕，峨峨倚雲煙。搜奇竭四海，立制謀千年。',72,'御定全唐詩/json/477.json','["隋氏造宮闕，峨峨倚雲煙。搜奇竭四海，立制謀千年。", "秦兵半夜來，烈火焚高臺。萬人聚筋血，一旦為塵埃。", "君看汴河路，尚說隋家柳。但問哭陵人，秋草沒來久。"]'),
('yuding-4','鷓鴣詞二首','李涉','唐','御定全唐诗','yuding','','[]','湘江煙水深，沙岸隔楓林。何處鷓鴣飛，日斜斑竹陰。',96,'御定全唐詩/json/477.json','["湘江煙水深，沙岸隔楓林。何處鷓鴣飛，日斜斑竹陰。", "二女空垂淚，三閭枉自沉。惟有鷓鴣啼，獨傷行客心。", "越岡連越井，越鳥更南飛。何處鷓鴣啼，夕煙東嶺歸。", "嶺外行人少，天涯北客稀。鷓鴣啼別處，相對淚沾衣。"]'),
('yuding-5','山中','李涉','唐','御定全唐诗','yuding','','[]','無奈牧童何，放牛吃我竹。隔林呼不應，叫笑如生鹿。',36,'御定全唐詩/json/477.json','["無奈牧童何，放牛吃我竹。隔林呼不應，叫笑如生鹿。", "欲報田舍翁，更深不歸屋。"]'),
('yuding-6','寄荊娘寫真','李涉','唐','御定全唐诗','yuding','','[]','章華台南莎草齊，長河柳色連金堤。青樓曈曨曙光蚤，',204,'御定全唐詩/json/477.json','["章華台南莎草齊，長河柳色連金堤。青樓曈曨曙光蚤，", "教坊大使久知名，郢上詞人歌不足。少年才子心相許，", "緣池並戲雙鴛鴦，田田翠葉紅蓮香。百年恩愛兩相許，", "只愁陵谷變人寰，空歎桑田歸海岸。願分精魄定形影，", "忽然相對兩不語，疑是妝成來鏡中。豈期人願天不違，", "良人翻作東飛翼，卻遣江頭問消息。經年不得一封書，", "征帆三千里，前月發豫章。知我別時言，識我馬上郎。", "恨無羽翼飛，使我徒怨滄波長。開篋取畫圖，", "蒼梧九疑在何處，斑斑竹淚連瀟湘。"]'),
('yuding-7','與弟渤新羅劍歌','李涉','唐','御定全唐诗','yuding','','[]','我有神劍異人與，暗中往往精靈語。識者知從東海來，',73,'御定全唐詩/json/477.json','["我有神劍異人與，暗中往往精靈語。識者知從東海來，", "昨夜大樑城下宿，不借eZ跌光顏看。刃邊颯颯塵沙缺，", "我有愛弟都九江，一條直氣今無雙。青光好去莫惆悵，"]'),
('yuding-8','六歎','李涉','唐','御定全唐诗','yuding','','[]','綺羅香風翡翠車，清明獨傍芙蓉渠。上有雲鬟洞仙女，',136,'御定全唐詩/json/477.json','["綺羅香風翡翠車，清明獨傍芙蓉渠。上有雲鬟洞仙女，", "欲傳一劄孤飛翼，山長水遠無消息。卻鎖重門一院深，", "深院梧桐夾金井，上有轆轤青絲索。美人清晝汲寒泉，", "惆悵不來照明鏡，卻掩洞房抱寂寂。", "漢臣一沒丁零塞，牧羊西過陰沙外。朝憑南雁信難回，", "但將鐘鼓悅私愛，肯以犬羊為國羞。夜宿寒雲臥冰雪，"]'),
('yuding-9','春山三朅來','李涉','唐','御定全唐诗','yuding','','[]','釣魚朅來春日暖，沿溪不厭舟行緩。野竹初栽碧玉長，',152,'御定全唐詩/json/477.json','["釣魚朅來春日暖，沿溪不厭舟行緩。野竹初栽碧玉長，", "我今無事亦如此，赤鯉忽到長竿頭。泛泛隨波凡幾裏，", "有時帶月歸扣舷，身閑自是漁家仙。", "山上朅來采新茗，新花亂髮前山頂。瓊英動搖鐘乳碧，", "越甌遙見裂鼻香，欲覺身輕騎白鶴。", "采藥朅來藥苗盛，藥生只傍行人徑。世人重耳不重目，", "小男學語便分別，已辯君臣知匹配。都市廣長開大鋪，"]'),
('yuding-10','牧童詞','李涉','唐','御定全唐诗','yuding','','[]','朝牧牛，牧牛下江曲。夜牧牛，牧牛度村穀。',44,'御定全唐詩/json/477.json','["朝牧牛，牧牛下江曲。夜牧牛，牧牛度村穀。", "荷蓑出林春雨細，蘆管臥吹莎草綠。亂插蓬蒿箭滿腰，"]'),
('yuding-11','醉中贈崔膺','李涉','唐','御定全唐诗','yuding','','[]','與君兄弟匡嶺故，與君相逢揚子渡。白浪南分吳塞雲，',96,'御定全唐詩/json/477.json','["與君兄弟匡嶺故，與君相逢揚子渡。白浪南分吳塞雲，", "煬帝陵邊草木深，汴河流水空歸海。古今悠悠人自別，", "與君一言兩相許，外舍形骸中爾女。揚州歌酒不可追，", "暫到香爐一夕間，能展愁眉百世事。君看白日光如箭，"]'),
('yuding-12','岳陽別張祜','李涉','唐','御定全唐诗','yuding','','[]','十年蹭蹬為逐臣，鬢毛白盡巴江春。鹿鳴猿嘯雖寂寞，',112,'御定全唐詩/json/477.json','["十年蹭蹬為逐臣，鬢毛白盡巴江春。鹿鳴猿嘯雖寂寞，", "半夜州符喚牧童，虛教衰病生驚怕。巫峽洞庭千里餘，", "霸橋昔與張生別，萬變桑田何處說。龍蛇縱在沒泥塗，", "洛下諸生懼刺先，烏鳶不得齊鷹鷂。岳陽西南湖上寺，", "策馬前途須努力，莫學龍鍾虛歎息。"]'),
('yuding-13','寄河陽從事楊潛','李涉','唐','御定全唐诗','yuding','','[]','憶昨天台尋石樑，赤城枕下看扶桑。金烏欲上海如血，',212,'御定全唐詩/json/477.json','["憶昨天台尋石樑，赤城枕下看扶桑。金烏欲上海如血，", "回舟偶得風水便，煙帆數夕歸瀟湘。瀟湘水清岩嶂曲，", "進者恐不榮，退者恐不深。魚遊鳥逝兩雖異，", "稚子才年七歲餘，漁樵一半分渠力。吾友從軍在河上，", "見君顏色猶憔悴，知君未展心中事。落日驅車出孟津，", "漢家天子不東游，古木行宮閉煙月。洛濱老翁年八十，", "當時天下無甲兵，雖聞賦斂毫毛輕。紅車翠蓋滿衢路，", "九重宮殿閉豺狼，萬國生人自相噬。蹭蹬瘡痍今不平，", "秦中豪寵爭出群，巧將言智寬明君。南山四皓不敢語，"]'),
('yuding-14','重登滕王閣','李涉','唐','御定全唐诗','yuding','','[]','滕王閣上唱伊州，二十年前向此遊。',32,'御定全唐詩/json/477.json','["滕王閣上唱伊州，二十年前向此遊。", "半是半非君莫問，好山長在水長流。"]'),
('yuding-15','重到襄陽哭亡友韋壽朋','李涉','唐','御定全唐诗','yuding','','[]','故人墳樹立秋風，伯道無兒跡便空。',32,'御定全唐詩/json/477.json','["故人墳樹立秋風，伯道無兒跡便空。", "重到笙歌分散地，隔江吹笛月明中。"]'),
('yuding-16','再至長安','李涉','唐','御定全唐诗','yuding','','[]','十年謫宦鬼方人，三遇鴻恩始到秦。',32,'御定全唐詩/json/477.json','["十年謫宦鬼方人，三遇鴻恩始到秦。", "今日九衢騎馬望，卻疑渾是刹那身。"]'),
('yuding-17','贈道器法師','李涉','唐','御定全唐诗','yuding','','[]','冰作形容雪作眉，早知談論兩川知。',32,'御定全唐詩/json/477.json','["冰作形容雪作眉，早知談論兩川知。", "如今不用空求佛，但把令狐宰相詩。"]'),
('yuding-18','廬山得元侍禦書','李涉','唐','御定全唐诗','yuding','','[]','慚君知我命龍鍾，一紙書來意萬重。',32,'御定全唐詩/json/477.json','["慚君知我命龍鍾，一紙書來意萬重。", "正著白衣尋古寺，忽然郵遞到雲峰。"]'),
('yuding-19','竹枝詞','李涉','唐','御定全唐诗','yuding','','[]','荊門灘急水潺潺，兩岸猿啼煙滿山。',128,'御定全唐詩/json/477.json','["荊門灘急水潺潺，兩岸猿啼煙滿山。", "渡頭少年應官去，月落西陵望不還。", "巫峽雲開神女祠，綠潭紅樹影參差。", "不勞戍口初相問，無義灘頭剩別離。", "石壁千重樹萬重，白雲斜掩碧芙蓉。", "昭君溪上年年月，偏照嬋娟色最濃。", "十二峰頭月欲低，空聆灘上子規啼。", "孤舟一夜東歸客，泣向東風憶建溪。"]'),
('yuding-20','京口送朱晝之淮南','李涉','唐','御定全唐诗','yuding','','[]','兩行客淚愁中落，萬樹山花雨後殘。',32,'御定全唐詩/json/477.json','["兩行客淚愁中落，萬樹山花雨後殘。", "君到揚州見桃葉，為傳風水渡江難。"]'),
('yuding-21','題鶴林寺僧舍','李涉','唐','御定全唐诗','yuding','','[]','終日昏昏醉夢間，忽聞春盡強登山。',32,'御定全唐詩/json/477.json','["終日昏昏醉夢間，忽聞春盡強登山。", "因過竹院逢僧話，又得浮生半日閑。"]'),
('yuding-22','重過文上人院','李涉','唐','御定全唐诗','yuding','','[]','南隨越鳥北燕鴻，松月三年別遠公。',32,'御定全唐詩/json/477.json','["南隨越鳥北燕鴻，松月三年別遠公。", "無限心中不平事，一宵清話又成空。"]'),
('yuding-23','雙峰寺得舍弟書','李涉','唐','御定全唐诗','yuding','','[]','暫入松門拜祖師，殷勤再讀塔前碑。',32,'御定全唐詩/json/477.json','["暫入松門拜祖師，殷勤再讀塔前碑。", "回頭忽向尋陽使，太守如今是惠持。"]'),
('yuding-24','木蘭花','李涉','唐','御定全唐诗','yuding','','[]','碧落真人著紫衣，始堪相並木蘭枝。',32,'御定全唐詩/json/477.json','["碧落真人著紫衣，始堪相並木蘭枝。", "今朝繞郭花看遍，儘是深村田舍兒。"]'),
('yuding-25','過招隱寺','李涉','唐','御定全唐诗','yuding','','[]','每憶中林訪惠持，今來正遇早春時。',32,'御定全唐詩/json/477.json','["每憶中林訪惠持，今來正遇早春時。", "自從休去無心事，唯向高僧說便知。"]'),
('yuding-26','酬舉生許遇山居','李涉','唐','御定全唐诗','yuding','','[]','琉璃潭上新秋月，清淨泉中智惠珠。',32,'御定全唐詩/json/477.json','["琉璃潭上新秋月，清淨泉中智惠珠。", "不似本宗疏二教，許過雲壑訪潛夫。"]'),
('yuding-27','春晚游鶴林寺寄使府諸公','李涉','唐','御定全唐诗','yuding','','[]','野寺尋花春已遲，背岩唯有兩三枝。',32,'御定全唐詩/json/477.json','["野寺尋花春已遲，背岩唯有兩三枝。", "明朝攜酒猶堪賞，為報春風且莫吹。"]'),
('yuding-28','題開聖寺','李涉','唐','御定全唐诗','yuding','','[]','宿雨初收草木濃，群鴉飛散下堂鐘。',32,'御定全唐詩/json/477.json','["宿雨初收草木濃，群鴉飛散下堂鐘。", "長廊無事僧歸院，盡日門前獨看松。"]'),
('yuding-29','奉使淮南','李涉','唐','御定全唐诗','yuding','','[]','漢使徵兵詔未休，兩行旌旆接揚州。',32,'御定全唐詩/json/477.json','["漢使徵兵詔未休，兩行旌旆接揚州。", "試上高樓望春色，一年風景盡堪愁。"]'),
('yuding-30','登北固山亭','李涉','唐','御定全唐诗','yuding','','[]','海繞重山江抱城，隋家宮苑此分明。',32,'御定全唐詩/json/477.json','["海繞重山江抱城，隋家宮苑此分明。", "居人不覺三吳恨，卻笑關河又戰爭。"]'),
('yuding-31','秋日過員太祝林園','李涉','唐','御定全唐诗','yuding','','[]','望水尋山二裏餘，竹林斜到地仙居。',32,'御定全唐詩/json/477.json','["望水尋山二裏餘，竹林斜到地仙居。", "秋光何處堪消日，玄晏先生滿架書。"]'),
('yuding-32','題武關','李涉','唐','御定全唐诗','yuding','','[]','來往悲歡萬里心，多從此路計浮沉。',32,'御定全唐詩/json/477.json','["來往悲歡萬里心，多從此路計浮沉。", "皆緣不得空門要，舜葬蒼梧直到今。"]'),
('yuding-33','題溫泉','李涉','唐','御定全唐诗','yuding','','[]','能使時平四十春，開元聖主得賢臣。',32,'御定全唐詩/json/477.json','["能使時平四十春，開元聖主得賢臣。", "當時姚宋並燕許，儘是驪山從駕人。"]'),
('yuding-34','經溳川館寄使府群公','李涉','唐','御定全唐诗','yuding','','[]','溳川水竹十家餘，漁艇蓬門對岸居。',32,'御定全唐詩/json/477.json','["溳川水竹十家餘，漁艇蓬門對岸居。", "大勝塵中走鞍馬，與他軍府判文書。"]'),
('yuding-35','葺夷陵幽居','李涉','唐','御定全唐诗','yuding','','[]','負郭依山一徑深，萬竿如朿翠沉沉。',32,'御定全唐詩/json/477.json','["負郭依山一徑深，萬竿如朿翠沉沉。", "從來愛物多成癖，辛苦移家為竹林。"]'),
('yuding-36','再遊頭陀寺','李涉','唐','御定全唐诗','yuding','','[]','無因暫泊魯陽戈，白髮兼愁日日多。',32,'御定全唐詩/json/477.json','["無因暫泊魯陽戈，白髮兼愁日日多。", "只恐雪晴花便盡，數來山寺亦無他。"]'),
('yuding-37','看射柳枝','李涉','唐','御定全唐诗','yuding','','[]','玉弝朱弦敕賜弓，新加二鬥得秋風。',32,'御定全唐詩/json/477.json','["玉弝朱弦敕賜弓，新加二鬥得秋風。", "萬人齊看翻金勒，百步穿楊逐箭空。"]'),
('yuding-38','寄峽州韋郎中','李涉','唐','御定全唐诗','yuding','','[]','年過五十鬢如絲，不必前程更問師。',32,'御定全唐詩/json/477.json','["年過五十鬢如絲，不必前程更問師。", "幸得休耕樂堯化，楚山深處最相宜。"]'),
('yuding-39','贈田玉卿','李涉','唐','御定全唐诗','yuding','','[]','長安裏巷舊鄰居，未解梳頭五歲餘。',32,'御定全唐詩/json/477.json','["長安裏巷舊鄰居，未解梳頭五歲餘。", "今朝嫁得風流婿，歌舞閒時看讀書。"]'),
('yuding-40','題招隱寺即戴顒舊宅','李涉','唐','御定全唐诗','yuding','','[]','兩崖古樹千般色，一井寒泉數丈冰。',32,'御定全唐詩/json/477.json','["兩崖古樹千般色，一井寒泉數丈冰。", "欲問前朝戴居士，野煙秋色是丘陵。"]'),
