('yuding-30','疾愈步庭花','陸暢','唐','御定全唐诗','yuding','','[]','桃紅李白覺春歸，強步閒庭力尚微。',32,'御定全唐詩/json/478.json','["桃紅李白覺春歸，強步閒庭力尚微。", "從困不扶靈壽杖，恐驚花裏早鶯飛。"]'),
('yuding-31','籌筆店江亭','陸暢','唐','御定全唐诗','yuding','','[]','九折岩邊下馬行，江亭暫歇聽江聲。',32,'御定全唐詩/json/478.json','["九折岩邊下馬行，江亭暫歇聽江聲。", "白雲綠樹不關我，枉與樵人樂一生。"]'),
('yuding-32','贈賀若少府','陸暢','唐','御定全唐诗','yuding','','[]','十日廣陵城裏住，聽君花下撫金徽。',32,'御定全唐詩/json/478.json','["十日廣陵城裏住，聽君花下撫金徽。", "新聲指上懷中紙，莫怪潛偷數曲歸。"]'),
('yuding-33','太子劉舍人邀看花','陸暢','唐','御定全唐诗','yuding','','[]','年少風流七品官，朱衣白馬冶遊盤。',32,'御定全唐詩/json/478.json','["年少風流七品官，朱衣白馬冶遊盤。", "負心不報春光主，幾處偷看紅牡丹。"]'),
('yuding-34','薔薇花','陸暢','唐','御定全唐诗','yuding','','[]','錦窠花朵燈叢醉，翠葉眉稠裛露垂。',32,'御定全唐詩/json/478.json','["錦窠花朵燈叢醉，翠葉眉稠裛露垂。", "莫引美人來架下，恐驚紅片落燕支。"]'),
('yuding-35','句','陸暢','唐','御定全唐诗','yuding','','[]','蜀道易，易於履平地。',22,'御定全唐詩/json/478.json','["蜀道易，易於履平地。", "蟬噪入雲樹，風開無主花。"]'),
('yuding-0','應制賀邊軍支春衣','柳公權','唐','御定全唐诗','yuding','','[]','去歲雖無戰，今年未得歸。皇恩何以報，春日得春衣。',48,'御定全唐詩/json/479.json','["去歲雖無戰，今年未得歸。皇恩何以報，春日得春衣。", "挾纊非真纊，分衣是假衣。從今貔武士，不憚戍金微。"]'),
('yuding-1','應制為宮嬪詠','柳公權','唐','御定全唐诗','yuding','','[]','不分前時忤主恩，已甘寂寞守長門。',32,'御定全唐詩/json/479.json','["不分前時忤主恩，已甘寂寞守長門。", "今朝卻得君王顧，重入椒房拭淚痕。"]'),
('yuding-2','題朱審寺壁山水畫','柳公權','唐','御定全唐诗','yuding','','[]','朱審偏能視夕嵐，洞邊深墨寫秋潭。',32,'御定全唐詩/json/479.json','["朱審偏能視夕嵐，洞邊深墨寫秋潭。", "與君一顧西牆畫，從此看山不向南。"]'),
('yuding-3','閶門即事','柳公權','唐','御定全唐诗','yuding','','[]','耕夫占募逐樓船，春草青青萬頃田。',32,'御定全唐詩/json/479.json','["耕夫占募逐樓船，春草青青萬頃田。", "試上吳門看郡郭，清明幾處有新煙。"]'),
('yuding-4','貢院樓北新栽小松','吳武陵','唐','御定全唐诗','yuding','','[]','拂檻愛貞容，移根自遠峰。已曾經草沒，終不任苔封。',72,'御定全唐詩/json/479.json','["拂檻愛貞容，移根自遠峰。已曾經草沒，終不任苔封。", "葉少初陵雪，鱗生欲化龍。乘春濯雨露，得地近垣墉。", "逐吹香微動，含煙色漸濃。時回日月照，為謝小山松。"]'),
('yuding-5','題路左佛堂','吳武陵','唐','御定全唐诗','yuding','','[]','雀兒來逐颺風高，下視鷹鸇意氣豪。',32,'御定全唐詩/json/479.json','["雀兒來逐颺風高，下視鷹鸇意氣豪。", "自謂能生千里翼，黃昏依舊委蓬蒿。"]'),
('yuding-6','盛山十二詩：隱月岫','韋處厚','唐','御定全唐诗','yuding','','[]','初映鉤如線，終銜鏡似鉤。遠澄秋水色，高倚曉河流。',24,'御定全唐詩/json/479.json','["初映鉤如線，終銜鏡似鉤。遠澄秋水色，高倚曉河流。"]'),
('yuding-7','盛山十二詩：流杯渠','韋處厚','唐','御定全唐诗','yuding','','[]','激曲縈飛箭，浮溝泛滿卮。將來山太守，早向習家池。',24,'御定全唐詩/json/479.json','["激曲縈飛箭，浮溝泛滿卮。將來山太守，早向習家池。"]'),
('yuding-8','盛山十二詩：竹岩','韋處厚','唐','御定全唐诗','yuding','','[]','不資冬日秀，為作暑天寒。先植誠非鳳，來翔定是鸞。',24,'御定全唐詩/json/479.json','["不資冬日秀，為作暑天寒。先植誠非鳳，來翔定是鸞。"]'),
('yuding-9','盛山十二詩：繡衣石榻','韋處厚','唐','御定全唐诗','yuding','','[]','巉巉雪中嶠，磊磊標方峭。勿為枕蒼山，還當礎清廟。',24,'御定全唐詩/json/479.json','["巉巉雪中嶠，磊磊標方峭。勿為枕蒼山，還當礎清廟。"]'),
('yuding-10','盛山十二詩：宿雲亭','韋處厚','唐','御定全唐诗','yuding','','[]','雨合飛危砌，天開卷曉窗。齊平聯郭柳，帶繞抱城江。',24,'御定全唐詩/json/479.json','["雨合飛危砌，天開卷曉窗。齊平聯郭柳，帶繞抱城江。"]'),
('yuding-11','盛山十二詩：梅溪','韋處厚','唐','御定全唐诗','yuding','','[]','夾岸凝清素，交枝漾淺淪。味調方薦實，臘近又先春。',24,'御定全唐詩/json/479.json','["夾岸凝清素，交枝漾淺淪。味調方薦實，臘近又先春。"]'),
('yuding-12','盛山十二詩：桃塢','韋處厚','唐','御定全唐诗','yuding','','[]','噴日舒紅景，通蹊茂綠陰。終期王母摘，不羨武陵深。',24,'御定全唐詩/json/479.json','["噴日舒紅景，通蹊茂綠陰。終期王母摘，不羨武陵深。"]'),
('yuding-13','盛山十二詩：胡盧沼','韋處厚','唐','御定全唐诗','yuding','','[]','疏鑿徒為巧，圓窪自可澄。倒花紛錯秀，鑒月靜涵冰。',24,'御定全唐詩/json/479.json','["疏鑿徒為巧，圓窪自可澄。倒花紛錯秀，鑒月靜涵冰。"]'),
('yuding-14','盛山十二詩：茶嶺','韋處厚','唐','御定全唐诗','yuding','','[]','顧渚吳商絕，蒙山蜀信稀。千叢因此始，含露紫英肥。',24,'御定全唐詩/json/479.json','["顧渚吳商絕，蒙山蜀信稀。千叢因此始，含露紫英肥。"]'),
('yuding-15','盛山十二詩：磐石磴','韋處厚','唐','御定全唐诗','yuding','','[]','繚繞緣雲上，璘玢甃玉聯。高高曾幾折，極目瞰秋鳶。',24,'御定全唐詩/json/479.json','["繚繞緣雲上，璘玢甃玉聯。高高曾幾折，極目瞰秋鳶。"]'),
('yuding-16','盛山十二詩：琵琶台','韋處厚','唐','御定全唐诗','yuding','','[]','褊地難層土，因厓遂削成。淺深嵐嶂色，盡向此中呈。',24,'御定全唐詩/json/479.json','["褊地難層土，因厓遂削成。淺深嵐嶂色，盡向此中呈。"]'),
('yuding-17','盛山十二詩：上士瓶泉','韋處厚','唐','御定全唐诗','yuding','','[]','綆汲豈無井，顛崖貴非浚。願灑塵垢餘，一雨根莖潤。',24,'御定全唐詩/json/479.json','["綆汲豈無井，顛崖貴非浚。願灑塵垢餘，一雨根莖潤。"]'),
('yuding-18','客思吟','楊敬之','唐','御定全唐诗','yuding','','[]','禾黍正離離，南園剪白芝。細腰沈趙女，高髻唱蠻姬。',48,'御定全唐詩/json/479.json','["禾黍正離離，南園剪白芝。細腰沈趙女，高髻唱蠻姬。", "路愧前岡月，梳慚一頷絲。鄉人不可語，獨念畏人知。"]'),
('yuding-19','贈項斯','楊敬之','唐','御定全唐诗','yuding','','[]','幾度見詩詩總好，及觀標格過於詩。',32,'御定全唐詩/json/479.json','["幾度見詩詩總好，及觀標格過於詩。", "平生不解藏人善，到處逢人說項斯。"]'),
('yuding-20','句','楊敬之','唐','御定全唐诗','yuding','','[]','霜樹鳥棲夜，空街雀報明。',24,'御定全唐詩/json/479.json','["霜樹鳥棲夜，空街雀報明。", "碧山相倚暮，歸雁一行斜。"]'),
('yuding-21','初日照鳳樓','李虞仲','唐','御定全唐诗','yuding','','[]','旭日煙雲殿，朝陽燭帝居。斷霞生峻宇，通閣麗晴虛。',72,'御定全唐詩/json/479.json','["旭日煙雲殿，朝陽燭帝居。斷霞生峻宇，通閣麗晴虛。", "流彩連朱檻，騰輝照綺疏。曈曨晨景裏，明滅曉光初。", "戶牖仙山近，軒楹鳳翼舒。還如王母過，遙度五雲車。"]'),
('yuding-22','郡齋三月下旬作','張又新','唐','御定全唐诗','yuding','','[]','春事日已歇，池塘曠幽尋。殘紅披獨墜，初綠間淺深。',48,'御定全唐詩/json/479.json','["春事日已歇，池塘曠幽尋。殘紅披獨墜，初綠間淺深。", "偃仰倦芳褥，顧步愛新陰。謀春未及竟，夏初遽見侵。"]'),
('yuding-23','五月水邊柳','張又新','唐','御定全唐诗','yuding','','[]','結根挺涯涘，垂影覆清淺。睡臉寒未開，懶腰晴更軟。',72,'御定全唐詩/json/479.json','["結根挺涯涘，垂影覆清淺。睡臉寒未開，懶腰晴更軟。", "搖空條已重，拂水帶方展。似醉煙景凝，如愁月露泫。", "絲長魚誤恐，枝弱禽驚踐。悵別幾多情，含春任攀搴。"]'),
('yuding-24','三月五日陪大夫泛長沙東湖','張又新','唐','御定全唐诗','yuding','','[]','上巳餘風景，芳辰集遠坰。彩舟浮泛蕩，繡轂下娉婷。',72,'御定全唐詩/json/479.json','["上巳餘風景，芳辰集遠坰。彩舟浮泛蕩，繡轂下娉婷。", "棲樹回蔥蒨，笙歌轉杳冥。湖光迷翡翠，草色醉蜻蜓。", "鳥弄桐花日，魚翻穀雨萍。從今留勝會，誰看畫蘭亭。"]'),
('yuding-25','贈廣陵妓','張又新','唐','御定全唐诗','yuding','','[]','雲雨分飛二十年，當時求夢不曾眠。',32,'御定全唐詩/json/479.json','["雲雨分飛二十年，當時求夢不曾眠。", "今來頭白重相見，還上襄王玳瑁筵。"]'),
('yuding-26','牡丹','張又新','唐','御定全唐诗','yuding','','[]','牡丹一朵值千金，將謂從來色最深。',32,'御定全唐詩/json/479.json','["牡丹一朵值千金，將謂從來色最深。", "今日滿欄開似雪，一生辜負看花心。"]'),
('yuding-27','遊白鶴山','張又新','唐','御定全唐诗','yuding','','[]','白鶴山邊秋複春，張文宅畔少風塵。',32,'御定全唐詩/json/479.json','["白鶴山邊秋複春，張文宅畔少風塵。", "欲驅五馬尋真隱，誰是當初□竹人。"]'),
('yuding-28','行田詩','張又新','唐','御定全唐诗','yuding','','[]','白石岩前湖水春，湖邊舊境有清塵。',32,'御定全唐詩/json/479.json','["白石岩前湖水春，湖邊舊境有清塵。", "欲追謝守行田意，今古同憂是長人。"]'),
('yuding-29','羅浮山','張又新','唐','御定全唐诗','yuding','','[]','江北重巒積翠濃，綺霞遙映碧芙蓉。',32,'御定全唐詩/json/479.json','["江北重巒積翠濃，綺霞遙映碧芙蓉。", "不知末後滄溟上，減卻瀛洲第幾峰。"]'),
('yuding-30','青障山','張又新','唐','御定全唐诗','yuding','','[]','一派遠光澄碧月，萬株聳翠獵金飆。',32,'御定全唐詩/json/479.json','["一派遠光澄碧月，萬株聳翠獵金飆。", "陶仙謾學長生術，暑往寒來更寂寥。"]'),
('yuding-31','中界山','張又新','唐','御定全唐诗','yuding','','[]','瑟瑟峰頭玉水流，晉時遺跡更堪愁。',32,'御定全唐詩/json/479.json','["瑟瑟峰頭玉水流，晉時遺跡更堪愁。", "愁人到此勞長望，何處煙波是祖州。"]'),
('yuding-32','帆游山','張又新','唐','御定全唐诗','yuding','','[]','漲海嘗從此地流，千帆飛過碧山頭。',32,'御定全唐詩/json/479.json','["漲海嘗從此地流，千帆飛過碧山頭。", "君看深谷為陵後，翻覆人間未肯休。"]'),
('yuding-33','謝池','張又新','唐','御定全唐诗','yuding','','[]','郡郭東南積谷山，謝公曾是此躋攀。',32,'御定全唐詩/json/479.json','["郡郭東南積谷山，謝公曾是此躋攀。", "今來惟有靈池月，猶是嬋娟一水間。"]'),
('yuding-34','華蓋山','張又新','唐','御定全唐诗','yuding','','[]','一岫坡陀凝綠草，千重虛翠透紅霞。',32,'御定全唐詩/json/479.json','["一岫坡陀凝綠草，千重虛翠透紅霞。", "愁來始上消歸思，見盡江城數百家。"]'),
('yuding-35','吹臺山','張又新','唐','御定全唐诗','yuding','','[]','吹臺山上彩煙凝，日落雲收疊翠屏。',32,'御定全唐詩/json/479.json','["吹臺山上彩煙凝，日落雲收疊翠屏。", "應謂焦桐堪采斫，不知誰是柳吳興。"]'),
('yuding-36','青嶴山','張又新','唐','御定全唐诗','yuding','','[]','靈海泓澄匝翠峰，昔賢心賞已成空。',32,'御定全唐詩/json/479.json','["靈海泓澄匝翠峰，昔賢心賞已成空。", "今朝亭館無遺制，積水滄浪一望中。"]'),
('yuding-37','孤嶼','張又新','唐','御定全唐诗','yuding','','[]','碧水逶迤浮翠巘，綠蘿蒙密媚晴江。',32,'御定全唐詩/json/479.json','["碧水逶迤浮翠巘，綠蘿蒙密媚晴江。", "不知誰與名孤嶼，其實中川是一雙。"]'),
('yuding-38','春草池','張又新','唐','御定全唐诗','yuding','','[]','謝公夢草一差微，謫宦當時道不機。',32,'御定全唐詩/json/479.json','["謝公夢草一差微，謫宦當時道不機。", "且謂飛霞遊賞地，池塘煙柳亦依依。"]'),
('yuding-39','春色滿皇州','封敖','唐','御定全唐诗','yuding','','[]','帝裏春光正，蔥蘢喜氣浮。錦鋪仙禁側，鏡寫曲江頭。',72,'御定全唐詩/json/479.json','["帝裏春光正，蔥蘢喜氣浮。錦鋪仙禁側，鏡寫曲江頭。", "紅萼開蕭閣，黃絲拂禦樓。千門歌吹動，九陌綺羅遊。", "日近風先滿，仁深澤共流。應非憔悴質，辛苦在神州。"]'),
('yuding-40','題西隱寺','封敖','唐','御定全唐诗','yuding','','[]','三年未到九華山，終日披圖一室間。秋寺喜因晴後賞，',41,'御定全唐詩/json/479.json','["三年未到九華山，終日披圖一室間。秋寺喜因晴後賞，", "勝事倘能銷歲月，已co名利不相關。"]'),
('yuding-41','奉和白敏中聖道和平致茲休運歲終功就合詠盛明呈上','馬植','唐','御定全唐诗','yuding','','[]','舜德堯仁化犬戎，許提河隴款皇風。指揮貙武皆神算，',40,'御定全唐詩/json/479.json','["舜德堯仁化犬戎，許提河隴款皇風。指揮貙武皆神算，", "天留此事還英主，不在他年在大中。"]'),
('yuding-42','夏日途中','李廓','唐','御定全唐诗','yuding','','[]','樹夾炎風路，行人正午稀。初蟬數聲起，戲蝶一團飛。',48,'御定全唐詩/json/479.json','["樹夾炎風路，行人正午稀。初蟬數聲起，戲蝶一團飛。", "日色欺清鏡，槐膏點白衣。無成歸故里，自覺少光輝。"]'),
('yuding-43','長安少年行','李廓','唐','御定全唐诗','yuding','','[]','金紫少年郎，繞街鞍馬光。身從左中尉，官屬右春坊。',480,'御定全唐詩/json/479.json','["金紫少年郎，繞街鞍馬光。身從左中尉，官屬右春坊。", "剗戴揚州帽，重熏異國香。垂鞭踏青草，來去杏園芳。", "追逐輕薄伴，閒遊不著緋。長攏出獵馬，數換打球衣。", "曉日尋花去，春風帶酒歸。青樓無晝夜，歌舞歇時稀。", "日高春睡足，帖馬賞年華。倒插銀魚袋，行隨金犢車。", "還攜新市酒，遠醉曲江花。幾度歸侵黑，金吾送到家。", "好勝耽長夜，天明燭滿樓。留人看獨腳，賭馬換偏頭。", "樂奏曾無歇，杯巡不暫休。時時遙冷笑，怪客有春愁。", "遨遊攜豔妓，裝束似男兒。杯酒逢花住，笙歌簇馬吹。", "鶯聲催曲急，春色送歸遲。不以聞街鼓，華筵待月移。", "賞春惟逐勝，大宅可曾歸。不樂還逃席，多狂慣衩衣。", "歌人踏日起，語燕捲簾飛。婦好唯相妒，倡樓不醉稀。", "戟門連日閉，苦飲惜殘春。開鎖通新客，教姬屈醉人。", "倩歌牽白馬，自舞踏紅茵。時輩皆相許，平生不負身。", "新年高殿上，始見有光輝。玉雁排方帶，金鵝立仗衣。", "酒深和碗賜，馬疾打珂飛。朝下人爭看，香街意氣歸。", "遊市慵騎馬，隨姬入坐車。樓邊聽歌吹，簾外見鶯花。", "樂眼從人鬧，歸心畏日斜。蒼頭來去報，飲伴到倡家。", "小婦教鸚鵡，頭邊喚醉醒。犬嬌眠玉簟，鷹掣撼金鈴。", "碧地攢花障，紅泥待客亭。雖然長按曲，不飲不曾聽。"]'),
('yuding-44','雞鳴曲','李廓','唐','御定全唐诗','yuding','','[]','星稀月沒入五更，膠膠角角雞初鳴。征人牽馬出門立，',48,'御定全唐詩/json/479.json','["星稀月沒入五更，膠膠角角雞初鳴。征人牽馬出門立，", "才分曙色第二鳴，旌旆紅塵已出城。婦人上城亂招手，"]'),
('yuding-45','鏡聽詞','李廓','唐','御定全唐诗','yuding','','[]','匣中取鏡辭灶王，羅衣掩盡明月光。昔時長著照容色，',48,'御定全唐詩/json/479.json','["匣中取鏡辭灶王，羅衣掩盡明月光。昔時長著照容色，", "更深弱體冷如鐵，繡帶菱花懷裏熱。銅片銅片如有靈，"]'),
('yuding-46','猛士行','李廓','唐','御定全唐诗','yuding','','[]','戰鼓驚沙惡天色，猛士虯髯眼前黑。單于衣錦日行兵，',24,'御定全唐詩/json/479.json','["戰鼓驚沙惡天色，猛士虯髯眼前黑。單于衣錦日行兵，"]'),
('yuding-47','送振武將軍','李廓','唐','御定全唐诗','yuding','','[]','葉葉歸邊騎，風頭萬里幹。金裝腰帶重，鐵縫耳衣寒。',48,'御定全唐詩/json/479.json','["葉葉歸邊騎，風頭萬里幹。金裝腰帶重，鐵縫耳衣寒。", "蘆酒燒蓬暖，霜鴻撚箭看。黃河古戍道，秋雪白漫漫。"]'),
('yuding-48','落第','李廓','唐','御定全唐诗','yuding','','[]','榜前潛制淚，眾裏自嫌身。氣味如中酒，情懷似別人。',48,'御定全唐詩/json/479.json','["榜前潛制淚，眾裏自嫌身。氣味如中酒，情懷似別人。", "暖風張樂席，晴日看花塵。儘是添愁處，深居乞過春。"]'),
('yuding-49','贈商山東於嶺僧','李廓','唐','御定全唐诗','yuding','','[]','商嶺東西路欲分，兩間茅屋一溪雲。',32,'御定全唐詩/json/479.json','["商嶺東西路欲分，兩間茅屋一溪雲。", "師言耳重知師意，人是人非不欲聞。"]'),
('yuding-50','上令狐舍人','李廓','唐','御定全唐诗','yuding','','[]','名利生愁地，貧居歲月移。買書添架上，斷酒過花時。',48,'御定全唐詩/json/479.json','["名利生愁地，貧居歲月移。買書添架上，斷酒過花時。", "宿客嫌吟苦，乖童恨睡遲。近來唯儉靜，持此答深知。"]'),
('yuding-0','南梁行','李紳','唐','御定全唐诗','yuding','','[]','江城鬱鬱春草長，悠悠漢水浮青光。雜英飛盡空晝景，',144,'御定全唐詩/json/480.json','["江城鬱鬱春草長，悠悠漢水浮青光。雜英飛盡空晝景，", "青天詔下寵光至，頒籍金閨征石渠。秭歸山路煙嵐隔，", "杜鵑啼咽花亦殷，聲悲絕豔連空山。斜陽瞥映淺深樹，", "喬木幽溪上下同，雄雌不惑飛棲處。望秦峰回過商顏，", "元和列侍明光殿，諫草初焚市朝變。北闕趨承半隙塵，", "故篋歲深開斷簡，秋堂月曙掩遺題。嗚嗚曉角霞輝粲，"]'),
('yuding-1','趨翰苑遭誣構四十六韻','李紳','唐','御定全唐诗','yuding','','[]','九五當幹德，三千應瑞符。纂堯昌聖曆，宗禹盛丕圖。',552,'御定全唐詩/json/480.json','["九五當幹德，三千應瑞符。纂堯昌聖曆，宗禹盛丕圖。", "畫象垂新令，消兵易舊謨。選賢方去智，招諫忽升愚。", "大樂調元氣，神功運化爐。脫鱗超沆瀣，翻翼集蓬壺。", "捧日恩光別，抽毫顧問殊。鳳形憐采筆，龍頷借驪珠。", "擲地聲名寡，摩天羽翮孤。潔身酬雨露，利口扇讒諛。", "碧海同宸眷，鴻毛比賤軀。辨疑分黑白，舉直抵朋徒。", "庭獸方呈角，階蓂始效莩。日傾烏掩魄，星落鬥摧樞。", "墜劍悲喬嶽，號弓泣鼎湖。亂群逢害馬，擇肉縱狂貙。", "膽為隳肝竭，心因瀝血枯。滿帆摧駭浪，征棹折危途。", "燕客書方詐，堯門信未孚。謗興金就鑠，毀極玉生愈。", "礪吻矜先搏，張羅騁疾驅。地嫌稀魍魎，海恨止番禺。", "瘴嶺沖蛇入，蒸池躡虺趨。望天收雪涕，看鏡攬霜須。", "草毒人驚剪，茅荒室未誅。火風晴處扇，山鬼雨中呼。", "窮老鄉關遠，羈愁骨肉無。鵲靈窺牖戶，龜瑞出泥途。", "煙島深千瘴，滄波淼四隅。海標傳信使，江棹認妻孥。", "到接三冬暮，來經六月徂。暗灘朝不怒，驚瀨夜無虞。", "俯首安羸業，齊眉慰病夫。涸魚思雨潤，僵燕望雷蘇。", "詔下因頒朔，恩移詎省辜。誑天猶指鹿，依社尚憑狐。", "度嶺瞻牛鬥，浮江淬轆轤。未平人睚眥，誰懼鬼揶揄。", "盆浦潮通楚，匡山地接吳。庾樓清桂滿，遠寺素蓮敷。", "仿佛皆停馬，悲歡盡隙駒。舊交封宿草，衰鬢重生芻。", "萬戟分梁苑，雙旌寄魯儒。駸駸移歲月，冉冉近桑榆。", "疲馬愁千里，孤鴻念五湖。終當賦歸去，那更學楊朱。"]'),
('yuding-2','憶春日太液池亭候對','李紳','唐','御定全唐诗','yuding','','[]','宮鶯報曉瑞煙開，三島靈禽拂水回。橋轉彩虹當綺殿，',40,'御定全唐詩/json/480.json','["宮鶯報曉瑞煙開，三島靈禽拂水回。橋轉彩虹當綺殿，", "簪筆此時方侍從，卻思金馬笑鄒枚。"]'),
('yuding-3','憶夜直金鑾殿承旨','李紳','唐','御定全唐诗','yuding','','[]','月當銀漢玉繩低，深聽簫韶碧落齊。門壓紫垣高綺樹，',40,'御定全唐詩/json/480.json','["月當銀漢玉繩低，深聽簫韶碧落齊。門壓紫垣高綺樹，", "明日獨歸花路遠，可憐人世隔雲霓。"]'),
('yuding-4','憶春日曲江宴後許至芙蓉園','李紳','唐','御定全唐诗','yuding','','[]','春風上苑開桃李，詔許看花入禦園。香徑草中回玉勒，',40,'御定全唐詩/json/480.json','["春風上苑開桃李，詔許看花入禦園。香徑草中回玉勒，", "歸繞曲江煙景晚，未央明月鎖千門。"]'),
('yuding-5','新昌宅書堂前有藥樹一株，今已盈拱前。長慶中，於翰林院內，西軒藥樹下移得。纔長一寸，僕夫封一泥丸以歸植，今則長成，名之天上樹','李紳','唐','御定全唐诗','yuding','','[]','白榆星底開紅甲，珠樹宮中長紫霄。丹彩結心才辨質，',40,'御定全唐詩/json/480.json','["白榆星底開紅甲，珠樹宮中長紫霄。丹彩結心才辨質，", "長帶九天餘雨露，近來蔥翠欲成喬。"]'),
('yuding-6','過荊門','李紳','唐','御定全唐诗','yuding','','[]','荊江水闊煙波轉，荊門路繞山蔥蒨。帆勢侵雲滅又明，',120,'御定全唐詩/json/480.json','["荊江水闊煙波轉，荊門路繞山蔥蒨。帆勢侵雲滅又明，", "行行驅馬萬里遠，漸入煙嵐危棧賒。林中有鳥飛出穀，", "我聽此鳥祝我魂，魂死莫學聲銜冤。縱為羽族莫棲息，", "皎潔深看入澗泉，分明細見樵人徑。陰森鬼廟當郵亭，", "月低山曉問行客，已酹椒漿拜荒陌。惆悵忠貞徒自持，"]'),
('yuding-7','涉沅瀟','李紳','唐','御定全唐诗','yuding','','[]','屈原死處瀟湘陰，滄浪淼淼雲沉沉。蛟龍長怒虎長嘯，',122,'御定全唐詩/json/480.json','["屈原死處瀟湘陰，滄浪淼淼雲沉沉。蛟龍長怒虎長嘯，", "鴻叫離離入暮天，霞消漠漠深雲水。水靈江暗揚波濤，", "屈原爾為懷王沒，水府通天化靈物。何不驅雷擊電除奸邪，", "波白水黑山隱見，汨羅之上遙昏昏。風帆候曉看五兩，", "瀟湘島浦無人居，風驚水暗惟鮫魚。行來擊棹獨長歎，"]'),
('yuding-8','逾嶺嶠止荒陬抵高要','李紳','唐','御定全唐诗','yuding','','[]','天將南北分寒燠，北被羔裘南卉服。寒氣凝為戎虜驕，',216,'御定全唐詩/json/480.json','["天將南北分寒燠，北被羔裘南卉服。寒氣凝為戎虜驕，", "南標銅柱限荒徼，五嶺從茲窮險艱。衡山截斷炎方北，", "千崖傍聳猿嘯悲，丹蛇玄虺潛蜲蛇。瀧夫擬楫劈高浪，", "嶺上泉分南北流，行人照水愁腸骨。陰森石路盤縈紆，", "鷓鴣猿鳥聲相續，椎髻嘵呼同戚促。百處溪灘異雨晴，", "魚躍豈通清遠峽，雁飛難渡漳江東。雲蒸地熱無霜霰，", "幸逢雷雨蕩妖昏，提挈悲歡出海門。西日眼明看少長，", "物忌忠良表是非，朝驅絳灌為讎敵。明皇聖德異文皇，", "高明白日恩深海，齒發雖殘壯心在。空愧駑駘異一毛，"]'),
('yuding-9','移九江','李紳','唐','御定全唐诗','yuding','','[]','秋波入白水，帆去侵空小。五兩劇奔星，檣烏疾飛鳥。',204,'御定全唐詩/json/480.json','["秋波入白水，帆去侵空小。五兩劇奔星，檣烏疾飛鳥。", "盆城依落日，盆浦看雲眇。雲眇更蒼蒼，匡山低夕陽。", "楚客喜風水，秦人悲異鄉。異鄉秋思苦，江皋月華吐。", "漾漾隱波亭，悠悠通月浦。津橋歸候吏，竹巷開門戶。", "容膝有匡床，及肩才數堵。隙光非白駒，懸磬我無虞。", "體瘦寡行立，家肥安啜哺。天書憐譴謫，重作朱轓客。", "四座眼全青，一麾頭半白。今來思往事，往事益淒然。", "風月同今昔，悲歡異目前。四時嗟閱水，一紀換流年。", "獨有西庭鶴，孤鳴白露天。"]'),
('yuding-10','泛五湖','李紳','唐','御定全唐诗','yuding','','[]','範子蛻冠履，扁舟逸霄漢。嗟予抱險艱，怵惕驚彌漫。',192,'御定全唐詩/json/480.json','["範子蛻冠履，扁舟逸霄漢。嗟予抱險艱，怵惕驚彌漫。", "窮通氾濫勞，趣適殊昏旦。浴日蕩層空，浮天淼無畔。", "依灘落葉聚，立浦驚鴻散。浪疊雪峰連，山孤翠崖斷。", "風帆同巨壑，雲矗成高岸。宇宙可東西，星辰沈粲爛。", "霞生澒洞遠，月吐青熒亂。豈複問津迷，休為呂梁歎。", "漂沈自詎保，覆溺心長判。吳越郡異鄉，嬰童及為玩。", "依稀占井邑，嘹唳同鵝鸛。舉棹未宵分，維舟方日旰。", "征斯濟川力，若鼓淩風翰。易狎當悔遊，臨深罔知難。"]'),
('yuding-11','過鐘陵','李紳','唐','御定全唐诗','yuding','','[]','龍沙江尾抱鐘陵，水郭村橋晚景澄。江對楚山千里月，',40,'御定全唐詩/json/480.json','["龍沙江尾抱鐘陵，水郭村橋晚景澄。江對楚山千里月，", "惆悵舊遊同草露，卻思恩顧一沾膺。"]'),
('yuding-12','溯西江','李紳','唐','御定全唐诗','yuding','','[]','江風不定半晴陰，愁對花時盡日吟。孤棹自遲從蹭蹬，',40,'御定全唐詩/json/480.json','["江風不定半晴陰，愁對花時盡日吟。孤棹自遲從蹭蹬，", "空闊遠看波浪息，楚山安穩過雲岑。"]'),
('yuding-13','早發','李紳','唐','御定全唐诗','yuding','','[]','沙洲月落宿禽驚，潮起風微曉霧生。黃鶴浪明知上信，',40,'御定全唐詩/json/480.json','["沙洲月落宿禽驚，潮起風微曉霧生。黃鶴浪明知上信，", "蕭索更看江葉下，兩鄉俱是宦遊情。"]'),
('yuding-14','守滁陽深秋憶登郡城望琅琊','李紳','唐','御定全唐诗','yuding','','[]','山城小閣臨青嶂，紅樹蓮宮接薜蘿。斜日半岩開古殿，',40,'御定全唐詩/json/480.json','["山城小閣臨青嶂，紅樹蓮宮接薜蘿。斜日半岩開古殿，", "深夜獨吟還不寐，坐看凝露滿庭莎。"]'),
('yuding-15','滁陽春日懷果園閑宴','李紳','唐','御定全唐诗','yuding','','[]','西園到日栽桃李，紅白低枝拂酒杯。繁豔只愁風處落，',40,'御定全唐詩/json/480.json','["西園到日栽桃李，紅白低枝拂酒杯。繁豔只愁風處落，", "聞道數年深草露，幾株猶得近池台。"]'),
('yuding-16','悲善才','李紳','唐','御定全唐诗','yuding','','[]','穆王夜幸蓬池曲，金鑾殿開高秉燭。東頭弟子曹善才，',184,'御定全唐詩/json/480.json','["穆王夜幸蓬池曲，金鑾殿開高秉燭。東頭弟子曹善才，", "天顏靜聽朱絲彈，眾樂寂然無敢舉。銜花金鳳當承撥，", "抽弦度曲新聲發，金鈴玉佩相瑳切。流鶯子母飛上林，", "三月曲江春草綠，九霄天樂下雲端。紫髯供奉前屈膝，", "日曛塵暗車馬散，為惜新聲有餘歎。明年冠劍閉橋山，", "聞道善才成朽骨，空餘弟子奉音徽。南譙寂寞三春晚，", "心悲不覺淚闌幹，更為調弦反復彈。秋吹動搖神女佩，", "惆悵追懷萬事空，雍門感慨徒為爾。"]'),
('yuding-17','聞裏謠效古歌','李紳','唐','御定全唐诗','yuding','','[]','鄉里兒，桑麻鬱鬱禾黍肥，冬有襤襦夏有絺。',140,'御定全唐詩/json/480.json','["鄉里兒，桑麻鬱鬱禾黍肥，冬有襤襦夏有絺。", "兄鋤弟耨妻在機，夜犬不吠開蓬扉。鄉里兒，醉還飽，", "勸年少，樂耕桑。使君為我剪荊棘，使君為我驅豺狼。", "林中無虎山有鹿，水底無蛟魚有魴。父漁子獵日歸暮，", "惡聲主吏噪爾門，唧唧力力烹雞豚。鄉里兒，莫悲吒。", "上有明王頒詔下，重選賢良恤孤寡。春日遲遲驅五馬，"]'),
('yuding-18','轉壽春守，太和庚戌歲二月祗命壽陽，時替裴五墉終歿。因視壁題，自墉而上，或除名在邊坐殿，歿凡七子，無一存焉。壽人多寇盜，好訴訐，時謂之凶郡，獷俗特著。蒙此處之，顧余衰年甘躡前患，俾三月而寇靜，期歲而人和，虎不暴物，姦吏屏竄。三載，復遭邪佞所惡，授賓客，分司東都。或舉其目，或寄於風，亦麤繼詩人之末云','李紳','唐','御定全唐诗','yuding','','[]','未登崖谷尋丹灶，且曆軒窗看壁題。那遇八公生羽翼，',40,'御定全唐詩/json/480.json','["未登崖谷尋丹灶，且曆軒窗看壁題。那遇八公生羽翼，", "點檢遺編盡朝菌，應難求望一刀圭。"]'),
('yuding-19','憶壽春廢虎坑，余以春二月至郡，主吏舉所職，稱霍山多虎，每歲採茶為患，擇肉於人，至春常修陷阱數十所，勒獵者採其皮睛，余悉除罷之。是歲虎不復為害，至余去郡三載','李紳','唐','御定全唐诗','yuding','','[]','匪將履尾求兢惕，那效探雛所患爭。當路絕群嘗誡暴，',40,'御定全唐詩/json/480.json','["匪將履尾求兢惕，那效探雛所患爭。當路絕群嘗誡暴，", "休逐豺狼止貪戾，好為仁獸答皇明。"]'),
('yuding-20','壽陽罷郡日有詩十首與追懷不殊今編於後兼紀瑞物：肥河維舟阻涷祇待敕命','李紳','唐','御定全唐诗','yuding','','[]','罷分符竹作閑官，舟凍肥河擬棹難。食蘗苦心甘處困，',80,'御定全唐詩/json/480.json','["罷分符竹作閑官，舟凍肥河擬棹難。食蘗苦心甘處困，", "西奏血誠遙稽首，乞容歸病老江幹。", "淮陽效理空多病，疏受辭榮豈戀班。陳力不任趨北闕，", "珍重八公山下叟，不勞重淚更追攀。"]'),
('yuding-21','壽陽罷郡日有詩十首與追懷不殊今編於後兼紀瑞物：別連理樹','李紳','唐','御定全唐诗','yuding','','[]','垂陰敢慕甘棠葉，附幹將呈瑞木符。十步蘭茶同秀彩，',40,'御定全唐詩/json/480.json','["垂陰敢慕甘棠葉，附幹將呈瑞木符。十步蘭茶同秀彩，", "好住孤根托桃李，莫令從此混樵蘇。"]'),
('yuding-22','壽陽罷郡日有詩十首與追懷不殊今編於後兼紀瑞物：虎不食人','李紳','唐','御定全唐诗','yuding','','[]','南山白額同馴擾，亦變仁心去殺機。不競牛甘令買患，',40,'御定全唐詩/json/480.json','["南山白額同馴擾，亦變仁心去殺機。不競牛甘令買患，", "爾效騶虞護生草，豈徒柔伏在淮淝。"]'),
('yuding-23','壽陽罷郡日有詩十首與追懷不殊今編於後兼紀瑞物：發壽陽分司敕到又遇新正感懷書事','李紳','唐','御定全唐诗','yuding','','[]','休為建隼臨淝守，轉作垂絲入洛人。罷閱舊林三載籍，',40,'御定全唐詩/json/480.json','["休為建隼臨淝守，轉作垂絲入洛人。罷閱舊林三載籍，", "漸喜雪霜消解盡，得隨風水到天津。"]'),
('yuding-24','壽陽罷郡日有詩十首與追懷不殊今編於後兼紀瑞物：初出淝口入淮','李紳','唐','御定全唐诗','yuding','','[]','東風百里雪初晴，淝口冰開好濯纓。野老擁途知意重，',40,'御定全唐詩/json/480.json','["東風百里雪初晴，淝口冰開好濯纓。野老擁途知意重，", "回首夕嵐山翠遠，楚郊煙樹隱襄城。"]'),
('yuding-25','壽陽罷郡日有詩十首與追懷不殊今編於後兼紀瑞物：入淮至盱眙','李紳','唐','御定全唐诗','yuding','','[]','山凝翠黛孤峰迥，淮起銀花五兩高。天外綺霞迷海鶴，',40,'御定全唐詩/json/480.json','["山凝翠黛孤峰迥，淮起銀花五兩高。天外綺霞迷海鶴，", "寄謝雲帆疾飛鳥，莫誇回雁卷輕毛。"]'),
('yuding-26','壽陽罷郡日有詩十首與追懷不殊今編於後兼紀瑞物：憶東湖','李紳','唐','御定全唐诗','yuding','','[]','菱歌罷唱鷁舟回，雪鷺銀鷗左右來。霞散浦邊雲錦截，',40,'御定全唐詩/json/480.json','["菱歌罷唱鷁舟回，雪鷺銀鷗左右來。霞散浦邊雲錦截，", "淮口值春偏悵望，數株臨水是寒梅。"]'),
('yuding-0','七年初到洛陽寓居宣教裏時已春暮而四老俱在洛中分司','李紳','唐','御定全唐诗','yuding','','[]','青莎滿地無三徑，白髮緣頭忝四人。官職謬齊商嶺客，',40,'御定全唐詩/json/481.json','["青莎滿地無三徑，白髮緣頭忝四人。官職謬齊商嶺客，", "惟有門人憐鈍拙，勸教沈醉洛陽春。"]'),
('yuding-1','初秋忽奉詔除浙東觀察使檢校右貂','李紳','唐','御定全唐诗','yuding','','[]','龍樓寄引簪裾客，鳳闕陪趨朔望朝。疏受杜門期脫屣，',40,'御定全唐詩/json/481.json','["龍樓寄引簪裾客，鳳闕陪趨朔望朝。疏受杜門期脫屣，", "飛詔寵榮歡裏舍，豈徒斑白與垂髫。"]'),
('yuding-2','憶至鞏縣河宿待家累追懷','李紳','唐','御定全唐诗','yuding','','[]','鞏樹翻紅秋日斜，水分伊洛照餘霞。弓開後騎低初月，',40,'御定全唐詩/json/481.json','["鞏樹翻紅秋日斜，水分伊洛照餘霞。弓開後騎低初月，", "今來憶事涼風晚，煙浦空悲黃菊花。"]'),
('yuding-3','宿揚州','李紳','唐','御定全唐诗','yuding','','[]','江橫渡闊煙波晚，潮過金陵落葉秋。嘹唳塞鴻經楚澤，',40,'御定全唐詩/json/481.json','["江橫渡闊煙波晚，潮過金陵落葉秋。嘹唳塞鴻經楚澤，", "今日市朝風俗變，不須開口問迷樓。"]'),
('yuding-4','憶被牛相留醉州中時無他賓牛公夜出真珠輩數人','李紳','唐','御定全唐诗','yuding','','[]','嚴城畫角三聲閉，清宴金樽一夕同。銀燭坐隅聽子夜，',40,'御定全唐詩/json/481.json','["嚴城畫角三聲閉，清宴金樽一夕同。銀燭坐隅聽子夜，", "淮海一從雲雨散，杳然俱是夢魂中。"]'),
('yuding-5','早渡揚子江','李紳','唐','御定全唐诗','yuding','','[]','日沖海浪翻銀屋，江轉秋波走雪山。青嶂迥開蹲虎戍，',40,'御定全唐詩/json/481.json','["日沖海浪翻銀屋，江轉秋波走雪山。青嶂迥開蹲虎戍，", "焚卻戍船無戰伐，使知風教被烏蠻。"]'),
('yuding-6','憶過潤州','李紳','唐','御定全唐诗','yuding','','[]','昔年從宦干戈地，黃綬青春一魯儒。弓犯控弦招武旅，',40,'御定全唐詩/json/481.json','["昔年從宦干戈地，黃綬青春一魯儒。弓犯控弦招武旅，", "談笑謝金何所愧，不為偷買用兵符。"]'),
('yuding-7','憶登棲霞寺峰','李紳','唐','御定全唐诗','yuding','','[]','香印煙火息，法堂鐘磬餘。紗燈耿晨焰，釋子安禪居。',168,'御定全唐詩/json/481.json','["香印煙火息，法堂鐘磬餘。紗燈耿晨焰，釋子安禪居。", "林葉脫紅影，竹煙含綺疏。星珠錯落耀，月宇參差虛。", "顧眺匪恣適，曠襟懷卷舒。江海淼清蕩，丘陵何所如。", "滔滔可問津，耕者非長沮。茅嶺感仙客，蕭園成古墟。", "移步下碧峰，涉澗更躊躇。烏噪啄秋果，翠驚銜素魚。", "回塘彩鷁來，落景標林箊。漾漾棹翻月，蕭蕭風襲裾。", "勞歌起舊思，戚歎竟難攄。卻數共遊者，凋落非裏閭。"]'),
('yuding-8','憶萬歲樓望金山','李紳','唐','御定全唐诗','yuding','','[]','樓高雉堞千師壘，峰拔驚波萬壑攢。山絕地維消虎踞，',40,'御定全唐詩/json/481.json','["樓高雉堞千師壘，峰拔驚波萬壑攢。山絕地維消虎踞，", "長對碧波臨古渡，幾經風月與悲歡。"]'),
('yuding-9','過梅裏七首家於無錫四十載今敝廬數堵猶存今列題於後：上家山
','李紳','唐','御定全唐诗','yuding','','[]','上家山，家山依舊好。昔去松桂長，今來容須老。',48,'御定全唐詩/json/481.json','["上家山，家山依舊好。昔去松桂長，今來容須老。", "上家山，臨古道。高低入雲樹，蕪沒連天草。草色綠萋萋，"]'),
('yuding-10','過梅裏七首家於無錫四十載今敝廬數堵猶存今列題於後：憶東郭居','李紳','唐','御定全唐诗','yuding','','[]','昔餘過稚齒，從師昧知奧。徒懷利物心，不獲藏身寶。',168,'御定全唐詩/json/481.json','["昔餘過稚齒，從師昧知奧。徒懷利物心，不獲藏身寶。", "曳婁一縫掖，出處勞昏早。醒醉迷啜哺，衣裳辨顛倒。", "忠誠貫白日，直已憑蒼昊。捲舌墮讒諛，驚波息行潦。", "衰禽識舊木，疲馬知歸道。楊柳長庭柯，蘭荃覆階草。", "旌旄光裏舍，騎服歡妻嫂。綠鬢絕新知，蒼須稀舊老。", "冠緌身忝貴，齋沐心常禱。笙磬諒諧和，庭除還灑掃。", "棲遲還竹巷，物役浸江島。倏忽變星霜，悲傷滿衷抱。"]'),
('yuding-11','過梅裏七首家於無錫四十載今敝廬數堵猶存今列題於後：憶題惠山寺書堂','李紳','唐','御定全唐诗','yuding','','[]','故山一別光陰改，秋露清風歲月多。松下壯心年少去，',40,'御定全唐詩/json/481.json','["故山一別光陰改，秋露清風歲月多。松下壯心年少去，", "惟有此身長是客，又驅旌旆寄煙波。"]'),
('yuding-12','過梅裏七首家於無錫四十載今敝廬數堵猶存今列題於後：憶西湖雙鸂鶒','李紳','唐','御定全唐诗','yuding','','[]','雙鸂鶒，錦毛斕斑長比翼。戲繞蓮叢回錦臆，',52,'御定全唐詩/json/481.json','["雙鸂鶒，錦毛斕斑長比翼。戲繞蓮叢回錦臆，", "雲間上下同棲息，不作驚禽遠相憶。東家少婦機中語，", "五裏裴回竟何補。"]'),
('yuding-13','過梅裏七首家於無錫四十載今敝廬數堵猶存今列題於後：早梅橋','李紳','唐','御定全唐诗','yuding','','[]','早梅花，滿枝發。東風報春春未徹，紫萼迎風玉珠裂。',48,'御定全唐詩/json/481.json','["早梅花，滿枝發。東風報春春未徹，紫萼迎風玉珠裂。", "楊柳未黃鶯結舌，委素飄香照新月。橋邊一樹傷離別，"]'),
('yuding-14','過梅裏七首家於無錫四十載今敝廬數堵猶存今列題於後：翡翠塢','李紳','唐','御定全唐诗','yuding','','[]','翡翠飛飛繞蓮塢，一啄嘉魚一鳴舞。蓮莖觸散蓮葉欹，',48,'御定全唐詩/json/481.json','["翡翠飛飛繞蓮塢，一啄嘉魚一鳴舞。蓮莖觸散蓮葉欹，", "直上層空翠影高，還向雲間雙比翼。彈射莫及弋不得，"]'),
('yuding-15','過梅裏七首家於無錫四十載今敝廬數堵猶存今列題於後：憶放鶴','李紳','唐','御定全唐诗','yuding','','[]','羽毛似雪無瑕點，顧影秋池舞白雲。閑整素儀三島近，',40,'御定全唐詩/json/481.json','["羽毛似雪無瑕點，顧影秋池舞白雲。閑整素儀三島近，", "淩勵坐看空碧外，更憐鳧鷺老江濆。"]'),
('yuding-16','過吳門二十四韻','李紳','唐','御定全唐诗','yuding','','[]','煙水吳都郭，閶門架碧流。綠楊深淺巷，青翰往來舟。',288,'御定全唐詩/json/481.json','["煙水吳都郭，閶門架碧流。綠楊深淺巷，青翰往來舟。", "朱戶千家室，丹楹百處樓。水光搖極浦，草色辨長洲。", "憶作麻衣翠，曾為旅棹遊。放歌隨楚老，清宴奉諸侯。", "花寺聽鶯入，春湖看雁留。裏吟傳綺唱，鄉語認歈謳。", "橋轉攢虹飲，波通鬥鷁浮。竹扉梅圃靜，水巷橘園幽。", "縫堵荒麋苑，穿岩破虎丘。舊風猶越鼓，餘俗尚吳鉤。", "故館曾閑訪，遺基亦遍搜。吹臺山木盡，香徑佛宮秋。", "帳殿菰蒲掩，雲房露霧收。苧蘿妖覆滅，荊棘鬼包羞。", "風月俄黃綬，經過半白頭。重來冠蓋客，非複別離愁。", "候火分通陌，前旌駐外郵。水風搖彩旆，堤柳引鳴騶。", "問吏兒孫隔，呼名禮敬修。顧瞻殊宿昔，語默過悲憂。", "義感心空在，容衰日易偷。還持滄海詔，從此布皇猷。"]'),
('yuding-17','杭州天竺靈隱二寺頃歲亦布衣一遊及赴鎮會稽不敢以登臨自適竟不復到寺寺多猿猱謂之孫團彌長其類因追思為詩二首','李紳','唐','御定全唐诗','yuding','','[]','翠岩幽谷高低寺，十裏松風碧嶂連。開盡春花芳草澗，',80,'御定全唐詩/json/481.json','["翠岩幽谷高低寺，十裏松風碧嶂連。開盡春花芳草澗，", "時有猿猱擾鐘磬，老僧無複得安禪。", "人煙不隔江城近，水石雖清海氣深。波動只觀羅刹相，", "近日尤聞重雕飾，世人遙禮二檀林。"]'),
('yuding-18','渡西陵十六韻','李紳','唐','御定全唐诗','yuding','','[]','雨送奔濤遠，風收駭浪平。截流張旆影，分岸走鼙聲。',192,'御定全唐詩/json/481.json','["雨送奔濤遠，風收駭浪平。截流張旆影，分岸走鼙聲。", "獸逐銜波湧，龜艨噴棹輕。海門凝霧暗，江渚濕雲橫。", "雁翼看舟子，魚鱗辨水營。騎交遮戍合，戈簇擁沙明。", "謬履千夫長，將詢百吏情。下車占黍稷，冬雨害粢盛。", "望禱依前聖，垂休冀厚生。半江猶慘澹，全野已澄清。", "愛景三辰朗，祥農萬庾盈。浦程通曲嶼，海色媚重城。", "弓日鞬櫜動，旗風虎豹爭。及郊揮白羽，入裏卷紅旌。", "愷悌思陳力，端莊冀表誠。臨人與安俗，非止奉師貞。"]'),
('yuding-19','新樓詩二十首：新樓','李紳','唐','御定全唐诗','yuding','','[]','戎容罷引旌旗卷，朱戶褰開雉堞高。山聳翠微連郡閣，',40,'御定全唐詩/json/481.json','["戎容罷引旌旗卷，朱戶褰開雉堞高。山聳翠微連郡閣，", "惆悵桂枝零落促，莫思方朔種仙桃。"]'),
('yuding-20','新樓詩二十首：海榴亭','李紳','唐','御定全唐诗','yuding','','[]','海榴亭早開繁蕊，光照晴霞破碧煙。高近紫霄疑菡萏，',40,'御定全唐詩/json/481.json','["海榴亭早開繁蕊，光照晴霞破碧煙。高近紫霄疑菡萏，", "搖落舊叢雲水隔，不堪行坐數流年。"]'),
('yuding-21','新樓詩二十首：望海亭','李紳','唐','御定全唐诗','yuding','','[]','烏盈兔缺天涯迥，鶴背松梢拂檻低。湖鏡坐隅看匣滿，',40,'御定全唐詩/json/481.json','["烏盈兔缺天涯迥，鶴背松梢拂檻低。湖鏡坐隅看匣滿，", "蕭索感心俱是夢，九天應共草萋萋。"]'),
('yuding-22','新樓詩二十首：杜鵑樓','李紳','唐','御定全唐诗','yuding','','[]','杜鵑如火千房拆，丹檻低看晚景中。繁豔向人啼宿露，',40,'御定全唐詩/json/481.json','["杜鵑如火千房拆，丹檻低看晚景中。繁豔向人啼宿露，", "惟有此花隨越鳥，一聲啼處滿山紅。"]'),
('yuding-23','新樓詩二十首：滿桂樓','李紳','唐','御定全唐诗','yuding','','[]','為憐湖水通宵望，不學樊楊卻月樓。惟待素規澄滿鏡，',40,'御定全唐詩/json/481.json','["為憐湖水通宵望，不學樊楊卻月樓。惟待素規澄滿鏡，", "蕭瑟曉風聞木落，此時何異洞庭秋。"]'),
('yuding-24','新樓詩二十首：東武亭','李紳','唐','御定全唐诗','yuding','','[]','綠波春水湖光滿，丹檻連楹碧嶂遙。蘭鷁對飛漁棹急，',40,'御定全唐詩/json/481.json','["綠波春水湖光滿，丹檻連楹碧嶂遙。蘭鷁對飛漁棹急，", "鼉鼓若雷爭勝負，柳堤花岸萬人招。"]'),
('yuding-25','新樓詩二十首：龍宮寺','李紳','唐','御定全唐诗','yuding','','[]','銀地溪邊遇衲師，笑將花宇指潛知。定觀玄度生前事，',40,'御定全唐詩/json/481.json','["銀地溪邊遇衲師，笑將花宇指潛知。定觀玄度生前事，", "好令滄海龍宮子，長護金人舊浴池。"]'),
('yuding-26','新樓詩二十首：禹廟','李紳','唐','御定全唐诗','yuding','','[]','削平水土窮滄海，畚鍤東南盡會稽。山擁翠屏朝玉帛，',40,'御定全唐詩/json/481.json','["削平水土窮滄海，畚鍤東南盡會稽。山擁翠屏朝玉帛，", "清廟萬年長血食，始知明德與天齊。"]'),
('yuding-27','新樓詩二十首：晏安寺','李紳','唐','御定全唐诗','yuding','','[]','寺深松桂無塵事，地接荒郊帶夕陽。啼鳥歇時山寂寂，',40,'御定全唐詩/json/481.json','["寺深松桂無塵事，地接荒郊帶夕陽。啼鳥歇時山寂寂，", "丘壟漸平邊茂草，九原何處不心傷。"]'),
('yuding-28','新樓詩二十首：龜山','李紳','唐','御定全唐诗','yuding','','[]','一峰凝黛當明鏡，十仞喬松倚翠屏。秋月滿時侵兔魄，',40,'御定全唐詩/json/481.json','["一峰凝黛當明鏡，十仞喬松倚翠屏。秋月滿時侵兔魄，", "不學大蛟憑水怪，等閒雪雨害生靈。"]'),
('yuding-29','新樓詩二十首：重台蓮','李紳','唐','御定全唐诗','yuding','','[]','綠荷舒卷涼風曉，紅萼開縈紫菂重。遊女漢皋爭笑臉，',40,'御定全唐詩/json/481.json','["綠荷舒卷涼風曉，紅萼開縈紫菂重。遊女漢皋爭笑臉，", "終恐玉京仙子識，卻將歸種碧池峰。"]'),
('yuding-30','新樓詩二十首：橘園','李紳','唐','御定全唐诗','yuding','','[]','江城霧斂輕霜早，園橘千株欲變金。朱實摘時天路近，',40,'御定全唐詩/json/481.json','["江城霧斂輕霜早，園橘千株欲變金。朱實摘時天路近，", "憐爾結根能自保，不隨寒暑換貞心。"]'),
('yuding-31','新樓詩二十首：寒林寺','李紳','唐','御定全唐诗','yuding','','[]','最深城郭在人煙，疑借壺中到梵天。岩樹桂花開月殿，',40,'御定全唐詩/json/481.json','["最深城郭在人煙，疑借壺中到梵天。岩樹桂花開月殿，", "應是法宮傳覺路，使無煩惱見青蓮。"]'),
('yuding-32','新樓詩二十首：北樓櫻桃花','李紳','唐','御定全唐诗','yuding','','[]','開花占得春光早，雪綴雲裝萬萼輕。凝豔拆時初照日，',40,'御定全唐詩/json/481.json','["開花占得春光早，雪綴雲裝萬萼輕。凝豔拆時初照日，", "多事東風入閨闥，盡飄芳思委江城。"]'),
('yuding-33','新樓詩二十首：城上薔薇','李紳','唐','御定全唐诗','yuding','','[]','薔薇繁豔滿城陰，爛熳開紅次第深。新蕊度香翻宿蝶，',40,'御定全唐詩/json/481.json','["薔薇繁豔滿城陰，爛熳開紅次第深。新蕊度香翻宿蝶，", "風月寂寥思往事，暮春空賦白頭吟。"]'),
('yuding-34','新樓詩二十首：南庭竹','李紳','唐','御定全唐诗','yuding','','[]','東南舊美淩霜操，五月凝陰入坐寒。煙惹翠梢含玉露，',40,'御定全唐詩/json/481.json','["東南舊美淩霜操，五月凝陰入坐寒。煙惹翠梢含玉露，", "知爾結根香實在，鳳凰終擬下雲端。"]'),
('yuding-35','新樓詩二十首：琪樹','李紳','唐','御定全唐诗','yuding','','[]','石橋峰上棲玄鶴，碧闕岩邊蔭羽人。冰葉萬條垂碧實，',40,'御定全唐詩/json/481.json','["石橋峰上棲玄鶴，碧闕岩邊蔭羽人。冰葉萬條垂碧實，", "徒使茯苓成琥珀，不為松老化龍鱗。"]'),
('yuding-36','新樓詩二十首：海棠','李紳','唐','御定全唐诗','yuding','','[]','海邊佳樹生奇彩，知是仙山取得栽。瓊蕊籍中聞閬苑，',40,'御定全唐詩/json/481.json','["海邊佳樹生奇彩，知是仙山取得栽。瓊蕊籍中聞閬苑，", "寄語春園百花道，莫爭顏色泛金杯。"]'),
('yuding-37','新樓詩二十首：水寺','李紳','唐','御定全唐诗','yuding','','[]','煙波野寺經過處，水國蒼茫夢想中。雲散浦間江月迥，',40,'御定全唐詩/json/481.json','["煙波野寺經過處，水國蒼茫夢想中。雲散浦間江月迥，", "聞道化城方便喻，只應從此到龍宮。"]'),
('yuding-38','新樓詩二十首：靈汜橋','李紳','唐','御定全唐诗','yuding','','[]','靈汜橋邊多感傷，分明湖派繞回塘。岸花前後聞幽鳥，',40,'御定全唐詩/json/481.json','["靈汜橋邊多感傷，分明湖派繞回塘。岸花前後聞幽鳥，", "何須化鶴歸華表，卻數凋零念越鄉。"]'),
('yuding-39','若耶溪','李紳','唐','御定全唐诗','yuding','','[]','嵐光花影繞山陰，山轉花稀到碧潯。傾國美人妖豔遠，',40,'御定全唐詩/json/481.json','["嵐光花影繞山陰，山轉花稀到碧潯。傾國美人妖豔遠，", "應是蛟龍長不去，若耶秋水尚沉沉。"]'),
('yuding-40','登禹廟回降雪五言二十韻','李紳','唐','御定全唐诗','yuding','','[]','金奏雲壇畢，同雲拂雪來。玉田千畝合，瓊室萬家開。',240,'御定全唐詩/json/481.json','["金奏雲壇畢，同雲拂雪來。玉田千畝合，瓊室萬家開。", "湖暗冰封鏡，山明樹變梅。裂繒分井陌，連璧混樓臺。", "麻引詩人興，鹽牽謝女才。細疑歌響盡，旅作舞腰回。", "著水鵝毛失，鋪松鶴羽摧。半崖雲掩映，當砌月裴回。", "遇物纖能狀，隨方巧若裁。玉花全綴萼，珠蚌盡呈胎。", "志士書頻照，鮫人杼正催。妒妝淩粉匣，欺酒上瓊杯。", "海使迷奔轍，江濤認暗雷。疾飄風作馭，輕集霰為媒。", "劍客休矜利，農師正念摧。瑞彰知有感，靈貺表無災。", "堯曆占新慶，虞階想舊陪。粉凝鶯閣下，銀結鳳池隈。", "雞樹花驚笑，龍池絮欲猜。勞歌會稽守，遙祝永康哉。"]'),
('yuding-41','題法華寺五言二十韻','李紳','唐','御定全唐诗','yuding','','[]','花界無生地，慈宮有相天。化娥騰寶像，留影閟金仙。',240,'御定全唐詩/json/481.json','["花界無生地，慈宮有相天。化娥騰寶像，留影閟金仙。", "殿湧全身塔，池開半月泉。十峰排碧落，雙澗合清漣。", "藥草經行遍，香燈次第燃。戒珠高臘護，心印祖僧傳。", "瓶識先羅漢，衣存舊福田。幻身觀火宅，昏眼照青蓮。", "住覺超真境，依遊渡法船。化城珠百億，靈跡冠三千。", "蕭壁將沈影，梁薪尚綴煙。色塵知有數，劫燼豈無年。", "龍噴疑通海，鯨吞想漏川。磬疏聞啟梵，鐘息見安禪。", "指喻三車覺，開迷五陰纏。教通方便入，心達是非詮。", "貝葉千花藏，檀林萬寶篇。坐嚴獅子迅，幢飾網珠懸。", "極樂知無礙，分明應有緣。還將意功德，留偈法王前。"]'),
('yuding-0','宿越州天王寺','李紳','唐','御定全唐诗','yuding','','[]','海隅布政慚期月，江上沾巾愧萬人。休按簿書懲黠吏，',40,'御定全唐詩/json/482.json','["海隅布政慚期月，江上沾巾愧萬人。休按簿書懲黠吏，", "清夜佛宮觀色相，卻歸前老更前身。"]'),
('yuding-1','卻渡西陵別越中父老','李紳','唐','御定全唐诗','yuding','','[]','海潮晚上江風急，津吏篙師語默齊。傾手奉觴看故老，',40,'御定全唐詩/json/482.json','["海潮晚上江風急，津吏篙師語默齊。傾手奉觴看故老，", "漸舉雲帆煙水闊，杳然鳧雁各東西。"]'),
('yuding-2','卻到浙西','李紳','唐','御定全唐诗','yuding','','[]','臨平水竭蒹葭死，裏社蕭條旅館秋。嘗歎晉郊無乞糴，',40,'御定全唐詩/json/482.json','["臨平水竭蒹葭死，裏社蕭條旅館秋。嘗歎晉郊無乞糴，", "苛政尚存猶惕息，老人偷拜擁前舟。"]'),
('yuding-3','蘇州不住遙望武丘報恩兩寺','李紳','唐','御定全唐诗','yuding','','[]','秋山古寺東西遠，竹院松門悵望同。幽鳥靜時侵徑月，',40,'御定全唐詩/json/482.json','["秋山古寺東西遠，竹院松門悵望同。幽鳥靜時侵徑月，", "官備散寮身卻累，往來慚謝二蓮宮。"]'),
('yuding-4','回望館娃故宮','李紳','唐','御定全唐诗','yuding','','[]','江雲斷續草綿連，雲隔秋波樹覆煙。飄雪荻花鋪漲渚，',40,'御定全唐詩/json/482.json','["江雲斷續草綿連，雲隔秋波樹覆煙。飄雪荻花鋪漲渚，", "因問館娃何所恨，破吳紅臉尚開蓮。"]'),
('yuding-5','姑蘇台雜句','李紳','唐','御定全唐诗','yuding','','[]','越王巧破夫差國，來獻黃金重雕刻。西施醉舞花豔傾，',96,'御定全唐詩/json/482.json','["越王巧破夫差國，來獻黃金重雕刻。西施醉舞花豔傾，", "歌清管咽歡未極，越師戈甲浮江來。伍胥抉目看吳滅，", "靈岩香徑掩禪扉，秋草荒涼遍落暉。江浦回看鷗鳥沒，", "野寺經過懼悔尤，公程迫蹙悲秋館。吳鄉越國舊淹留，"]'),
('yuding-6','開元寺','李紳','唐','御定全唐诗','yuding','','[]','十層花宇真毫相，數仞峰巒閟月扉。攢立寶山中色界，',40,'御定全唐詩/json/482.json','["十層花宇真毫相，數仞峰巒閟月扉。攢立寶山中色界，", "難保爾形終不轉，莫令偷拂六銖衣。"]'),
('yuding-7','皋橋','李紳','唐','御定全唐诗','yuding','','[]','伯鸞憔悴甘飄寓，非向囂塵隱姓名。鴻鵠羽毛終有志，',40,'御定全唐詩/json/482.json','["伯鸞憔悴甘飄寓，非向囂塵隱姓名。鴻鵠羽毛終有志，", "猶有餘風未磨滅，至今鄉里重和鳴。"]'),
('yuding-8','真娘墓','李紳','唐','御定全唐诗','yuding','','[]','一株繁豔春城盡，雙樹慈門忍草生。愁態自隨風燭滅，',40,'御定全唐詩/json/482.json','["一株繁豔春城盡，雙樹慈門忍草生。愁態自隨風燭滅，", "還似錢塘蘇小小，只應回首是卿卿。"]'),
('yuding-9','卻望無錫芙蓉湖','李紳','唐','御定全唐诗','yuding','','[]','水寬山遠煙嵐迥，柳岸縈回在碧流。',160,'御定全唐詩/json/482.json','["水寬山遠煙嵐迥，柳岸縈回在碧流。", "清晝不風鳧雁少，卻疑初夢鏡湖秋。", "丹橘村邊獨火微，碧流明處雁初飛。", "蕭條落葉垂楊岸，隔水寥寥聞擣衣。", "逐波雲影參差遠，背日嵐光隱見深。", "猶似望中連海樹，月生湖上是山陰。", "舊山認得煙嵐近，湖水平鋪碧岫間。", "喜見雲泉還悵望，自慚山叟不歸山。", "翠崖幽谷分明處，倦鳥歸雲在眼前。", "惆悵白頭為四老，遠隨塵土去伊川。"]'),
('yuding-10','重到惠山','李紳','唐','御定全唐诗','yuding','','[]','碧峰依舊松筠老，重得經過已白頭。俱是海天黃葉信，',40,'御定全唐詩/json/482.json','["碧峰依舊松筠老，重得經過已白頭。俱是海天黃葉信，", "還向窗間名姓下，數行添記別離愁。"]'),
('yuding-11','鑒玄影堂','李紳','唐','御定全唐诗','yuding','','[]','香燈寂寞網塵中，煩惱身須色界空。龍缽已傾無法雨，',40,'御定全唐詩/json/482.json','["香燈寂寞網塵中，煩惱身須色界空。龍缽已傾無法雨，", "深夜月明松子落，儼然聽法侍生公。"]'),
('yuding-12','別石泉','李紳','唐','御定全唐诗','yuding','','[]','素沙見底空無色，青石潛流暗有聲。微渡竹風涵淅瀝，',40,'御定全唐詩/json/482.json','["素沙見底空無色，青石潛流暗有聲。微渡竹風涵淅瀝，", "應是梵宮連洞府，浴池今化醒泉清。"]'),
('yuding-13','別雙溫樹','李紳','唐','御定全唐诗','yuding','','[]','翠條盈尺憐孤秀，植向西窗待月軒。輕剪綠絲秋葉暗，',40,'御定全唐詩/json/482.json','["翠條盈尺憐孤秀，植向西窗待月軒。輕剪綠絲秋葉暗，", "看爾拂雲今得地，莫隨陵穀改深根。"]'),
('yuding-14','重別西湖','李紳','唐','御定全唐诗','yuding','','[]','浦邊梅葉看凋落，波上雙禽去寂寥。吹管曲傳花易失，',40,'御定全唐詩/json/482.json','["浦邊梅葉看凋落，波上雙禽去寂寥。吹管曲傳花易失，", "繁豔彩毛無處所，盡成愁歎別溪橋。"]'),
('yuding-15','毗陵東山','李紳','唐','御定全唐诗','yuding','','[]','昔人別館淹留處，蔔築東山學謝家。叢桂半空摧枳棘，',40,'御定全唐詩/json/482.json','["昔人別館淹留處，蔔築東山學謝家。叢桂半空摧枳棘，", "依舊秋風還寂寞，數行衰柳宿啼鴉。"]'),
('yuding-16','建元寺','李紳','唐','御定全唐诗','yuding','','[]','江城物候傷心地，遠寺經過禁火辰。芳草壟邊回首客，',40,'御定全唐詩/json/482.json','["江城物候傷心地，遠寺經過禁火辰。芳草壟邊回首客，", "歎息光陰催白髮，莫悲風月獨沾巾。"]'),
('yuding-17','卻到金陵登北固亭','李紳','唐','御定全唐诗','yuding','','[]','龍形江影隔雲深，虎勢山光入浪沈。潮蹙海風驅萬里，',40,'御定全唐詩/json/482.json','["龍形江影隔雲深，虎勢山光入浪沈。潮蹙海風驅萬里，", "還叱楫師看五兩，莫令辜負濟川心。"]'),
('yuding-18','望鶴林寺','李紳','唐','御定全唐诗','yuding','','[]','鶴棲峰下青蓮宇，花發江城世界春。紅照日高殷奪火，',40,'御定全唐詩/json/482.json','["鶴棲峰下青蓮宇，花發江城世界春。紅照日高殷奪火，", "自歎秋風勞物役，白頭拘束一閒人。"]'),
('yuding-19','宿瓜州','李紳','唐','御定全唐诗','yuding','','[]','煙昏水郭津亭晚，回望金陵若動搖。沖浦回風翻宿浪，',40,'御定全唐詩/json/482.json','["煙昏水郭津亭晚，回望金陵若動搖。沖浦回風翻宿浪，", "官冷舊諳唯旅館，歲陰輕薄是涼飆。"]'),
('yuding-20','入揚州郭','李紳','唐','御定全唐诗','yuding','','[]','菊芳沙渚殘花少，柳過秋風墜葉疏。堤繞門津喧井市，',40,'御定全唐詩/json/482.json','["菊芳沙渚殘花少，柳過秋風墜葉疏。堤繞門津喧井市，", "非為掩身羞白髮，自緣多病喜肩輿。"]'),
('yuding-21','宿揚州水館','李紳','唐','御定全唐诗','yuding','','[]','舟依淺岸參差合，橋映晴虹上下連。輕楫過時搖水月，',40,'御定全唐詩/json/482.json','["舟依淺岸參差合，橋映晴虹上下連。輕楫過時搖水月，", "閑憑欄幹指星漢，尚疑軒蓋在樓船。"]'),
('yuding-22','州中小飲便別牛相','李紳','唐','御定全唐诗','yuding','','[]','笙歌罷曲辭賓侶，庭竹移陰就小齋。愁不解顏徒滿酌，',40,'御定全唐詩/json/482.json','["笙歌罷曲辭賓侶，庭竹移陰就小齋。愁不解顏徒滿酌，", "從此別離長酩酊，洛陽狂狷任椎埋。"]'),
('yuding-23','卻過淮陰吊韓信廟','李紳','唐','御定全唐诗','yuding','','[]','功高自棄漢元臣，遺廟陰森楚水濱。英主任賢增虎翼，',40,'御定全唐詩/json/482.json','["功高自棄漢元臣，遺廟陰森楚水濱。英主任賢增虎翼，", "徒用千金酬一飯，不知明哲重防身。"]'),
('yuding-24','卻入泗口','李紳','唐','御定全唐诗','yuding','','[]','洪河一派清淮接，堤草蘆花萬里秋。煙樹寂寥分楚澤，',40,'御定全唐詩/json/482.json','["洪河一派清淮接，堤草蘆花萬里秋。煙樹寂寥分楚澤，", "惆悵路岐真此處，夕陽西沒水東流。"]'),
('yuding-25','重入洛陽東門','李紳','唐','御定全唐诗','yuding','','[]','商顏重命伊川叟，時事知非入洛人。連野碧流通御苑，',40,'御定全唐詩/json/482.json','["商顏重命伊川叟，時事知非入洛人。連野碧流通御苑，", "驅馬獨歸尋裏巷，日斜行處舊紅塵。"]'),
('yuding-26','拜三川守','李紳','唐','御定全唐诗','yuding','','[]','恭承寵詔臨伊洛，靜守朝章化比閭。風變市兒驚偃草，',40,'御定全唐詩/json/482.json','["恭承寵詔臨伊洛，靜守朝章化比閭。風變市兒驚偃草，", "唯有從容期一德，使齊文教奉皇居。"]'),
('yuding-27','慶雲見','李紳','唐','御定全唐诗','yuding','','[]','禮成中嶽陳金冊，祥報卿雲冠玉峰。輕未透林疑待鳳，',40,'御定全唐詩/json/482.json','["禮成中嶽陳金冊，祥報卿雲冠玉峰。輕未透林疑待鳳，", "還入九霄成沆瀣，夕嵐生處鶴歸松。"]'),
('yuding-28','靈蛇見少林寺','李紳','唐','御定全唐诗','yuding','','[]','瑣文結綬靈蛇降，蠖屈螭盤顧視閑。鱗蹙翠光抽璀璨，',40,'御定全唐詩/json/482.json','["瑣文結綬靈蛇降，蠖屈螭盤顧視閑。鱗蹙翠光抽璀璨，", "知爾全身護昆閬，不矜揮尾在常山。"]'),
('yuding-29','拜宣武軍節度使','李紳','唐','御定全唐诗','yuding','','[]','油幢併入虎旗開，錦橐從天鳳詔來。星應魏師新鼓角，',40,'御定全唐詩/json/482.json','["油幢併入虎旗開，錦橐從天鳳詔來。星應魏師新鼓角，", "伊洛鏡清回首處，是非紛雜任塵埃。"]'),
('yuding-30','到宣武三十韻','李紳','唐','御定全唐诗','yuding','','[]','七月趨梁苑，三年謝尹京。舊風除物蠹，新律奉師貞。',360,'御定全唐詩/json/482.json','["七月趨梁苑，三年謝尹京。舊風除物蠹，新律奉師貞。", "龍節雙油重，蛇矛百練明。躍魚連後旆，騰虎耀前旌。", "路轉金神並，川開鐵馬橫。擁旄差白羽，分轡引紅纓。", "在浚風煙接，維嵩鞏洛清。貫魚奔騎疾，連雁卷行輕。", "煙壘風調角，秋原雨洗兵。宿雲看布甲，疏柳見分營。", "鼓徹通宵警，和門候曉晴。虎符三校列，魚胄萬夫迎。", "弄馬猿猱健，奔車角抵呈。駕肩傍隘道，張幕內連楹。", "森戟承三令，攢戈退一聲。及郊知雨過，觀俗辨風行。", "望宋憐思女，游梁念客卿。義夫留感激，公子播英名。", "澤廣豚魚洽，恩宣豈弟生。善師忘任智，中略在推誠。", "式宴歌鐘合，陳筵綺繡並。戲鼙千卒躍，均酒百壺傾。", "樂與師徒共，歡從井邑盈。教通因漸染，人悅尚和平。", "授鉞慚分閫，登壇荷列城。虛裘朝獨坐，雄劍夜孤鳴。", "白髮侵霜變，丹心捧日驚。衛青終保志，潘嶽未忘情。", "期月終迷化，三年詎有成。惟看波海動，天外斬長鯨。"]'),
('yuding-0','江南暮春寄家','李紳','唐','御定全唐诗','yuding','','[]','雒陽城見梅迎雪，魚口橋逢雪送梅。劍水寺前芳草合，',40,'御定全唐詩/json/483.json','["雒陽城見梅迎雪，魚口橋逢雪送梅。劍水寺前芳草合，", "想得心知近寒食，潛聽喜鵲望歸來。"]'),
('yuding-1','奉酬樂天立秋夕有懷見寄','李紳','唐','御定全唐诗','yuding','','[]','深夜星漢靜，秋風初報涼。階篁淅瀝響，露葉參差光。',180,'御定全唐詩/json/483.json','["深夜星漢靜，秋風初報涼。階篁淅瀝響，露葉參差光。", "冰兔半升魄，銅壺微滴長。薄帷乍飄卷，襟帶輕搖颺。", "此際昏夢清，斜月滿軒房。屣履步前楹，劍戟森在行。", "重城宵正分，號鼓互相望。獨坐有所思，夫君鸞鳳章。", "天津落星河，一葦安可航。龍泉白玉首，魚服黃金裝。", "報國未知效，惟鵜徒在梁。裴回顧戎旃，顥氣生東方。", "衰葉滿欄草，斑毛盈鏡霜。羸牛未脫轅，老馬強騰驤。", "吟君白雪唱，慚愧巴人腸。"]'),
('yuding-2','山出雲','李紳','唐','御定全唐诗','yuding','','[]','杳靄祥雲起，飄颺翠嶺新。縈峰開石秀，吐葉間松春。',72,'御定全唐詩/json/483.json','["杳靄祥雲起，飄颺翠嶺新。縈峰開石秀，吐葉間松春。", "林靜翻空少，山明度嶺頻。回崖時掩鶴，幽澗或隨人。", "姑射朝凝雪，陽臺晚伴神。悠悠九霄上，應坐玉京賓。"]'),
('yuding-3','上党奏慶雲見','李紳','唐','御定全唐诗','yuding','','[]','飛龍久馭宇，真氣尚興雲。五色傳嘉瑞，千齡表聖君。',72,'御定全唐詩/json/483.json','["飛龍久馭宇，真氣尚興雲。五色傳嘉瑞，千齡表聖君。", "從風忽蕭索，依漢更氛氳。影徹天初霽，光鮮日未曛。", "表祥近自遠，垂化聚還分。寧作無依者，空傳陶令文。"]'),
('yuding-4','華山慶雲見','李紳','唐','御定全唐诗','yuding','','[]','聖主祠名岳，高峰發慶雲。金柯初繚繞，玉葉漸氛氳。',72,'御定全唐詩/json/483.json','["聖主祠名岳，高峰發慶雲。金柯初繚繞，玉葉漸氛氳。", "氣色含珠日，晴夫吐翠雰。依稀來鶴態，仿佛列山群。", "萬樹流光影，千潭寫錦文。蒼生欣有望，祥瑞在吾君。"]'),
('yuding-5','欲到西陵寄王行周','李紳','唐','御定全唐诗','yuding','','[]','西陵沙岸回流急，船底粘沙去岸遙。驛吏遞呼催下纜，',40,'御定全唐詩/json/483.json','["西陵沙岸回流急，船底粘沙去岸遙。驛吏遞呼催下纜，", "欲責舟人無次第，自知貪酒過春潮。"]'),
('yuding-6','華頂','李紳','唐','御定全唐诗','yuding','','[]','欲向仙峰煉九丹，獨瞻華頂禮仙壇。石標琪樹淩空碧，',40,'御定全唐詩/json/483.json','["欲向仙峰煉九丹，獨瞻華頂禮仙壇。石標琪樹淩空碧，", "浮生未有從師地，空誦仙經想羽翰。"]'),
('yuding-7','鶯鶯歌','李紳','唐','御定全唐诗','yuding','','[]','伯勞飛遲燕飛疾，垂楊綻金花笑日。綠窗嬌女字鶯鶯，',40,'御定全唐詩/json/483.json','["伯勞飛遲燕飛疾，垂楊綻金花笑日。綠窗嬌女字鶯鶯，", "門掩重關蕭寺中，芳草花時不曾出。"]'),
('yuding-8','贈毛仙翁','李紳','唐','御定全唐诗','yuding','','[]','憶昔我祖神仙主，玄元皇帝周柱史。曾師軒黃友堯湯，',144,'御定全唐詩/json/483.json','["憶昔我祖神仙主，玄元皇帝周柱史。曾師軒黃友堯湯，", "穆王粗識神仙事，八極輪蹄方逞志。鶴發韜真世不知，", "仙兄受術幾千年，已是當時駕鴻客。海光悠容天路長，", "桂窗一別三千春，秦妃鏡裏娥眉新。忽控香虯天上去，", "九州爭奪無時休，八駿垂頭避豺虎。我亦玄元千世孫，", "百年命促奔馬疾，愁腸盤結心摧崒。今朝稽首拜仙兄，"]'),
('yuding-9','和晉公三首','李紳','唐','御定全唐诗','yuding','','[]','鳳儀常欲附，蚊力自知微。願假樽罍末，膺門自此依。',72,'御定全唐詩/json/483.json','["鳳儀常欲附，蚊力自知微。願假樽罍末，膺門自此依。", "貂蟬公獨步，鴛鷺我同群。插羽先飛酒，交鋒便著文。", "窮陰初莽蒼，離思漸氛氳。殘雪午橋岸，斜陽伊水濱。"]'),
('yuding-10','古風二首','李紳','唐','御定全唐诗','yuding','','[]','春種一粒粟，秋成萬顆子。四海無閒田，農夫猶餓死。',48,'御定全唐詩/json/483.json','["春種一粒粟，秋成萬顆子。四海無閒田，農夫猶餓死。", "鋤禾日當午，汗滴禾下土。誰知盤中餐，粒粒皆辛苦。"]'),
('yuding-11','柳二首','李紳','唐','御定全唐诗','yuding','','[]','陶令門前罥接籬，亞夫營裏拂朱旗。',64,'御定全唐詩/json/483.json','["陶令門前罥接籬，亞夫營裏拂朱旗。", "人事推移無舊物，年年春至綠垂絲。", "千條垂柳拂金絲，日暖牽風葉學眉。", "愁見花飛狂不定，還同輕薄五陵兒。"]'),
('yuding-12','題白樂天文集','李紳','唐','御定全唐诗','yuding','','[]','寄玉蓮花藏，緘珠貝葉扃。院閑容客讀，講倦許僧聽。',48,'御定全唐詩/json/483.json','["寄玉蓮花藏，緘珠貝葉扃。院閑容客讀，講倦許僧聽。", "部列雕金榜，題存刻石銘。永添鴻寶集，莫雜小乘經。"]'),
('yuding-13','答章孝標','李紳','唐','御定全唐诗','yuding','','[]','假金方用真金鍍，若是真金不鍍金。',32,'御定全唐詩/json/483.json','["假金方用真金鍍，若是真金不鍍金。", "十載長安得一第，何須空腹用高心。"]'),
('yuding-14','朱槿花','李紳','唐','御定全唐诗','yuding','','[]','瘴煙長暖無霜雪，槿豔繁花滿樹紅。',32,'御定全唐詩/json/483.json','["瘴煙長暖無霜雪，槿豔繁花滿樹紅。", "每歎芳菲四時厭，不知開落有春風。"]'),
('yuding-15','至潭州聞猿','李紳','唐','御定全唐诗','yuding','','[]','昔陪天上三清客，今作端州萬里人。',32,'御定全唐詩/json/483.json','["昔陪天上三清客，今作端州萬里人。", "湘浦更聞猿夜嘯，斷腸無淚可沾巾。"]'),
('yuding-16','江亭','李紳','唐','御定全唐诗','yuding','','[]','瘴江昏霧連天合，欲作家書更斷腸。',32,'御定全唐詩/json/483.json','["瘴江昏霧連天合，欲作家書更斷腸。", "今日病身悲狀候，豈能埋骨向炎荒。"]'),
('yuding-17','紅蕉花','李紳','唐','御定全唐诗','yuding','','[]','紅蕉花樣炎方識，瘴水溪邊色最深。',32,'御定全唐詩/json/483.json','["紅蕉花樣炎方識，瘴水溪邊色最深。", "葉滿叢深殷似火，不唯燒眼更燒心。"]'),
('yuding-18','憶漢月','李紳','唐','御定全唐诗','yuding','','[]','花開花落無時節，春去春來有底憑。',32,'御定全唐詩/json/483.json','["花開花落無時節，春去春來有底憑。", "燕子不藏雷不蟄，燭煙昏霧暗騰騰。"]'),
('yuding-19','端州江亭得家書二首','李紳','唐','御定全唐诗','yuding','','[]','雨中鵲語喧江樹，風處蛛絲颺水潯。',64,'御定全唐詩/json/483.json','["雨中鵲語喧江樹，風處蛛絲颺水潯。", "開拆遠書何事喜，數行家信抵千金。", "長安別日春風早，嶺外今來白露秋。", "莫道淮南悲木葉，不聞搖落更堪愁。"]'),
('yuding-20','聞猿','李紳','唐','御定全唐诗','yuding','','[]','見說三聲巴峽深，此時行者盡沾襟。',32,'御定全唐詩/json/483.json','["見說三聲巴峽深，此時行者盡沾襟。", "端州江口連雲處，始信哀猿傷客心。"]'),
('yuding-21','贈韋金吾','李紳','唐','御定全唐诗','yuding','','[]','自報金吾主禁兵，腰間寶劍重橫行。',32,'御定全唐詩/json/483.json','["自報金吾主禁兵，腰間寶劍重橫行。", "接輿也是狂歌客，更就將軍乞一聲。"]'),
('yuding-22','長門怨','李紳','唐','御定全唐诗','yuding','','[]','宮殿沉沉曉欲分，昭陽更漏不堪聞。',32,'御定全唐詩/json/483.json','["宮殿沉沉曉欲分，昭陽更漏不堪聞。", "珊瑚枕上千行淚，不是思君是恨君。"]'),
('yuding-23','龜山寺魚池','李紳','唐','御定全唐诗','yuding','','[]','汲水添池活白蓮，十千鬐鬣盡生天。',64,'御定全唐詩/json/483.json','["汲水添池活白蓮，十千鬐鬣盡生天。", "凡庸不識慈悲意，自葬江魚入九泉。", "剃發多緣是代耕，好聞人死惡人生。", "祇園說法無高下，爾輩何勞尚世情。"]'),
('yuding-24','賦月','李紳','唐','御定全唐诗','yuding','','[]','月。光輝，皎潔。耀乾坤，靜空闊。圓滿中秋，玩爭詩哲。',68,'御定全唐詩/json/483.json','["月。光輝，皎潔。耀乾坤，靜空闊。圓滿中秋，玩爭詩哲。", "玉兔鏑難穿，桂枝人共折。萬象照乃無私，瓊台豈遮君謁。", "抱琴對彈別鶴聲，不得知音聲不切。"]'),
('yuding-25','句','李紳','唐','御定全唐诗','yuding','','[]','君詠風月夕，余當童稚年。閑窗讀書罷，偷詠左司篇。',50,'御定全唐詩/json/483.json','["君詠風月夕，余當童稚年。閑窗讀書罷，偷詠左司篇。", "（韋應物為滁州刺史，有《登北樓》詩。紳後為刺史繼和，"]'),
('yuding-0','和太原張相公山亭懷古','崔公信','唐','御定全唐诗','yuding','','[]','疊石狀崖巘，翠含城上樓。前移廬霍峰，遠帶沅湘流。',48,'御定全唐詩/json/484.json','["疊石狀崖巘，翠含城上樓。前移廬霍峰，遠帶沅湘流。", "瀟灑主人靜，夤緣芳徑幽。清輝在昏旦，豈異東山遊。"]'),
('yuding-1','過小妓英英墓','楊虞卿','唐','御定全唐诗','yuding','','[]','蕭晨騎馬出皇都，聞說埋冤在路隅。別我已為泉下土，',40,'御定全唐詩/json/484.json','["蕭晨騎馬出皇都，聞說埋冤在路隅。別我已為泉下土，", "蘭質蕙心何所在，焉知過者是狂夫。"]'),
('yuding-2','句','楊虞卿','唐','御定全唐诗','yuding','','[]','河勢昆侖遠，山形菡萏秋。',12,'御定全唐詩/json/484.json','["河勢昆侖遠，山形菡萏秋。"]'),
('yuding-3','和段相公登武擔寺西台','楊汝士','唐','御定全唐诗','yuding','','[]','清淨此道宮，層台複倚空。偶時三伏外，列席九霄中。',48,'御定全唐詩/json/484.json','["清淨此道宮，層台複倚空。偶時三伏外，列席九霄中。", "平視雲端路，高臨樹杪風。自憐榮末座，前日別池籠。"]'),
('yuding-4','和段相公夏登張儀樓','楊汝士','唐','御定全唐诗','yuding','','[]','從公城上來，秋近絕纖埃。樓古秦規在，江分蜀望開。',48,'御定全唐詩/json/484.json','["從公城上來，秋近絕纖埃。樓古秦規在，江分蜀望開。", "遠山標宿雪，末席本寒灰。陪賞今為忝，臨歡敢訴杯。"]'),
('yuding-5','和宗人尚書嗣複祠祭武侯畢，題臨淮公舊碑','楊汝士','唐','御定全唐诗','yuding','','[]','古柏森然地，修嚴蜀相祠。一過榮異代，三顧盛當時。',72,'御定全唐詩/json/484.json','["古柏森然地，修嚴蜀相祠。一過榮異代，三顧盛當時。", "功德流何遠，馨香薦未衰。敬名探國志，飾像慰甿思。", "昔謁從征蓋，今聞擁信旗。固宜光寵下，有淚刻前碑。"]'),
('yuding-6','宴楊僕射新昌裏第','楊汝士','唐','御定全唐诗','yuding','','[]','隔坐應須賜禦屏，盡將仙翰入高冥。文章舊價留鸞掖，',40,'御定全唐詩/json/484.json','["隔坐應須賜禦屏，盡將仙翰入高冥。文章舊價留鸞掖，", "當時疏廣雖雲盛，詎有茲筵醉綠醽。"]'),
('yuding-7','建節後偶作','楊汝士','唐','御定全唐诗','yuding','','[]','拋卻弓刀上砌台，上方台榭與雲開。',32,'御定全唐詩/json/484.json','["拋卻弓刀上砌台，上方台榭與雲開。", "山僧見我衣裳窄，知道新從戰地來。"]'),
('yuding-8','題畫山水','楊汝士','唐','御定全唐诗','yuding','','[]','太華峰前是故鄉，路人遙指讀書堂。',32,'御定全唐詩/json/484.json','["太華峰前是故鄉，路人遙指讀書堂。", "如今老大騎官馬，羞向關西道姓楊。"]'),
('yuding-9','賀筵占贈營妓','楊汝士','唐','御定全唐诗','yuding','','[]','郎君得意及青春，蜀國將軍又不貧。',32,'御定全唐詩/json/484.json','["郎君得意及青春，蜀國將軍又不貧。", "一曲高歌紅一匹，兩頭娘子謝夫人。"]'),
('yuding-10','句','楊汝士','唐','御定全唐诗','yuding','','[]','昔日蘭亭無豔質，此時金谷有高人。（裴令公居守東洛，',74,'御定全唐詩/json/484.json','["昔日蘭亭無豔質，此時金谷有高人。（裴令公居守東洛，", "士云云。白知不能加，遽裂之，曰：「笙歌鼎沸，勿作", "冷淡生活。」元顧白曰：「樂天所謂能全其名者也。」）"]'),
('yuding-11','賦得芙蓉出水','陳至','唐','御定全唐诗','yuding','','[]','菡萏迎秋吐，夭搖映水濱。劍芒開寶匣，峰影寫蒲津。',72,'御定全唐詩/json/484.json','["菡萏迎秋吐，夭搖映水濱。劍芒開寶匣，峰影寫蒲津。", "下覆參差荇，高辭苒弱蘋。自當巢翠甲，非止戲赬鱗。", "莫以時先後，而言色故新。芳香正堪玩，誰報涉江人。"]'),
('yuding-12','薦冰','陳至','唐','御定全唐诗','yuding','','[]','淩寒開涸冱，寢廟致精誠。色靜澄三酒，光寒肅兩楹。',72,'御定全唐詩/json/484.json','["淩寒開涸冱，寢廟致精誠。色靜澄三酒，光寒肅兩楹。", "形鹽非近進，玉豆為潛英。禮自春分展，堅從北陸成。", "藉茅心共結，出鑒水漸明。幸得來觀薦，靈台一小生。"]'),
('yuding-13','句','陳至','唐','御定全唐诗','yuding','','[]','藻井尚寒龍跡在，紅樓初施日光通。',16,'御定全唐詩/json/484.json','["藻井尚寒龍跡在，紅樓初施日光通。"]'),
('yuding-14','薦冰','趙蕃','唐','御定全唐诗','yuding','','[]','仲月開淩室，齋心感聖情。寒姿分玉坐，皓彩發丹楹。',72,'御定全唐詩/json/484.json','["仲月開淩室，齋心感聖情。寒姿分玉坐，皓彩發丹楹。", "積素因風壯，虛空向日明。遙涵窗戶冷，近映冕旒清。", "在掌光逾澈，當軒質自輕。良辰方可致，由此表精誠。"]'),
('yuding-15','老人星','趙蕃','唐','御定全唐诗','yuding','','[]','大史占南極，秋分見壽星。增輝延寶曆，發曜起祥經。',72,'御定全唐詩/json/484.json','["大史占南極，秋分見壽星。增輝延寶曆，發曜起祥經。", "灼爍依狼地，昭彰近帝庭。高懸方杳杳，孤白乍熒熒。", "應見光新吐，休征德自形。既能符聖祚，從此表遐齡。"]'),
('yuding-0','古意','鮑溶','唐','御定全唐诗','yuding','','[]','女蘿寄青松，綠蔓花綿綿。三五定君婚，結髮早移天。',132,'御定全唐詩/json/485.json','["女蘿寄青松，綠蔓花綿綿。三五定君婚，結髮早移天。", "肅肅羔雁禮，泠泠琴瑟篇。恭承采蘩祀，敢效同車賢。", "皎日不留景，良辰如逝川。愁心忽移愛，花貌無歸妍。", "翠袖皓珠粉，碧階封綠錢。新人易如玉，廢瑟難為弦。", "寄謝蕣華木，榮君香閣前。豈無搖落苦，貴與根蒂連。", "希君舊光景，照妾薄暮年。"]'),
('yuding-1','蕭史圖歌','鮑溶','唐','御定全唐诗','yuding','','[]','霜綃數幅八月天，彩龍引鳳堂堂然。小載蕭仙穆公女，',48,'御定全唐詩/json/485.json','["霜綃數幅八月天，彩龍引鳳堂堂然。小載蕭仙穆公女，", "胡髯毿珊雲髻光，翠蕤皎潔瓊華涼。露痕煙跡漬紅貌，"]'),
('yuding-2','會仙歌','鮑溶','唐','御定全唐诗','yuding','','[]','輕輕濛濛，龍言鳳語何從容，耳有響兮目無蹤。杳杳默默，',98,'御定全唐詩/json/485.json','["輕輕濛濛，龍言鳳語何從容，耳有響兮目無蹤。杳杳默默，", "青毛仙鳥銜錦符，謹上阿環起居王母書。始知仙事亦多故，", "冠劍低昂蹈舞頻，禮容盡若君臣事。願言小仙藝，", "碧花醉，靈揚揚，笑賜二子長生方。二子未及伸拜謝，"]'),
('yuding-3','李夫人歌','鮑溶','唐','御定全唐诗','yuding','','[]','璿閨羽帳華燭陳，方士夜降夫人神。葳蕤半露芙蓉色，',72,'御定全唐詩/json/485.json','["璿閨羽帳華燭陳，方士夜降夫人神。葳蕤半露芙蓉色，", "嚬黛含犀竟不言，春思秋怨誰能問。欲求巧笑如生時，", "愛之欲其生又死，東流萬代無回水。宮漏丁丁夜向晨，"]'),
('yuding-4','水殿采菱歌','鮑溶','唐','御定全唐诗','yuding','','[]','宮鴉叫赤光，潮聲入宮宮影涼。火華啼露卷橫塘，',38,'御定全唐詩/json/485.json','["宮鴉叫赤光，潮聲入宮宮影涼。火華啼露卷橫塘，", "採蓮一聲歌態長，青絲結眼捕鴛鴦。"]'),
('yuding-5','周先生畫洞庭歌','鮑溶','唐','御定全唐诗','yuding','','[]','江南客，水為鄉，舟為宅，能以筆鋒知地脈。',76,'御定全唐詩/json/485.json','["江南客，水為鄉，舟為宅，能以筆鋒知地脈。", "閑分楚水入丹青，不下此堂臨洞庭。水文不浪煙不動，", "六月火光衣上生，齋心寂聽潺湲聲。林冰搖鏡水拂簟，", "玉壺先生在何處？"]'),
('yuding-6','霓裳羽衣歌','鮑溶','唐','御定全唐诗','yuding','','[]','玉煙生窗午輕凝，晨華左耀鮮相淩。人言天孫機上親手跡，',90,'御定全唐詩/json/485.json','["玉煙生窗午輕凝，晨華左耀鮮相淩。人言天孫機上親手跡，", "五聲寫出心中見，拊石喧金柏梁殿。此衣春日賜何人，", "眼前意是三清客，星宿離離繞身白。鸞鳳有聲不見身，", "喬山一閉曲未終，鼎湖秋驚白頭浪。"]'),
('yuding-7','寓興','鮑溶','唐','御定全唐诗','yuding','','[]','念來若望神，追往如話夢。夢神不無跡，誰使煩心用。',48,'御定全唐詩/json/485.json','["念來若望神，追往如話夢。夢神不無跡，誰使煩心用。", "魯聖虛泣麟，楚狂浪歌鳳。那言阮家子，更作窮途慟。"]'),
('yuding-8','游山','鮑溶','唐','御定全唐诗','yuding','','[]','白道行深雲，雲高路彌細。時時天上客，遺路人間世。',84,'御定全唐詩/json/485.json','["白道行深雲，雲高路彌細。時時天上客，遺路人間世。", "煙花最深處，井臼得空刺。天寒鶴巢林，石長泉脈閉。", "神化萬靈集，心期一朝契。不見金板書，誰知阮家裔。", "終期太古人，問取松柏歲。"]'),
('yuding-9','隋宮','鮑溶','唐','御定全唐诗','yuding','','[]','禦街多行客，行客悲春風。楚老幾代人，種田煬帝宮。',36,'御定全唐詩/json/485.json','["禦街多行客，行客悲春風。楚老幾代人，種田煬帝宮。", "零落池台勢，高低禾黍中。"]'),
('yuding-10','懷仙二首','鮑溶','唐','御定全唐诗','yuding','','[]','昆侖九層台，臺上宮城峻。西母持地圖，東來獻虞舜。',116,'御定全唐詩/json/485.json','["昆侖九層台，臺上宮城峻。西母持地圖，東來獻虞舜。", "虞宮禮成後，回駕仙風順。十二樓上人，笙歌沸天引。", "裴回扶桑路，白日生離恨。青鳥更不來，麻姑斷書信。", "乃知東海水，清淺誰能問。", "閬峰綺閣幾千丈，瑤水西流十二城。", "曾見周靈王太子，碧桃花下自吹笙。"]'),
('yuding-11','懷遠人','鮑溶','唐','御定全唐诗','yuding','','[]','遠道在天際，客行如浮雲。浮雲不知歸，似我長望君。',72,'御定全唐詩/json/485.json','["遠道在天際，客行如浮雲。浮雲不知歸，似我長望君。", "秋至漢水高，南音何時聞。瑤草難遠寄，西風氣氤氳。", "常恐山嶽遊，不反鸞鳳群。無厭坐遲人，風雨驚斯文。"]'),
('yuding-12','懷尹真人','鮑溶','唐','御定全唐诗','yuding','','[]','萬里疊嶂翠，一心浮雲閑。羽人杏花發，倚樹紅瓊顏。',72,'御定全唐詩/json/485.json','["萬里疊嶂翠，一心浮雲閑。羽人杏花發，倚樹紅瓊顏。", "流水杳冥外，女蘿陰蔭間。卻思人間世，多恐不可還。", "青鳥飛難遠，春雲晴不閑。但恐五靈車，山上複有山。"]'),
('yuding-13','秋晚銅山道中宿隱者','鮑溶','唐','御定全唐诗','yuding','','[]','我鄉山川遙，秋晚空景促。天明共雲散，日落依鳥宿。',120,'御定全唐詩/json/485.json','["我鄉山川遙，秋晚空景促。天明共雲散，日落依鳥宿。", "主人逃名子，鶴發臥空穀。野言得真風，山貌宜古服。", "喜於無聲地，暫傲羲皇俗。秋窗照疏螢，寒犬吠落木。", "朝隱留此處，一點天邊宿。今憶見此時，添悲覽止足。", "遲遲清夜晝，幽路出深竹。笑謝萬戶侯，餘將恥幹祿。"]');
